const twk_Nasionalisme = [
{ text: "Andi, seorang ASN muda, diminta atasan langsungnya untuk memprioritaskan verifikasi berkas perusahaan milik kerabat sang atasan dalam proyek strategis nasional. Atasan berdalih perusahaan tersebut adalah aset lokal yang akan memperkuat ekonomi daerah. Andi menemukan adanya ketidaksesuaian kecil dalam dokumen teknis yang secara aturan dapat menggugurkan perusahaan tersebut. Tindakan yang paling mencerminkan esensi nilai Bela Negara dalam menghadapi dilema tersebut adalah...", options: [{text: "Meminta perusahaan tersebut segera memperbaiki dokumen agar proses administrasi negara tetap berjalan lancar dan akuntabel.", val: 0}, {text: "Melaporkan indikasi nepotisme atasan kepada unit pengawas internal demi menjaga marwah instansi dari praktik korupsi.", val: 0}, {text: "Menolak permintaan atasan dan memproses verifikasi sesuai standar yang berlaku demi menjaga integritas sistem pelayanan publik.", val: 5}, {text: "Membantu memberikan arahan teknis tambahan karena pemberdayaan pengusaha lokal merupakan wujud penguatan ketahanan ekonomi nasional.", val: 0}, {text: "Mendiskusikan solusi dengan rekan senior agar tetap dapat membantu atasan tanpa melanggar hukum yang berlaku secara fatal.", val: 0}] },
{ text: "Budi adalah seorang atase perdagangan yang sedang menegosiasikan perjanjian ekspor komoditas unggulan Indonesia di luar negeri. Pihak investor asing menawarkan klausul yang sangat menguntungkan secara finansial bagi perusahaan-perusahaan besar di Indonesia dalam jangka pendek, namun dalam jangka panjang, klausul tersebut berpotensi melemahkan kedaulatan cadangan sumber daya alam nasional. Di sisi lain, pemerintah pusat sedang membutuhkan suntikan dana cepat untuk stabilitas ekonomi domestik. Tindakan Budi yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Menerima klausul tersebut demi memastikan stabilitas ekonomi domestik tetap terjaga di masa krisis.", val: 0}, {text: "Meminta waktu tambahan untuk berkonsultasi dengan pakar hukum agar perjanjian tetap memiliki payung hukum yang kuat.", val: 0}, {text: "Menolak klausul tersebut dan mengajukan alternatif kontrak yang lebih adil meskipun keuntungan finansialnya lebih kecil.", val: 5}, {text: "Menyetujui perjanjian tersebut dengan catatan tambahan (addendum) agar kelak pemerintah bisa mengevaluasi ulang kontraknya.", val: 0}, {text: "Mengarahkan investor untuk bekerja sama dengan BUMN saja agar kontrol negara terhadap sumber daya tetap terjamin secara administratif.", val: 0}] },
{ text: "Sinta melihat sebuah unggahan di media sosial yang memuat data statistik yang terlihat valid namun digunakan untuk menyudutkan salah satu kelompok etnis dalam kebijakan ekonomi pemerintah. Unggahan tersebut viral dan memicu perdebatan panas yang mengarah pada sentimen disintegrasi. Sinta tahu bahwa data tersebut diambil secara parsial (tidak utuh) untuk menggiring opini negatif. Sebagai warga negara yang sadar akan nilai Bela Negara, respons Sinta yang paling tepat adalah...", options: [{text: "Melaporkan unggahan tersebut sebagai konten provokatif kepada pihak berwenang agar segera dilakukan pemblokiran akun.", val: 0}, {text: "Mengunggah data pembanding yang utuh dan memberikan penjelasan objektif di kolom komentar untuk meredam sentimen negatif.", val: 5}, {text: "Mengabaikan unggahan tersebut agar tidak memberikan panggung atau keterlibatan (engagement) yang membuat konten makin viral.", val: 0}, {text: "Mengajak teman-temannya untuk memberikan komentar positif di unggahan tersebut guna menyeimbangkan suasana diskusi.", val: 0}, {text: "Membuat konten baru yang bersifat edukatif mengenai pentingnya persatuan tanpa menyinggung secara langsung konten yang sedang viral tersebut.", val: 0}] },
{ text: "Seorang dokter yang bertugas di wilayah perbatasan yang terpencil dihadapkan pada situasi di mana pasokan obat-obatan dari pusat sangat terbatas. Suatu hari, terjadi wabah lokal yang membutuhkan penanganan cepat. Ada tawaran bantuan obat-obatan dan dana dari organisasi internasional non-pemerintah yang belum memiliki izin resmi dari kementerian terkait, namun obat tersebut sangat dibutuhkan saat itu juga untuk menyelamatkan nyawa warga di perbatasan. Tindakan dokter tersebut yang paling mewakili esensi Bela Negara adalah...", options: [{text: "Menerima bantuan tersebut demi kemanusiaan karena menyelamatkan nyawa warga negara adalah prioritas tertinggi dalam Bela Negara.", val: 0}, {text: "Menolak bantuan tersebut dan tetap menggunakan fasilitas negara yang ada sambil menunggu pengiriman resmi dari pusat.", val: 0}, {text: "Berkoordinasi secara darurat dengan otoritas keamanan setempat untuk melegitimasi penggunaan bantuan tersebut demi keselamatan publik.", val: 5}, {text: "Menerima bantuan tersebut secara diam-diam agar tidak menimbulkan kerumitan birokrasi yang dapat menghambat penanganan medis.", val: 0}, {text: "Menyarankan organisasi tersebut untuk menyerahkan bantuannya melalui jalur formal di tingkat provinsi agar tidak melanggar aturan.", val: 0}] },
{ text: "Seorang kepala daerah di wilayah pesisir mendapatkan tawaran investasi besar dari perusahaan asing untuk membangun resor mewah di area yang merupakan zona lindung bakau (mangrove). Perusahaan menjanjikan penyerapan ribuan tenaga kerja lokal dan peningkatan pendapatan daerah secara signifikan yang sangat dibutuhkan pascapandemi. Namun, riset lingkungan menunjukkan bahwa hilangnya bakau tersebut akan memperlemah benteng alami wilayah dari abrasi dan ancaman tsunami di masa depan. Tindakan kepala daerah yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Menerima investasi tersebut dengan syarat perusahaan wajib mengalokasikan dana CSR untuk pembangunan infrastruktur penahan tsunami buatan.", val: 0}, {text: "Menolak investasi tersebut dan mengarahkan pengembangan ekonomi daerah pada sektor ekowisata yang menjaga kelestarian hutan bakau.", val: 5}, {text: "Menyetujui pembangunan resor di titik yang paling minim dampak lingkungannya demi menjaga keseimbangan antara ekonomi dan ekologi.", val: 0}, {text: "Mengonsultasikan tawaran tersebut kepada pemerintah pusat agar keputusan yang diambil memiliki legitimasi hukum dan politik yang kuat.", val: 0}, {text: "Meminta perusahaan untuk memindahkan lokasi pembangunan ke wilayah lain yang tidak termasuk zona lindung meskipun nilai investasinya mengecil.", val: 0}] },
{ text: "Seorang peneliti di sebuah lembaga negara menemukan bahwa data efikasi sebuah inovasi teknologi yang akan diluncurkan pemerintah untuk publik ternyata belum mencapai standar keamanan yang memadai. Namun, pimpinan lembaga meminta peneliti tersebut tetap merilis hasil yang positif dengan alasan demi menjaga kepercayaan publik terhadap pemerintah dan menghindari kegaduhan politik di tengah situasi nasional yang sedang sensitif. Dalam konteks Bela Negara, respons terbaik peneliti tersebut adalah...", options: [{text: "Menuruti instruksi pimpinan demi menjaga stabilitas nasional dan integritas lembaga pemerintah di mata masyarakat.", val: 0}, {text: "Menyampaikan keberatan secara internal dan meminta waktu tambahan untuk menyempurnakan penelitian sebelum data dirilis.", val: 0}, {text: "Merilis data apa adanya secara transparan kepada publik sebagai bentuk tanggung jawab moral dan kejujuran seorang ilmuwan negara.", val: 0}, {text: "Menyusun laporan yang menonjolkan sisi positif inovasi tersebut namun tetap mencantumkan catatan kecil mengenai kekurangan teknisnya.", val: 0}, {text: "Menolak merilis data yang tidak akurat dan bersedia menanggung konsekuensi jabatan demi melindungi keselamatan masyarakat luas.", val: 5}] },
{ text: "Dalam sebuah forum kebudayaan internasional, seorang tokoh pemuda Indonesia melihat adanya upaya dari negara lain untuk mengklaim sebuah tradisi asli nusantara sebagai warisan budaya mereka melalui narasi sejarah yang telah dimodifikasi. Tokoh pemuda tersebut memiliki kesempatan untuk melakukan interupsi dan memprotes klaim tersebut, namun ia khawatir tindakan tersebut akan merusak suasana diplomatis yang sedang dibangun oleh kementerian luar negeri dalam kerja sama ekonomi dengan negara tersebut. Tindakan yang paling tepat dilakukan adalah...", options: [{text: "Menahan diri untuk tidak memprotes di forum resmi demi menjaga kelancaran negosiasi ekonomi yang sedang diperjuangkan pemerintah.", val: 0}, {text: "Melakukan interupsi dengan cara yang elegan untuk memaparkan bukti sejarah asli tradisi tersebut sebagai upaya menjaga identitas bangsa.", val: 5}, {text: "Mencatat klaim tersebut dan melaporkannya kepada kementerian terkait setelah acara selesai agar diselesaikan melalui jalur diplomasi formal.", val: 0}, {text: "Mengajak perwakilan negara tersebut berdiskusi secara personal di luar forum untuk mencari kesepahaman mengenai klaim budaya tersebut.", val: 0}, {text: "Membuat kampanye tandingan di media sosial dengan konten budaya asli Indonesia agar publik internasional tahu kebenaran yang sesungguhnya.", val: 0}] },
{ text: "Seorang penyuluh pertanian di sebuah daerah lumbung padi nasional menyadari bahwa banyak petani di wilayahnya mulai menjual lahan sawah mereka kepada pengembang industri karena tergiur harga tanah yang melonjak tinggi. Para petani berencana beralih profesi menjadi pekerja pabrik demi kesejahteraan instan. Di sisi lain, pemerintah daerah mendukung industrialisasi tersebut karena dianggap akan meningkatkan Pendapatan Asli Daerah (PAD) secara signifikan. Tindakan penyuluh tersebut yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Menghormati keputusan para petani karena kesejahteraan ekonomi keluarga adalah hak asasi yang harus didukung oleh negara.", val: 0}, {text: "Melaporkan fenomena alih fungsi lahan tersebut kepada kementerian terkait agar segera diterbitkan aturan larangan penjualan lahan.", val: 0}, {text: "Mengedukasi petani mengenai pentingnya menjaga lahan sawah sebagai pilar kedaulatan pangan bangsa demi keselamatan generasi mendatang.", val: 0}, {text: "Membantu petani melakukan negosiasi harga lahan dengan pengembang agar mereka mendapatkan modal yang cukup untuk usaha baru.", val: 0}, {text: "Mengusulkan kepada pemerintah daerah untuk membangun kawasan industri di lahan non-produktif agar fungsi lahan pangan tetap terjaga.", val: 5}] },
{ text: "Di sebuah desa yang menjunjung tinggi nilai gotong royong, seorang warga yang dikenal sangat dermawan dan sering membantu pembangunan masjid serta sekolah tertangkap tangan melakukan praktik perjudian daring berskala besar. Masyarakat desa merasa berhutang budi dan berencana melakukan aksi damai untuk meminta keringanan hukuman atau penghentian kasus kepada kepolisian setempat demi menghargai jasa-jasa sosial pelaku. Sebagai tokoh pemuda desa yang memahami nilai Bela Negara, respons Anda adalah...", options: [{text: "Mendukung aksi damai masyarakat sebagai bentuk apresiasi atas kontribusi sosial yang telah dilakukan pelaku bagi desa.", val: 0}, {text: "Meminta masyarakat untuk tetap tenang dan menyerahkan sepenuhnya proses hukum kepada pihak berwenang sebagai bentuk penghormatan terhadap supremasi hukum.", val: 0}, {text: "Menggalang dana bantuan hukum bagi pelaku sebagai wujud solidaritas sesama warga negara yang sedang mengalami masalah hukum.", val: 0}, {text: "Memberikan edukasi kepada masyarakat bahwa membela hukum negara adalah bentuk nyata Bela Negara yang lebih tinggi dibanding solidaritas kelompok.", val: 5}, {text: "Menyarankan agar dilakukan musyawarah antara tokoh masyarakat dan kepolisian untuk mencari jalan tengah yang bersifat kekeluargaan.", val: 0}] },
{ text: "Seorang ilmuwan muda Indonesia berhasil menciptakan alat pemurni air sederhana namun sangat efektif untuk daerah bencana yang harganya jauh lebih murah dibanding produk impor. Namun, alat tersebut belum memiliki sertifikasi internasional yang sering menjadi syarat utama pengadaan barang di instansi pemerintah. Saat terjadi bencana besar, pemerintah cenderung ingin mengimpor alat serupa agar aman secara administrasi. Tindakan ilmuwan tersebut yang mencerminkan esensi Bela Negara adalah...", options: [{text: "Menggratiskan alat buatannya untuk digunakan oleh relawan di lapangan tanpa melalui jalur birokrasi pemerintah agar cepat menolong korban.", val: 0}, {text: "Mendesak pemerintah melalui media sosial agar memprioritaskan produk lokal demi menunjukkan semangat kemandirian bangsa.", val: 0}, {text: "Meminta bantuan lembaga riset negara untuk mempercepat uji standarisasi nasional agar alat tersebut legal digunakan dalam pengadaan darurat.", val: 5}, {text: "Terus menyempurnakan alat tersebut secara mandiri hingga nantinya diakui secara internasional agar tidak dipandang sebelah mata oleh negara sendiri.", val: 0}, {text: "Menjual lisensi alat tersebut kepada perusahaan asing yang sudah memiliki sertifikat internasional agar alatnya bisa segera digunakan di Indonesia.", val: 0}] },
{ text: "Pemerintah sedang merencanakan kerja sama pembangunan infrastruktur energi terbarukan dengan konsorsium perusahaan multinasional. Kerja sama ini akan memberikan transfer teknologi besar-besaran bagi tenaga ahli Indonesia dalam 5 tahun ke depan. Namun, muncul gelombang protes dari sekelompok organisasi yang menuntut agar seluruh proyek dikerjakan 100% oleh perusahaan dalam negeri saat ini juga, meskipun perusahaan lokal tersebut belum memiliki teknologi inti yang dibutuhkan. Sebagai seorang analis kebijakan yang memahami Bela Negara, respons Anda adalah...", options: [{text: "Mendukung tuntutan organisasi tersebut sebagai bentuk keberanian bangsa untuk mandiri dan tidak bergantung pada teknologi asing.", val: 0}, {text: "Menyarankan pemerintah untuk membatalkan kerja sama asing demi menjaga kehormatan dan harga diri bangsa di mata internasional.", val: 0}, {text: "Melanjutkan kerja sama tersebut sambil memperketat klausul transfer teknologi agar tenaga kerja lokal mampu mandiri di masa depan.", val: 5}, {text: "Meminta perusahaan asing tersebut memberikan dana hibah yang besar sebagai kompensasi atas penggunaan ruang wilayah Indonesia.", val: 0}, {text: "Melakukan kampanye nasional tentang pentingnya mencintai produk dan jasa dalam negeri untuk meredam gejolak sosial yang terjadi.", val: 0}] },
{ text: "Seorang anggota TNI/Polri menemukan adanya indikasi penyimpangan prosedur keamanan dalam distribusi bantuan logistik di wilayah konflik yang dilakukan oleh rekan satu angkatannya sendiri demi efisiensi waktu. Rekan tersebut dikenal sangat berdedikasi dan telah berkali-kali bertaruh nyawa demi kedaulatan negara di wilayah tersebut. Melaporkan hal ini berisiko merusak moral satuan dan solidaritas yang sangat dibutuhkan di medan tugas. Tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Memaklumi penyimpangan tersebut selama tujuannya adalah demi kelancaran tugas negara dan keselamatan warga di wilayah konflik.", val: 0}, {text: "Menegur rekan tersebut secara pribadi dan memintanya untuk lebih berhati-hati agar tidak diketahui oleh atasan atau pihak luar.", val: 0}, {text: "Melaporkan temuan tersebut sesuai prosedur internal agar integritas institusi pertahanan negara tetap terjaga dan profesional.", val: 5}, {text: "Mengabaikan temuan tersebut demi menjaga kekompakan dan moral satuan yang sedang menghadapi ancaman nyata dari luar.", val: 0}, {text: "Mengajak rekan-rekan lain untuk menutupi kesalahan tersebut sebagai bentuk kesetiakawanan dalam suka dan duka di medan tugas.", val: 0}] },
{ text: "Sebuah festival seni internasional di luar negeri secara tidak sengaja salah mencantumkan asal muasal alat musik tradisional Indonesia sebagai milik negara tetangga dalam katalog resmi mereka. Hal ini memicu kemarahan netizen Indonesia yang mulai menyerang akun media sosial festival tersebut dengan komentar kasar. Sebagai delegasi kebudayaan Indonesia yang hadir di sana, tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Turut menyuarakan protes keras di media sosial agar penyelenggara tahu bahwa bangsa Indonesia sangat mencintai dan menjaga budayanya.", val: 0}, {text: "Melakukan aksi protes diam di depan lokasi festival untuk menarik perhatian media internasional terhadap kesalahan klaim tersebut.", val: 0}, {text: "Menghubungi penyelenggara secara resmi dengan menyertakan dokumen sejarah yang valid untuk mengoreksi katalog dan meminta klarifikasi publik.", val: 5}, {text: "Meminta pemerintah Indonesia segera memutus kerja sama kebudayaan dengan negara penyelenggara sebagai bentuk ketegasan bangsa.", val: 0}, {text: "Menampilkan pertunjukan alat musik tersebut secara besar-besaran di festival untuk membuktikan secara visual bahwa itu adalah milik Indonesia.", val: 0}] },
{ text: "Sebuah platform media sosial global menolak permintaan pemerintah Indonesia untuk menghapus konten yang secara halus mempromosikan paham yang bertentangan dengan Pancasila, dengan alasan kebebasan berpendapat. Konten tersebut mulai memengaruhi opini generasi muda di daerah perbatasan. Sebagai seorang ASN di bidang komunikasi dan informasi, tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Mengusulkan pemblokiran total platform tersebut di Indonesia sebagai bentuk ketegasan negara dalam melindungi ideologi bangsa.", val: 0}, {text: "Menggerakkan komunitas konten kreator lokal untuk memproduksi narasi tandingan yang kreatif dan edukatif tentang nilai-nilai Pancasila.", val: 5}, {text: "Melakukan aksi protes digital bersama netizen untuk menekan platform tersebut agar tunduk pada aturan hukum Indonesia.", val: 0}, {text: "Membiarkan konten tersebut selama tidak memicu kekerasan fisik, demi menjaga citra Indonesia sebagai negara demokrasi di mata dunia.", val: 0}, {text: "Meminta bantuan peretas (hacker) nasional untuk melumpuhkan akun-akun yang menyebarkan paham tersebut secara mandiri.", val: 0}] },
{ text: "Indonesia sedang mengembangkan pesawat tempur hasil kerja sama dengan negara maju. Di tengah jalan, negara mitra membatasi akses Indonesia terhadap teknologi kunci radar karena alasan keamanan nasional mereka. Beberapa tokoh menyarankan agar Indonesia membatalkan proyek tersebut dan beralih membeli pesawat tempur dari negara lain yang lebih kooperatif, meskipun secara teknologi lebih rendah. Respons yang paling tepat dalam perspektif Bela Negara adalah...", options: [{text: "Membatalkan kerja sama dan segera membeli pesawat dari negara lain demi memastikan kesiapan tempur TNI tidak terganggu.", val: 0}, {text: "Melanjutkan proyek tersebut sambil menugaskan peneliti dalam negeri untuk melakukan rekayasa balik (reverse engineering) pada teknologi yang dibatasi.", val: 0}, {text: "Melakukan diplomasi tingkat tinggi untuk mendesak negara mitra membuka akses teknologi sebagai syarat kelanjutan kontrak ekonomi lainnya.", val: 5}, {text: "Menghentikan sementara proyek dan fokus pada penguatan industri pertahanan dalam negeri agar mampu menciptakan radar mandiri di masa depan.", val: 0}, {text: "Menyetujui pembatasan tersebut asalkan harga pesawat dikurangi secara signifikan agar anggaran negara bisa dialokasikan untuk kebutuhan lain.", val: 0}] },
{ text: "Sebuah wilayah hutan adat di Kalimantan ditemukan memiliki cadangan mineral langka yang sangat penting untuk industri baterai kendaraan listrik dunia. Pemerintah ingin membuka tambang di sana untuk menjadikan Indonesia pusat industri hijau global. Namun, masyarakat adat menolak karena hutan tersebut adalah identitas budaya dan sumber kehidupan mereka secara turun-temurun. Sebagai pejabat yang berwenang, tindakan yang paling mencerminkan Bela Negara adalah...", options: [{text: "Meyakinkan masyarakat adat bahwa pengorbanan lahan mereka adalah wujud nyata cinta tanah air demi kemajuan ekonomi nasional.", val: 0}, {text: "Memaksakan pembukaan tambang demi kepentingan nasional yang lebih besar dengan memberikan kompensasi finansial yang sangat tinggi.", val: 0}, {text: "Membatalkan rencana tambang dan menetapkan wilayah tersebut sebagai taman nasional yang tidak boleh diganggu gugat oleh industri mana pun.", val: 0}, {text: "Mencari titik temu dengan melibatkan masyarakat adat dalam pengelolaan industri tersebut tanpa merusak area sakral dan ekosistem utama.", val: 5}, {text: "Melakukan studi banding ke negara lain untuk melihat cara mengelola tambang di wilayah adat tanpa menimbulkan gejolak sosial.", val: 0}] },
{ text: "Seorang atase pertahanan di luar negeri menemukan bahwa teknologi satelit yang akan dibeli pemerintah Indonesia memiliki celah keamanan (backdoor) yang bisa diakses oleh negara produsen. Namun, pembatalan kontrak akan merusak hubungan diplomatik dan kerja sama militer yang sedang sangat dibutuhkan untuk stabilitas kawasan. Tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Melanjutkan pembelian demi menjaga stabilitas diplomasi kawasan.", val: 0}, {text: "Menegosiasikan ulang kontrak dengan syarat audit teknologi total.", val: 5}, {text: "Membatalkan kontrak secara sepihak untuk melindungi rahasia negara.", val: 0}, {text: "Tetap membeli namun memperkuat sistem pertahanan siber internal.", val: 0}, {text: "Melaporkan temuan tersebut kepada Dewan Keamanan Nasional.", val: 0}] },
{ text: "Sebuah perusahaan besar milik pengusaha nasional yang banyak menyumbang bagi kegiatan kemanusiaan di Indonesia terbukti melakukan manipulasi pajak dalam jumlah masif. Banyak pihak menyarankan agar kasus ini diselesaikan secara kekeluargaan (non-yustisial) mengingat besarnya jasa perusahaan tersebut bagi ekonomi rakyat. Dalam perspektif Bela Negara, respons terbaik adalah...", options: [{text: "Mengutamakan penyelesaian administratif demi menjaga iklim ekonomi.", val: 0}, {text: "Memberikan sanksi ringan sebagai apresiasi atas jasa sosialnya.", val: 0}, {text: "Menindak tegas sesuai hukum untuk menegakkan keadilan sistem.", val: 5}, {text: "Melakukan mediasi agar kerugian negara diganti tanpa proses hukum.", val: 0}, {text: "Menyerahkan keputusan sepenuhnya kepada kebijakan pimpinan tertinggi.", val: 0}] },
{ text: "Narasi dan Pertanyaan: Di era globalisasi, banyak generasi muda Indonesia lebih bangga menggunakan bahasa asing dan mengadopsi gaya hidup luar negeri karena dianggap lebih modern. Hal ini mulai mengikis penggunaan bahasa daerah dan bahasa Indonesia di ruang publik. Sebagai warga negara yang sadar akan nilai Bela Negara, tindakan yang paling mendasar adalah...", options: [{text: "Mendukung pembatasan konten budaya asing di media massa nasional.", val: 0}, {text: "Mewajibkan penggunaan pakaian adat di instansi pendidikan dan kantor.", val: 0}, {text: "Menjadikan budaya lokal sebagai basis inovasi di kancah internasional.", val: 5}, {text: "Memperkuat literasi nilai kebangsaan melalui jalur keluarga dan sekolah.", val: 0}, {text: "Menolak segala bentuk budaya asing yang tidak sesuai dengan Pancasila.", val: 0}] },
{ text: "Sebuah daerah memiliki potensi sumber daya alam yang melimpah, namun pengelolaannya selama ini belum optimal bagi kesejahteraan warga lokal. Pemerintah pusat merencanakan pengambilalihan pengelolaan melalui Badan Usaha Milik Negara (BUMN) untuk menjamin pasokan energi nasional. Masyarakat lokal melalui tokoh adat menolak dan menuntut pengelolaan mandiri sepenuhnya agar hasil kekayaan tersebut tetap berada di daerah. Sebagai pejabat mediator, tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Mendukung penuh tuntutan masyarakat lokal demi keadilan ekonomi daerah.", val: 0}, {text: "Memastikan BUMN masuk dengan memberikan porsi saham bagi masyarakat adat.", val: 0}, {text: "Menjalankan mandat pusat untuk pengamanan energi nasional secara mutlak.", val: 0}, {text: "Memfasilitasi kerja sama yang menyeimbangkan kedaulatan energi dan hak lokal.", val: 5}, {text: "Menyerahkan keputusan pada mekanisme hukum di pengadilan tata usaha negara.", val: 0}] },
{ text: "Dodi adalah seorang pakar teknologi informasi yang bekerja di sebuah perusahaan rintisan (startup) asing yang sukses. Ia menemukan bahwa sistem yang sedang dikembangkannya memiliki potensi untuk digunakan memetakan data perilaku pemilih di Indonesia secara ilegal untuk kepentingan politik pihak luar. Jika ia mengundurkan diri, ia kehilangan karier cemerlangnya; jika ia melapor, ia dianggap melanggar kontrak kerahasiaan perusahaan. Tindakan Dodi yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Tetap bekerja namun secara diam-diam menanamkan sistem pengaman data.", val: 0}, {text: "Mengundurkan diri secara baik-baik tanpa membocorkan rahasia perusahaan.", val: 0}, {text: "Melaporkan temuan tersebut kepada otoritas keamanan siber negara Indonesia.", val: 5}, {text: "Berkonsultasi dengan pengacara untuk mencari celah hukum dalam kontraknya.", val: 0}, {text: "Meminta perusahaan untuk mengubah arah pengembangan sistem agar lebih etis.", val: 0}] },
{ text: "Seorang atlet muda Indonesia yang sedang berprestasi di tingkat dunia mendapatkan tawaran untuk berpindah kewarganegaraan dari negara maju. Negara tersebut menjamin fasilitas latihan terbaik, kesejahteraan seumur hidup, dan peluang medali emas olimpiade yang sulit didapatkan jika tetap di Indonesia karena keterbatasan fasilitas nasional. Tindakan atlet tersebut yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Menerima tawaran tersebut agar tetap bisa mengharumkan nama asal Indonesia di podium.", val: 0}, {text: "Menolak tawaran dan tetap bertahan di Indonesia meski dengan fasilitas terbatas.", val: 0}, {text: "Menerima tawaran dengan syarat tetap diperbolehkan membangun yayasan olahraga di Indonesia.", val: 0}, {text: "Bertahan di Indonesia dan menggunakan pengaruhnya untuk menarik investor olahraga nasional.", val: 5}, {text: "Meminta pemerintah Indonesia memberikan fasilitas yang sama agar ia tidak berpindah negara.", val: 0}] },
{ text: "Sebuah perusahaan asing menawarkan investasi besar-besaran untuk membangun dermaga logistik di pulau terluar Indonesia yang selama ini terisolasi. Pihak asing meminta hak pengelolaan eksklusif selama 50 tahun termasuk kontrol atas lalu lintas kapal yang keluar masuk demi keamanan aset mereka. Pemerintah daerah sangat mendukung karena ini akan mengentaskan kemiskinan lokal secara instan. Sebagai pengambil kebijakan, tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Menerima investasi demi percepatan kesejahteraan masyarakat di pulau terluar.", val: 0}, {text: "Menyetujui pembangunan dengan syarat tenaga kerja lokal diprioritaskan 100%.", val: 0}, {text: "Menolak klausul hak eksklusif demi menjaga kedaulatan penuh atas wilayah.", val: 5}, {text: "Mengalihkan lokasi pembangunan ke wilayah pedalaman agar lebih aman secara politik.", val: 0}, {text: "Meminta jaminan tertulis bahwa aset tersebut akan menjadi milik negara di akhir kontrak.", val: 0}] },
{ text: "Seorang manajer di sebuah BUMN menemukan bahwa sistem manajemen risiko perusahaannya sengaja dimanipulasi agar laporan keuangan terlihat surplus demi mendapatkan bonus tahunan bagi seluruh karyawan. Jika ia membongkar hal ini, reputasi perusahaan akan jatuh dan ribuan rekan kerjanya akan kehilangan bonus yang sangat diharapkan untuk kebutuhan keluarga mereka. Tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Mendiamkan hal tersebut demi menjaga moral dan kesejahteraan rekan kerja.", val: 0}, {text: "Melakukan perbaikan sistem secara perlahan tanpa harus menciptakan kegaduhan.", val: 0}, {text: "Melaporkan manipulasi tersebut demi transparansi dan kesehatan aset negara.", val: 5}, {text: "Mengundurkan diri sebagai bentuk protes moral atas ketidakjujuran manajemen.", val: 0}, {text: "Menyarankan manajemen untuk mengalokasikan bonus tersebut bagi kegiatan sosial.", val: 0}] },
{ text: "Seorang peneliti tanaman herbal di pedalaman menemukan spesies tanaman yang terbukti efektif menyembuhkan penyakit kronis. Sebuah perusahaan farmasi luar negeri menawarkan kontrak riset dengan pendanaan melimpah, namun mereka mensyaratkan bahwa seluruh paten hasil riset akan menjadi hak milik perusahaan tersebut tanpa mencantumkan asal-usul geografis tanaman tersebut. Tindakan peneliti yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Menerima kontrak agar obat tersebut cepat diproduksi untuk menolong umat manusia.", val: 0}, {text: "Menolak kontrak dan memilih melakukan riset mandiri meski dengan fasilitas terbatas.", val: 0}, {text: "Menegosiasikan hak paten bersama (joint patent) sebagai pengakuan kedaulatan aset bangsa.", val: 0}, {text: "Menyerahkan temuan tersebut kepada pemerintah agar dipatenkan sebagai milik negara.", val: 5}, {text: "Mempublikasikan temuan secara terbuka di internet agar tidak bisa diklaim secara sepihak.", val: 0}] },
{ text: "Seorang ahli siber di lembaga pertahanan menemukan bahwa sebuah organisasi kemanusiaan internasional yang sedang memberikan bantuan bencana di wilayah konflik Indonesia, secara teknis mengirimkan data pemetaan geografis mendetail ke server luar negeri yang bisa diakses oleh pihak intelijen asing. Organisasi tersebut berdalih data itu diperlukan untuk koordinasi logistik bantuan agar tepat sasaran bagi rakyat yang menderita. Tindakan ahli siber tersebut yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Membiarkan pengiriman data tersebut demi kelancaran bantuan kemanusiaan bagi rakyat di wilayah konflik.", val: 0}, {text: "Menegur organisasi tersebut secara lisan agar lebih berhati-hati dalam mengelola data sensitif negara.", val: 0}, {text: "Memutus akses pengiriman data secara sepihak untuk melindungi rahasia geospasial pertahanan nasional.", val: 0}, {text: "Melaporkan temuan tersebut kepada otoritas keamanan negara agar diambil tindakan hukum dan kedaulatan.", val: 5}, {text: "Meminta salinan data tersebut agar pemerintah Indonesia juga memiliki data yang sama untuk kepentingan pusat.", val: 0}] },
{ text: "Indonesia sedang mengajukan diri menjadi anggota organisasi ekonomi bergengsi dunia. Salah satu syaratnya adalah keterbukaan data perbankan yang sangat transparan. Namun, tim analis menemukan bahwa keterbukaan penuh tersebut akan mengungkap kelemahan sistemik pada beberapa bank milik negara yang jika diketahui pasar global dapat memicu pelarian modal besar-besaran (capital flight) dan melemahkan rupiah. Tindakan ketua tim analis yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Menunda pengiriman data hingga sistem perbankan nasional benar-benar kuat secara internal.", val: 0}, {text: "Melakukan modifikasi data agar kondisi ekonomi terlihat tetap stabil di mata organisasi dunia.", val: 0}, {text: "Melaporkan kondisi sebenarnya kepada pemerintah agar diambil langkah penyelamatan ekonomi nasional.", val: 5}, {text: "Tetap mengirimkan data secara transparan sebagai bukti komitmen Indonesia terhadap standar global.", val: 0}, {text: "Menyarankan pengunduran diri dari pencalonan anggota demi melindungi stabilitas moneter dalam negeri.", val: 0}] },
{ text: "Sebuah yayasan pendidikan luar negeri menawarkan bantuan dana dan kurikulum modern secara gratis untuk sekolah-sekolah di pelosok Indonesia. Kurikulum tersebut sangat maju dalam bidang sains dan teknologi, namun secara implisit menyelipkan nilai-nilai individualisme ekstrem yang perlahan mengikis semangat gotong royong dan nilai luhur Pancasila pada siswa. Sebagai pejabat pendidikan daerah, tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Menerima bantuan tersebut sepenuhnya demi mengejar ketertinggalan teknologi siswa di pelosok.", val: 0}, {text: "Menolak bantuan tersebut untuk mencegah masuknya pengaruh budaya asing yang merusak jati diri.", val: 0}, {text: "Menerima bantuan tersebut dengan syarat kurikulum sainsnya saja yang diterapkan tanpa nilai sosialnya.", val: 0}, {text: "Mengadopsi metode sainsnya namun mewajibkan integrasi nilai Pancasila dalam setiap mata pelajaran.", val: 5}, {text: "Meminta pemerintah pusat membuat kurikulum tandingan yang setara agar tidak perlu bantuan asing.", val: 0}] },
{ text: "Indonesia sedang mengembangkan teknologi reaktor nuklir untuk kemandirian energi nasional dengan bantuan riset dari negara maju. Di tengah proyek, negara mitra meminta akses penuh untuk memantau seluruh aktivitas data riset tersebut dengan alasan pengawasan keamanan global dan pencegahan penyalahgunaan senjata. Jika menolak, bantuan pendanaan dan transfer teknologi akan dihentikan, yang berarti proyek kemandirian energi ini terancam mangkrak. Tindakan tim ahli Indonesia yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Menerima pengawasan tersebut demi memastikan proyek kemandirian energi nasional tetap berjalan hingga tuntas.", val: 0}, {text: "Menolak akses penuh tersebut dan memilih melanjutkan riset secara mandiri meski harus memakan waktu jauh lebih lama.", val: 0}, {text: "Menawarkan kompromi berupa laporan berkala yang transparan tanpa memberikan akses langsung ke sistem data inti riset.", val: 5}, {text: "Mengajak negara mitra melakukan audit bersama di bawah pengawasan lembaga internasional yang bersifat netral.", val: 0}, {text: "Menghentikan kerja sama tersebut dan mencari mitra negara lain yang tidak memberikan syarat yang mengikat kedaulatan data.", val: 0}] },
{ text: "Seorang pejabat kementerian keuangan menemukan bahwa sebuah konsorsium besar yang memegang proyek strategis nasional melakukan praktik penghindaran pajak yang sangat rumit namun secara teknis legal di bawah celah aturan lama. Jika celah ini ditutup secara mendadak, konsorsium tersebut mengancam akan menarik seluruh investasinya yang dapat memicu krisis kepercayaan investor dan PHK massal di sektor terkait. Tindakan pejabat tersebut yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Membiarkan praktik tersebut untuk sementara waktu demi menjaga stabilitas ekonomi dan mencegah terjadinya PHK massal.", val: 0}, {text: "Melakukan negosiasi agar konsorsium tersebut memberikan kompensasi berupa investasi sosial bagi masyarakat sekitar proyek.", val: 0}, {text: "Melaporkan celah aturan tersebut kepada pimpinan untuk segera dilakukan revisi regulasi demi keadilan pajak nasional.", val: 5}, {text: "Memberikan peringatan rahasia kepada perusahaan agar memperbaiki praktik pajaknya sebelum aturan baru resmi diberlakukan.", val: 0}, {text: "Meminta pendapat ahli hukum internasional untuk mencari jalan tengah yang tidak merugikan iklim investasi maupun negara.", val: 0}] },
{ text: "Dalam menghadapi ancaman terorisme lintas negara, lembaga intelijen negara meminta akses ke data enkripsi percakapan warga di sebuah platform komunikasi digital populer untuk mendeteksi sel tidur (sleeper cells). Hal ini memicu perdebatan mengenai pelanggaran privasi warga negara. Namun, jika akses ditolak, potensi serangan yang mengancam nyawa ribuan rakyat menjadi sangat tinggi. Sebagai penasihat kebijakan, tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Mendukung pemberian akses penuh kepada intelijen karena keselamatan rakyat adalah hukum tertinggi bagi negara.", val: 0}, {text: "Menolak pemberian akses tersebut demi melindungi hak asasi dan privasi warga negara sebagai pilar demokrasi.", val: 0}, {text: "Mengizinkan akses terbatas yang hanya bisa dibuka dengan perintah pengadilan dan pengawasan lembaga independen.", val: 5}, {text: "Menyarankan pengembangan teknologi pemantauan mandiri oleh negara tanpa harus bergantung pada data platform digital.", val: 0}, {text: "Melakukan sosialisasi kepada warga agar secara sukarela melaporkan aktivitas mencurigakan di lingkungan masing-masing.", val: 0}] },
{ text: "Indonesia sedang memimpin inisiatif pembentukan pakta perdagangan regional untuk memperkuat posisi tawar komoditas lokal di pasar global. Salah satu negara mitra kunci, yang memiliki pengaruh besar dalam stabilitas keamanan kawasan, mensyaratkan agar Indonesia melonggarkan aturan standarisasi industri dalam negeri bagi produk mereka sebagai bentuk timbal balik atas dukungan keamanan. Jika menolak, pakta ini terancam gagal dan posisi ekonomi Indonesia di masa depan akan sulit bersaing dengan blok dagang lain. Keputusan yang paling menunjukkan keteguhan pada prinsip Bela Negara dalam situasi diplomasi ekonomi tersebut adalah...", options: [{text: "Menyetujui pelonggaran tersebut secara terbatas hanya pada sektor non-vital demi menjaga keberlangsungan aliansi keamanan kawasan.", val: 0}, {text: "Menawarkan kerja sama investasi di bidang manufaktur sebagai pengganti pelonggaran standar agar kedaulatan industri tetap terjaga.", val: 0}, {text: "Menolak persyaratan tersebut dan tetap pada standar nasional guna melindungi daya saing dan martabat industri dalam negeri.", val: 5}, {text: "Meminta waktu untuk melakukan kajian dampak sosial-ekonomi guna mencari celah kompromi yang tidak merugikan kedua belah pihak.", val: 0}, {text: "Menggalang dukungan dari negara mitra lain yang lebih kecil untuk menekan negara kunci tersebut agar membatalkan persyaratannya.", val: 0}] },
{ text: "Andi adalah seorang auditor negara yang menemukan kebocoran data strategis terkait cadangan mineral langka di sebuah BUMN tambang. Data tersebut bocor akibat kelalaian sistem keamanan yang dikelola oleh perusahaan rintisan milik rekan seperjuangannya yang selama ini banyak membantu riset-riset strategis pemerintah. Jika Andi melaporkan temuan ini secara terbuka, perusahaan rekannya akan hancur dan riset penting lainnya akan terhenti. Namun, jika dibiarkan, data tersebut dapat disalahgunakan oleh spekulan asing. Langkah manakah yang paling merepresentasikan tanggung jawab Andi sebagai warga negara yang sadar akan nilai Bela Negara?", options: [{text: "Memberikan teguran keras dan waktu singkat bagi perusahaan rekannya untuk memperbaiki sistem sebelum melakukan audit ulang.", val: 0}, {text: "Melaporkan kebocoran tersebut kepada otoritas berwenang agar langkah mitigasi penyelamatan data negara dapat segera dilakukan.", val: 5}, {text: "Membantu rekan tersebut memperbaiki sistem keamanan secara mandiri agar kerahasiaan data negara kembali terjamin tanpa kegaduhan.", val: 0}, {text: "Menyusun laporan audit dengan catatan perbaikan internal tanpa harus mempublikasikan detail kebocoran kepada pihak luar.", val: 0}, {text: "Mengonsultasikan masalah tersebut kepada pimpinan lembaga auditor untuk mencari solusi yang paling minim risiko bagi semua pihak.", val: 0}] },
{ text: "Sebuah tim ilmuwan Indonesia berhasil mengembangkan vaksin untuk penyakit endemik lokal dengan biaya produksi yang sangat murah. Namun, sebuah organisasi kesehatan internasional menawarkan hibah vaksin serupa secara gratis dalam jumlah besar untuk 10 tahun ke depan, dengan syarat Indonesia harus menghentikan produksi mandiri vaksin lokal tersebut demi standarisasi global. Pemerintah daerah sangat mendesak agar hibah diterima karena dapat menghemat anggaran kesehatan secara masif. Sebagai pembuat kebijakan nasional, tindakan yang paling selaras dengan semangat Bela Negara adalah...", options: [{text: "Menerima hibah tersebut untuk jangka pendek sambil terus menyempurnakan kualitas vaksin lokal agar kelak bisa bersaing.", val: 0}, {text: "Menolak hibah tersebut secara tegas dan mengalokasikan anggaran negara untuk mempercepat produksi massal vaksin dalam negeri.", val: 5}, {text: "Menyetujui hibah tersebut dengan syarat organisasi internasional bersedia melakukan transfer teknologi kepada ilmuwan lokal.", val: 0}, {text: "Melakukan uji perbandingan antara kedua vaksin secara transparan dan memilih yang paling efektif bagi kesehatan masyarakat.", val: 0}, {text: "Menerima sebagian hibah untuk daerah terpencil dan tetap mengizinkan produksi lokal untuk kebutuhan wilayah perkotaan.", val: 0}] },
{ text: "Sebuah perusahaan teknologi asing menawarkan pemasangan menara pemancar internet gratis di wilayah perbatasan Indonesia yang selama ini terisolasi, dengan syarat mereka diberikan akses penuh untuk mengelola pusat data (data center) yang terbangun tanpa pengawasan otoritas keamanan nasional karena alasan kerahasiaan operasional perusahaan. Meskipun pemerintah daerah sangat mendukung karena akan mempercepat digitalisasi warga desa, tindakan yang paling mencerminkan keberpihakan pada prinsip kedaulatan negara dalam situasi tersebut adalah...", options: [{text: "Menerima tawaran tersebut demi percepatan akses informasi dan pendidikan warga perbatasan.", val: 0}, {text: "Menyetujui pembangunan dengan syarat perusahaan wajib mempekerjakan tenaga ahli lokal.", val: 0}, {text: "Menolak persyaratan akses data sepihak guna melindungi keamanan informasi strategis negara.", val: 5}, {text: "Mengalihkan lokasi pembangunan ke wilayah perkotaan agar lebih mudah diawasi pemerintah.", val: 0}, {text: "Meminta jaminan tertulis bahwa data warga tidak akan diperjualbelikan kepada pihak ketiga.", val: 0}] },
{ text: "Dalam sebuah audit proyek strategis nasional, seorang analis menemukan bahwa penggunaan bahan baku lokal yang dipaksakan oleh kebijakan pimpinan ternyata memiliki kualitas di bawah standar yang dapat membahayakan keselamatan publik dalam jangka panjang. Pimpinan meminta analis tersebut untuk memaklumi temuan ini sebagai bentuk dukungan terhadap industri dalam negeri dan penguatan ekonomi nasional agar tidak bergantung pada impor. Langkah yang paling menunjukkan integritas Bela Negara yang benar dalam dilema tersebut adalah...", options: [{text: "Mendukung pimpinan demi menjaga citra positif industri dalam negeri di mata masyarakat.", val: 0}, {text: "Memberikan catatan perbaikan teknis tanpa harus merubah status kelayakan proyek tersebut.", val: 0}, {text: "Menolak laporan yang tidak akurat demi menjamin keselamatan publik dan martabat negara.", val: 5}, {text: "Menyarankan penggunaan bahan impor secara diam-diam agar kualitas proyek tetap terjaga.", val: 0}, {text: "Melakukan pengujian ulang dengan standar yang lebih rendah agar bahan lokal bisa lulus.", val: 0}] },
{ text: "Indonesia mendapatkan tawaran hibah berupa sistem peringatan dini bencana alam dari sebuah negara maju dengan teknologi tercanggih, namun sistem tersebut mengharuskan seluruh data seismik dan pergerakan tanah di Indonesia terhubung langsung ke satelit negara pemberi hibah sebelum diolah oleh instansi terkait di dalam negeri. Mengingat Indonesia adalah wilayah rawan bencana, kebijakan yang paling selaras dengan semangat kemandirian dan bela negara adalah...", options: [{text: "Menerima hibah tersebut karena keselamatan nyawa rakyat dari bencana adalah prioritas utama.", val: 0}, {text: "Menolak hibah tersebut dan memprioritaskan pengembangan teknologi serupa oleh ilmuwan lokal.", val: 5}, {text: "Menerima hibah tersebut dengan syarat pusat pengolahan data tetap berada di wilayah Indonesia.", val: 0}, {text: "Mengajak negara tetangga untuk bersama-sama menggunakan hibah tersebut agar lebih transparan.", val: 0}, {text: "Menyetujui hibah tersebut hanya untuk wilayah yang belum terjangkau oleh alat sensor nasional.", val: 0}] },
{ text: "Di tengah masifnya penggunaan platform media sosial global, muncul tren konten kreatif yang mempromosikan gaya hidup konsumerisme ekstrem dan nilai-nilai individualisme yang perlahan mengikis budaya gotong royong di kalangan generasi muda Indonesia. Sebagai seorang pembuat kebijakan digital, tindakan yang paling mencerminkan strategi Bela Negara dalam menghadapi fenomena penjajahan budaya modern ini adalah...", options: [{text: "Menutup akses platform media sosial asing yang terbukti banyak memuat konten yang tidak sesuai dengan kepribadian bangsa Indonesia.", val: 0}, {text: "Memberikan insentif dan ruang luas bagi kreator konten lokal untuk memproduksi karya yang mengusung kearifan lokal secara modern.", val: 5}, {text: "Mewajibkan seluruh platform digital asing untuk menyaring konten secara ketat sesuai dengan standar nilai moral dan etika Pancasila.", val: 0}, {text: "Mengimbau masyarakat untuk membatasi penggunaan media sosial dan beralih ke aktivitas sosial kemasyarakatan yang bersifat fisik.", val: 0}, {text: "Melakukan sensor massal terhadap akun-akun luar negeri yang memiliki pengaruh besar namun tidak sejalan dengan budaya nusantara.", val: 0}] },
{ text: "Sebuah konsorsium internasional menawarkan investasi pembangunan pelabuhan logistik terbesar di wilayah Indonesia Timur dengan janji pertumbuhan ekonomi lokal yang sangat cepat, namun mereka mensyaratkan penggunaan sistem navigasi dan keamanan laut milik mereka sendiri secara eksklusif dengan alasan standar keselamatan internasional. Mengingat lokasi tersebut berdekatan dengan jalur pelayaran strategis dan wilayah militer, kebijakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: "Menerima investasi tersebut sepenuhnya demi mengejar ketertinggalan ekonomi rakyat di wilayah Indonesia Timur.", val: 0}, {text: "Menyetujui syarat tersebut asalkan otoritas militer Indonesia tetap diberikan akses untuk memantau data secara berkala.", val: 0}, {text: "Menolak persyaratan sistem navigasi asing dan mewajibkan integrasi dengan sistem pertahanan laut nasional secara mutlak.", val: 5}, {text: "Meminta kompensasi berupa pembangunan fasilitas publik lainnya agar masyarakat mendapatkan manfaat yang seimbang.", val: 0}, {text: "Menyarankan lokasi pembangunan dipindahkan ke wilayah lain yang tidak memiliki nilai strategis secara militer.", val: 0}] },
{ text: "Seorang ilmuwan data yang bekerja di instansi pemerintah menemukan bahwa algoritma sistem bantuan sosial nasional yang baru dikembangkan memiliki celah yang memungkinkan data kependudukan warga negara dapat dipetakan secara mendalam oleh pihak ketiga. Jika ia melaporkan hal ini secara formal, peluncuran program bantuan yang sangat dinanti masyarakat miskin akan tertunda selama berbulan-bulan akibat perbaikan sistem. Tindakan yang paling mewakili esensi Bela Negara dalam situasi dilematis ini adalah...", options: [{text: "Tetap meluncurkan program tersebut sesuai jadwal demi menyelamatkan ekonomi rakyat kecil yang sedang membutuhkan bantuan.", val: 0}, {text: "Melaporkan temuan celah keamanan tersebut secara resmi dan merekomendasikan penundaan hingga sistem benar-benar aman.", val: 5}, {text: "Meluncurkan program namun secara bertahap melakukan perbaikan sistem tanpa harus memberitahu publik mengenai celah tersebut.", val: 0}, {text: "Meminta perusahaan pengembang sistem untuk bertanggung jawab penuh secara hukum jika di masa depan terjadi kebocoran data.", val: 0}, {text: "Menyarankan penggunaan data sementara yang tidak sensitif agar program tetap berjalan meskipun tidak akurat 100%.", val: 0}] },
];

const twk_Integritas = [
{ text: "Anda adalah seorang Pejabat Pembuat Komitmen (PPK) di sebuah kementerian yang sedang menjalankan proyek pengadaan bantuan sosial darurat untuk wilayah terdampak bencana. Di tengah proses, atasan langsung Anda meminta agar pemenang tender dialihkan kepada sebuah perusahaan yang dimiliki oleh kerabat dekat seorang tokoh masyarakat berpengaruh. Atasan berargumen bahwa hal ini demi menjaga kondusivitas politik dan menjamin distribusi bantuan di lapangan tidak dihambat oleh kelompok lokal yang berafiliasi dengan tokoh tersebut. Di sisi lain, perusahaan tersebut secara teknis memiliki rekam jejak yang kurang meyakinkan dibandingkan kandidat pemenang saat ini. Sikap yang paling mencerminkan integritas tinggi dalam situasi tersebut adalah...", options: [{text: "Menyetujui permintaan atasan demi kelancaran distribusi bantuan di lapangan karena keselamatan warga terdampak bencana adalah prioritas kemanusiaan yang paling utama.", val: 0}, {text: "Meminta perusahaan kerabat tokoh tersebut untuk bekerja sama (sub-kontrak) dengan pemenang tender yang asli agar kualitas pekerjaan tetap terjaga namun aspek politis tetap terakomodasi.", val: 0}, {text: "Melaporkan tekanan tersebut kepada pihak otoritas pengawas internal (Itjen) dan tetap menjalankan proses pengadaan sesuai dengan hasil seleksi teknis yang objektif.", val: 5}, {text: "Mengajukan pengunduran diri dari posisi PPK karena merasa terjepit di antara tekanan atasan dan prinsip pribadi, agar posisi tersebut dapat diisi oleh orang lain yang lebih mampu berkompromi.", val: 0}, {text: "Menjelaskan secara persuasif kepada atasan mengenai risiko hukum yang besar bagi institusi, lalu menyarankan agar tokoh masyarakat tersebut diberikan peran lain dalam bentuk seremonial pembagian bantuan.", val: 0}] },
{ text: "Anda adalah seorang auditor internal yang menemukan adanya ketidaksesuaian administratif kronis dalam penggunaan anggaran perjalanan dinas di unit kerja Anda. Praktik ini sudah berlangsung bertahun-tahun dan dianggap sebagai tradisi untuk menutupi biaya operasional kantor yang tidak terakomodasi dalam DIPA. Rekan sejawat dan atasan meminta Anda untuk memaklumi hal tersebut demi menjaga keharmonisan internal dan memastikan kegiatan operasional kantor tetap berjalan lancar tanpa kendala biaya. Sikap Anda adalah...", options: [{text: "Menyarankan kepada atasan untuk segera melakukan revisi anggaran (DIPA) agar biaya operasional yang tidak tercover dapat masuk ke dalam pos yang resmi secara bertahap.", val: 0}, {text: "Tetap mencatatkan temuan tersebut secara objektif dalam Laporan Hasil Audit (LHA) sesuai dengan fakta yang ditemukan tanpa melakukan kompromi administratif.", val: 5}, {text: "Memberikan catatan perbaikan internal (nota dinas) tanpa memasukkannya ke laporan resmi guna memberikan kesempatan bagi unit kerja untuk berbenah tanpa merusak reputasi instansi.", val: 0}, {text: "Mendiskusikan solusi kreatif dengan bagian keuangan agar pengalokasian dana tetap terlihat sesuai prosedur namun tetap bisa membiayai operasional kantor yang mendesak.", val: 0}, {text: "Menyetujui kebijakan tersebut selama dana digunakan murni untuk kepentingan kantor dan bukan untuk memperkaya diri sendiri atau oknum tertentu.", val: 0}] },
{ text: "Menjelang pemilihan kepala daerah, seorang calon merupakan sahabat karib yang pernah berjasa besar dalam kehidupan pribadi Anda. Suatu hari, ia meminta izin untuk mengadakan pertemuan silaturahmi di kediaman Anda dengan warga sekitar. Ia menegaskan tidak akan ada atribut kampanye, hanya sekadar berbincang dan makan bersama sebagai bentuk kedekatan personal. Mengingat posisi Anda sebagai ASN yang harus menjaga netralitas, tindakan yang paling tepat adalah...", options: [{text: "Mengizinkan pertemuan tersebut di rumah Anda dengan syarat tidak ada pembicaraan politik atau ajakan memilih, karena menghormati nilai persahabatan adalah bagian dari etika kemanusiaan.", val: 0}, {text: "Menyarankan sahabat Anda untuk mengadakan pertemuan di tempat netral seperti rumah makan atau aula umum agar status Anda sebagai ASN tetap aman dari kecurigaan publik.", val: 0}, {text: "Menolak dengan santun dan menjelaskan bahwa sebagai ASN, Anda harus menghindari segala situasi yang dapat dipersepsikan sebagai dukungan politik, meskipun tanpa atribut kampanye.", val: 5}, {text: "Menghadiri pertemuan tersebut namun tetap bersikap pasif dan tidak ikut berbicara agar tetap dapat menjaga hubungan baik tanpa melanggar aturan netralitas secara langsung.", val: 0}, {text: "Meminta anggota keluarga lain yang bukan ASN untuk menjadi tuan rumah pertemuan tersebut agar secara administratif Anda tidak terlibat dalam kegiatan politik praktis.", val: 0}] },
{ text: "Unit kerja Anda sedang mengejar target kepatuhan pelayanan publik yang dinilai langsung oleh lembaga pengawas. Terdapat satu prosedur verifikasi dokumen yang memakan waktu lama dan sering menyebabkan antrean panjang. Atasan memerintahkan untuk melakukan verifikasi cepat dengan melewatkan beberapa tahapan pengecekan validitas dokumen agar target waktu pelayanan tercapai dan instansi mendapatkan penghargaan. Jika Anda tetap mengikuti prosedur, antrean akan membeludak dan masyarakat akan komplain. Sikap Anda adalah...", options: [{text: "Mengikuti instruksi atasan untuk melakukan verifikasi cepat demi kepuasan masyarakat yang tidak ingin mengantre terlalu lama (Public Satisfaction).", val: 0}, {text: "Melakukan verifikasi cepat hanya untuk dokumen yang terlihat meyakinkan, sementara dokumen yang mencurigakan tetap diverifikasi secara ketat agar asas kehati-hatian tetap terjaga.", val: 0}, {text: "Tetap menjalankan seluruh tahapan verifikasi sesuai SOP meskipun harus menghadapi keluhan masyarakat dan teguran atasan demi menjamin kebenaran data.", val: 5}, {text: "Mengusulkan kepada atasan untuk menambah personil dari unit lain secara sementara agar prosedur tetap dijalankan penuh namun waktu tunggu dapat dipangkas secara efektif.", val: 0}, {text: "Melakukan simplifikasi prosedur secara mandiri yang menurut penilaian profesional Anda tidak akan mengurangi esensi keamanan namun tetap mempercepat layanan.", val: 0}] },
{ text: "Anda adalah seorang auditor internal yang baru saja menemukan adanya praktik uang operasional tambahan di sebuah unit kerja. Dana ini dikumpulkan dari pemotongan sah honorarium narasumber dan uang perjalanan dinas staf secara sukarela untuk membiayai kegiatan sosial kantor, seperti santunan duka dan bantuan kesehatan bagi honorer yang tidak dicover asuransi. Seluruh staf setuju dan menganggap ini sebagai bentuk solidaritas korps yang mulia. Atasan meminta Anda untuk tidak mencantumkan temuan ini dalam laporan resmi agar iklim kerja yang harmonis tidak rusak. Sikap Anda adalah...", options: [{text: "Menyetujui usulan atasan dengan memberikan catatan internal agar praktik tersebut diubah menjadi sistem iuran sukarela yang terpisah dari pemotongan hak administratif negara.", val: 0}, {text: "Mengapresiasi nilai solidaritas tersebut namun tetap mencantumkan temuan pemotongan hak dalam laporan audit sesuai fakta objektif tanpa pengecualian.", val: 5}, {text: "Menyarankan kepada unit kerja untuk segera menghentikan praktik tersebut dan mengembalikan sisa dana yang terkumpul kepada yang berhak sebelum laporan audit final diterbitkan.", val: 0}, {text: "Membuat laporan yang bersifat pembinaan dengan memberikan rekomendasi perbaikan tanpa menyebutkan detail pemotongan agar tidak terjadi sanksi administratif yang berat bagi rekan sejawat.", val: 0}, {text: "Mengonsultasikan masalah ini kepada pimpinan tertinggi untuk mencari jalan tengah agar integritas audit terjaga namun fungsi sosial di unit kerja tersebut tetap bisa berjalan.", val: 0}] },
{ text: "Instansi Anda sedang dalam proses pengadaan lahan untuk proyek strategis nasional. Anda mengetahui bahwa data penilaian harga tanah (appraisal) yang digunakan sedikit di atas harga pasar karena ada tekanan dari pimpinan wilayah agar proses pembebasan lahan berjalan cepat tanpa konflik dengan warga. Jika Anda memprotes, proyek akan tertunda dan target instansi tahun ini akan gagal total, yang berdampak pada remunerasi seluruh pegawai. Atasan meminta Anda menutup mata demi kesejahteraan bersama dan kelancaran program pemerintah. Tindakan Anda adalah...", options: [{text: "Mendukung keputusan tersebut karena percepatan proyek strategis nasional memiliki dampak ekonomi yang jauh lebih besar bagi masyarakat luas daripada selisih harga lahan.", val: 0}, {text: "Mengusulkan diadakannya penilaian ulang oleh tim independen yang berbeda untuk memastikan harga yang ditetapkan benar-benar akuntabel secara hukum dan etika.", val: 0}, {text: "Menyusun laporan keberatan secara tertulis kepada atasan mengenai ketidaksesuaian harga tersebut sebagai bentuk tanggung jawab profesional, meskipun risiko ditolak tetap ada.", val: 5}, {text: "Menolak menandatangani dokumen verifikasi harga tersebut dan meminta atasan untuk menugaskan pejabat lain jika ingin tetap melanjutkan prosedur yang tidak sesuai standar.", val: 0}, {text: "Menyarankan agar selisih harga tersebut dikompensasi dengan peningkatan spesifikasi pembangunan di lahan tersebut agar nilai manfaat yang diterima negara tetap sebanding.", val: 0}] },
{ text: "Sebagai kepala bagian pelayanan, Anda menghadapi situasi di mana seorang warga miskin memerlukan dokumen perizinan mendesak untuk pengobatan anggota keluarganya. Namun, ada satu syarat administrasi yang belum terpenuhi dan tidak mungkin selesai dalam waktu singkat. Rekan kerja Anda menyarankan untuk mempermudah saja dengan memalsukan status kelengkapan di sistem agar izin terbit hari itu juga. Jika Anda menolak, keselamatan nyawa orang tersebut terancam. Sikap yang paling mencerminkan integritas adalah...", options: [{text: "Memberikan izin tersebut secara manual dengan catatan khusus dan menjamin secara pribadi bahwa kekurangan berkas akan segera dilengkapi dalam waktu 1x24 jam.", val: 0}, {text: "Menolak memberikan izin sampai syarat terpenuhi, namun secara pribadi membantu warga tersebut mengurus kekurangan berkasnya hingga selesai secepat mungkin.", val: 0}, {text: "Meminta staf untuk melompati prosedur sistem demi misi kemanusiaan, karena hukum tertinggi adalah keselamatan nyawa manusia (Salus Populi Suprema Lex Esto).", val: 0}, {text: "Mengarahkan warga tersebut untuk mencari bantuan dari lembaga sosial yang memiliki akses khusus ke pimpinan instansi agar diberikan diskresi resmi yang legal.", val: 0}, {text: "Tetap pada prosedur yang ada namun memberikan layanan pendampingan prioritas bagi warga tersebut agar proses birokrasi yang tersisa dapat dipercepat tanpa melanggar aturan.", val: 5}] },
{ text: "Anda adalah anggota tim seleksi untuk pengisian jabatan pimpinan tinggi di instansi Anda. Salah satu kandidat terkuat adalah rekan kerja yang selama ini sangat membantu karier Anda dan dikenal memiliki kompetensi luar biasa. Namun, saat proses verifikasi rekam jejak, Anda menemukan indikasi bahwa kandidat tersebut pernah melakukan manipulasi data laporan kinerja ringan beberapa tahun lalu untuk mendapatkan penghargaan. Jika Anda melaporkan ini, ia pasti gugur dan hubungan baik Anda akan hancur. Jika tidak, ia adalah orang paling kompeten untuk jabatan tersebut. Sikap integritas Anda adalah...", options: [{text: "Tetap memberikan penilaian tinggi pada aspek kompetensi namun memberikan catatan kecil mengenai temuan tersebut agar menjadi bahan pertimbangan pimpinan akhir (User).", val: 0}, {text: "Mengabaikan temuan tersebut karena manipulasi yang dilakukan bersifat ringan, terjadi di masa lalu, dan tidak sebanding dengan besarnya kontribusi yang bisa ia berikan bagi instansi.", val: 0}, {text: "Menyampaikan temuan tersebut secara transparan dalam rapat pleno tim seleksi sebagai bagian dari fakta rekam jejak yang harus divalidasi tanpa memandang hubungan personal.", val: 5}, {text: "Meminta kandidat tersebut secara pribadi untuk mengundurkan diri dari proses seleksi agar rahasianya tetap terjaga namun posisi jabatan tetap diisi oleh orang yang bersih.", val: 0}, {text: "Menyarankan kepada tim seleksi untuk memperdalam verifikasi pada seluruh kandidat tanpa menunjuk langsung pada rekan Anda, agar proses terlihat adil bagi semua pihak.", val: 0}] },
{ text: "Instansi Anda baru saja merilis aplikasi pelayanan publik baru yang diklaim sukses besar oleh pimpinan. Namun, sebagai analis sistem, Anda menemukan adanya celah keamanan data (bug) yang berpotensi membocorkan data pribadi pengguna jika diakses secara massal. Pimpinan meminta Anda untuk tidak membesar-besarkan masalah ini ke publik atau pihak pengawas luar agar tidak merusak citra instansi yang sedang naik daun, sembari memperbaiki celah tersebut secara perlahan. Tindakan yang paling berintegritas adalah...", options: [{text: "Mematuhi instruksi pimpinan untuk memperbaiki celah secara diam-diam demi menjaga kepercayaan masyarakat terhadap inovasi teknologi pemerintah.", val: 0}, {text: "Mengusulkan kepada pimpinan untuk menonaktifkan sementara layanan aplikasi tersebut dengan alasan pemeliharaan rutin sampai celah keamanan benar-benar diperbaiki.", val: 0}, {text: "Menyampaikan laporan teknis secara tertulis mengenai risiko fatal kebocoran data dan mendesak pimpinan untuk memberikan pernyataan transparan kepada pengguna.", val: 5}, {text: "Menghubungi rekan media secara anonim untuk membocorkan celah keamanan tersebut agar masyarakat waspada dan pimpinan dipaksa bertindak cepat.", val: 0}, {text: "Membuat pengumuman di media sosial pribadi mengenai risiko aplikasi tersebut agar lingkungan terdekat Anda tidak menjadi korban kebocoran data pribadi.", val: 0}] },
{ text: "Anda sedang menangani proyek pembangunan fasilitas umum yang anggarannya sudah ditetapkan. Di tengah jalan, Anda menyadari ada spesifikasi material yang diturunkan (downgrade) oleh kontraktor dengan persetujuan lisan dari pejabat atasan Anda untuk efisiensi. Anda diminta menandatangani berita acara serah terima pekerjaan seolah-olah semua sesuai spesifikasi awal. Jika Anda menolak, karier Anda akan dihambat dan Anda akan dipindahkan ke unit terpencil. Sikap Anda adalah...", options: [{text: "Menandatangani dokumen tersebut namun membuat catatan terpisah (disclaimer) yang menyatakan bahwa Anda hanya menjalankan perintah atasan demi keamanan posisi.", val: 0}, {text: "Menolak menandatangani berita acara tersebut dan siap menerima konsekuensi pemindahan tugas sebagai bentuk kepatuhan pada standar kualitas dan aturan hukum.", val: 5}, {text: "Menghubungi pihak kontraktor untuk mengembalikan spesifikasi ke standar awal secara mandiri tanpa melibatkan atasan agar tidak terjadi konflik internal yang tajam.", val: 0}, {text: "Meminta pendapat dari ahli hukum instansi mengenai konsekuensi hukum jika menandatangani dokumen tersebut, lalu mengikuti saran yang paling minim risiko pidana.", val: 0}, {text: "Menandatangani dokumen tersebut dengan syarat pihak kontraktor memberikan jaminan pemeliharaan yang lebih lama sebagai kompensasi atas penurunan spesifikasi material.", val: 0}] },
{ text: "Instansi Anda sedang merancang regulasi baru terkait standarisasi alat kesehatan. Sebagai anggota tim perumus, Anda menyadari bahwa salah satu kriteria teknis yang diusulkan oleh ketua tim secara spesifik hanya bisa dipenuhi oleh perusahaan milik mantan atasan Anda yang dulu sangat berjasa membantu kenaikan pangkat Anda. Ketua tim berargumen bahwa kriteria tersebut demi menjamin kualitas terbaik bagi masyarakat. Analisis Anda terhadap situasi ini berdasarkan prinsip integritas adalah...", options: [{text: "Mendukung kriteria tersebut karena kualitas layanan publik dan keselamatan pasien adalah hukum tertinggi yang harus diutamakan di atas kecurigaan administratif.", val: 0}, {text: "Mengusulkan penambahan kriteria pembanding dari standar internasional agar spesifikasi tidak mengarah pada satu vendor tertentu dan menjamin kompetisi yang sehat.", val: 5}, {text: "Meminta izin untuk mengundurkan diri dari tim perumus guna menghindari persepsi konflik kepentingan karena adanya hubungan emosional dengan pemilik perusahaan terkait.", val: 0}, {text: "Menyetujui kriteria tersebut dengan syarat proses lelang nantinya dilakukan secara terbuka dan diawasi ketat oleh Komisi Pengawas Persaingan Usaha (KPPU).", val: 0}, {text: "Mendiamkan hal tersebut selama kriteria teknis yang diajukan memang memiliki dasar saintifik yang dapat dipertanggungjawabkan secara profesional.", val: 0}] },
{ text: "Dalam sebuah perjalanan dinas luar kota yang jadwalnya sangat padat, Anda melihat rekan senior Anda menggunakan mobil dinas jemputan untuk pergi ke pusat perbelanjaan guna membeli oleh-oleh bagi pimpinan di kantor pusat. Rekan tersebut berargumen bahwa hal ini dilakukan agar efisien dan tidak membuang waktu, sehingga mereka bisa segera kembali ke hotel untuk menyelesaikan laporan kegiatan. Analisis tindakan yang paling mencerminkan integritas dalam situasi ini adalah...", options: [{text: "Memaklumi tindakan tersebut karena tujuannya adalah efisiensi waktu agar tugas laporan cepat selesai demi kepentingan organisasi.", val: 0}, {text: "Menyarankan rekan tersebut untuk menggunakan transportasi umum atau taksi daring guna memisahkan urusan pribadi/sosial dengan fasilitas negara.", val: 5}, {text: "Mengingatkan rekan tersebut bahwa memberikan oleh-oleh kepada pimpinan dapat dikategorikan sebagai gratifikasi yang dilarang oleh aturan kepegawaian.", val: 0}, {text: "Melaporkan penggunaan fasilitas dinas tersebut kepada bagian kendaraan agar dilakukan evaluasi terhadap prosedur peminjaman mobil di luar jam kerja.", val: 0}, {text: "Ikut pergi bersama rekan tersebut agar dapat memastikan bahwa penggunaan mobil dinas tidak disalahgunakan untuk keperluan lain yang lebih menyimpang.", val: 0}] },
{ text: "Anda adalah seorang kepala subbagian yang mendapati bahwa salah satu staf terbaik Anda melakukan kesalahan input data keuangan yang cukup signifikan. Staf tersebut mengakui bahwa kesalahan terjadi karena ia sedang kelelahan mengurus orang tuanya yang sakit sakral, namun ia memohon agar kesalahan tersebut diperbaiki secara diam-diam tanpa melalui prosedur revisi resmi agar nilai capaian kinerja unit Anda tidak turun di mata pimpinan. Analisis keputusan terbaik Anda adalah...", options: [{text: "Membantu staf tersebut memperbaiki data secara mandiri karena empati terhadap kondisi keluarganya dan demi menjaga prestasi unit kerja.", val: 0}, {text: "Menolak permohonan tersebut dan memberikan sanksi teguran keras secara lisan agar staf tersebut lebih teliti di masa depan meskipun dalam kondisi sulit.", val: 0}, {text: "Melakukan prosedur revisi sesuai ketentuan yang berlaku dan tetap mencatatkan kesalahan tersebut sebagai bahan evaluasi kinerja secara objektif.", val: 5}, {text: "Meminta staf lain untuk memperbaiki kesalahan tersebut agar tidak terjadi konflik kepentingan antara Anda sebagai atasan dengan staf yang sedang tertimpa musibah.", val: 0}, {text: "Melaporkan kejadian tersebut kepada pimpinan dengan menekankan pada prestasi staf sebelumnya agar kesalahan kali ini dapat dimaafkan tanpa catatan resmi.", val: 0}] },
{ text: "Unit kerja Anda memiliki sisa anggaran sosialisasi di akhir tahun yang cukup besar. Jika tidak habis, serapan anggaran Anda dinilai buruk dan pagu anggaran tahun depan terancam dipotong. Atasan menginstruksikan untuk membuat kegiatan Rapat Koordinasi di hotel mewah selama tiga hari dengan mengundang narasumber formal, namun agenda utamanya sebenarnya adalah rekreasi (family gathering) staf agar motivasi kerja meningkat setelah setahun bekerja keras. Analisis Anda terhadap situasi ini adalah...", options: [{text: "Menyetujui rencana tersebut karena peningkatan motivasi staf secara tidak langsung akan berdampak positif pada produktivitas dan pencapaian target organisasi di tahun depan.", val: 0}, {text: "Menyarankan agar kegiatan tetap dilaksanakan di kantor dengan agenda yang lebih padat, namun sisa anggaran dialihkan untuk pengadaan fasilitas kerja yang lebih mendesak bagi staf.", val: 0}, {text: "Menolak rencana tersebut karena penggunaan anggaran negara harus sesuai dengan nomenklatur dan substansi kegiatan, bukan sekadar untuk menghabiskan sisa pagu (serapan).", val: 5}, {text: "Mengusulkan untuk mengubah durasi rapat menjadi satu hari yang efektif, lalu sisa dananya dikembalikan ke kas negara sebagai bentuk efisiensi dan kejujuran anggaran.", val: 0}, {text: "Mendukung kegiatan tersebut selama ada output laporan kegiatan (notulensi) yang formal agar secara administratif tidak menjadi temuan oleh pemeriksa keuangan (BPK).", val: 0}] },
{ text: "Anda baru saja menyelesaikan proyek renovasi gedung kantor dengan hasil yang sangat memuaskan dan tepat waktu. Pihak kontraktor, sebagai bentuk syukur dan apresiasi atas profesionalisme tim Anda, mengirimkan sejumlah paket perangkat elektronik terbaru ke rumah masing-masing anggota tim, termasuk Anda. Mereka menegaskan bahwa ini bukan suap karena proyek sudah selesai 100% dan tidak ada lagi urusan bisnis di masa depan. Analisis tindakan yang paling mencerminkan integritas adalah...", options: [{text: "Menerima pemberian tersebut sebagai bentuk penghargaan atas prestasi kerja, asalkan dilaporkan kepada pimpinan sebagai inventaris pribadi yang sah.", val: 0}, {text: "Mengembalikan paket tersebut dengan sopan dan menjelaskan bahwa ASN dilarang menerima pemberian apa pun yang berhubungan dengan jabatan atau tugasnya.", val: 5}, {text: "Menerima paket tersebut namun kemudian menyumbangkannya ke panti asuhan atau lembaga sosial agar tidak ada keuntungan pribadi yang dinikmati.", val: 0}, {text: "Mengoordinasikan seluruh anggota tim untuk mengembalikan paket secara kolektif agar tidak terjadi kecemburuan sosial atau fitnah di lingkungan kantor.", val: 0}, {text: "Menanyakan kepada bagian kepatuhan internal apakah pemberian tersebut termasuk kategori gratifikasi yang wajib dilaporkan atau boleh dimiliki secara pribadi.", val: 0}] },
{ text: "Anda diminta oleh atasan untuk memberikan penilaian kinerja Sangat Baik kepada salah satu staf yang merupakan kerabat dekat pimpinan tertinggi di instansi Anda. Staf tersebut sebenarnya memiliki kinerja yang standar dan sering terlambat masuk kerja, namun atasan berargumen bahwa penilaian ini penting untuk menjaga hubungan baik antar-unit dan mempermudah koordinasi anggaran ke depannya. Analisis keputusan Anda adalah...", options: [{text: "Memberikan nilai sesuai permintaan atasan demi kepentingan organisasi yang lebih besar, namun memberikan catatan pembinaan secara lisan kepada staf tersebut.", val: 0}, {text: "Memberikan penilaian secara objektif berdasarkan indikator kinerja individu (KPI) yang nyata, meskipun berisiko memicu ketegangan dengan atasan atau pimpinan.", val: 5}, {text: "Memberikan nilai Baik (satu tingkat di bawah permintaan) sebagai jalan tengah agar tetap menghormati atasan namun tidak terlalu menyimpang dari kenyataan.", val: 0}, {text: "Menyarankan kepada atasan agar penilaian staf tersebut dilakukan oleh pejabat lain untuk menghindari subjektivitas dan konflik kepentingan pribadi Anda.", val: 0}, {text: "Menyetujui penilaian tersebut dengan syarat staf yang bersangkutan membuat komitmen tertulis untuk memperbaiki kedisiplinannya di masa mendatang.", val: 0}] },
{ text: "Sebagai sekretaris panitia lelang pengadaan infrastruktur, Anda menemukan bahwa atasan Anda (Ketua Panitia) secara sistematis membocorkan spesifikasi teknis dan Nilai HPS (Harga Perkiraan Sendiri) kepada salah satu vendor tertentu sebelum pengumuman resmi. Saat Anda konfrontasi secara pribadi, atasan Anda berkilah bahwa vendor tersebut adalah binaan instansi yang selalu memberikan hasil kerja berkualitas dan tepat waktu dibanding vendor lain. Atasan memperingatkan Anda bahwa membongkar hal ini akan membatalkan proyek pusat dan menghancurkan reputasi instansi di mata kementerian terkait. Tindakan Anda adalah...", options: [{text: "Mendokumentasikan seluruh bukti kebocoran data tersebut dan melaporkannya secara resmi melalui sistem Whistleblowing System (WBS) atau Inspektorat Jenderal demi menjaga keadilan kompetisi.", val: 5}, {text: "Menyetujui argumen atasan dengan syarat vendor tersebut harus memberikan jaminan kualitas tambahan (garansi) yang lebih lama sebagai bentuk pertanggungjawaban moral kepada negara.", val: 0}, {text: "Meminta mutasi ke unit kerja lain sesegera mungkin agar tidak terlibat lebih jauh dalam proses lelang yang tidak bersih tersebut namun tetap menjaga hubungan baik dengan atasan.", val: 0}, {text: "Menghubungi vendor pesaing untuk memberikan informasi serupa agar persaingan kembali menjadi seimbang dan tidak ada satu pihak yang mendominasi proyek secara tidak adil.", val: 0}, {text: "Menyarankan kepada atasan untuk melibatkan tim pendamping dari aparat penegak hukum (kejaksaan/kepolisian) agar proses lelang selanjutnya terlihat lebih transparan di mata publik.", val: 0}] },
{ text: "Instansi Anda mendapatkan sorotan tajam dari media karena kegagalan pencapaian target layanan masyarakat. Pimpinan memerintahkan tim IT dan humas untuk menyesuaikan data capaian di website resmi agar terlihat ada peningkatan signifikan, dengan alasan untuk meredam kegaduhan publik dan menjaga stabilitas sosial. Anda sebagai kepala bagian data tahu bahwa manipulasi ini akan menyesatkan kebijakan di masa depan. Evaluasi tindakan yang paling berintegritas adalah...", options: [{text: "Mengikuti instruksi pimpinan namun memberikan catatan kaki (disclaimer) yang sangat kecil agar secara teknis Anda tidak bisa disalahkan jika ada audit di kemudian hari.", val: 0}, {text: "Menolak melakukan manipulasi data dan bersedia memaparkan data asli serta kendala lapangan kepada pimpinan sebagai bahan evaluasi perbaikan layanan yang jujur.", val: 5}, {text: "Menyarankan pimpinan untuk hanya menampilkan data-data yang sukses saja (cherry picking) tanpa memanipulasi angka, agar citra instansi tetap terjaga secara parsial.", val: 0}, {text: "Melakukan manipulasi data sesuai perintah karena sebagai bawahan, tanggung jawab mutlak atas kebijakan tersebut berada di tangan pimpinan tertinggi, bukan pada pelaksana.", val: 0}, {text: "Mengusulkan untuk menutup sementara akses data publik dengan alasan perbaikan sistem (maintenance) sampai data yang asli berhasil diperbaiki secara nyata di lapangan.", val: 0}] },
{ text: "Dalam sebuah rapat internal, terungkap bahwa ada praktik pengumpulan dana taktis dari setiap vendor yang bekerja sama dengan instansi Anda. Dana ini dikelola secara transparan di internal untuk kesejahteraan seluruh pegawai, termasuk bantuan biaya sekolah anak staf golongan rendah dan rekreasi bersama. Semua pegawai merasa terbantu dan mendukung praktik ini. Anda sebagai pejabat baru diminta ikut menandatangani kesepakatan distribusi dana tersebut. Penilaian Anda terhadap situasi ini adalah...", options: [{text: "Menolak menandatangani dan melaporkan praktik tersebut kepada otoritas pengawas, meskipun Anda akan dimusuhi oleh seluruh rekan kerja di instansi tersebut.", val: 5}, {text: "Menandatangani kesepakatan tersebut karena dana digunakan untuk kesejahteraan bersama dan tidak ada satu pun oknum yang memperkaya diri secara pribadi.", val: 0}, {text: "Menyarankan agar dana tersebut dikelola oleh koperasi pegawai secara resmi agar memiliki payung hukum yang jelas dan tidak dianggap sebagai pungutan liar.", val: 0}, {text: "Bersedia menandatangani namun menolak menerima bagian dana tersebut untuk diri sendiri sebagai bentuk kompromi antara integritas pribadi dan solidaritas kantor.", val: 0}, {text: "Meminta pendapat dari Dewan Etik instansi secara tertulis untuk memastikan apakah praktik tersebut dapat dilegalkan melalui peraturan internal pimpinan.", val: 0}] },
{ text: "Anda adalah seorang petugas verifikasi pajak. Kakak kandung Anda, yang sedang mengalami kesulitan keuangan serius karena usahanya hampir bangkrut, meminta bantuan Anda untuk sedikit menyesuaikan laporan audit pajaknya agar denda keterlambatannya dapat dihapuskan. Jika denda tidak dihapus, ia terancam kehilangan rumah tempat tinggalnya. Tindakan yang paling mencerminkan integritas tertinggi adalah...", options: [{text: "Memberikan petunjuk teknis legal agar ia bisa mengajukan keringanan denda secara resmi ke kantor pajak.", val: 0}, {text: "Menolak membantu secara kedinasan dan memilih membantu secara pribadi dengan menyisihkan gaji Anda.", val: 0}, {text: "Melimpahkan proses verifikasi pajak kakak Anda kepada rekan sejawat untuk menjaga objektivitas penilaian.", val: 0}, {text: "Menolak permintaan tersebut secara tegas dan tetap memproses denda sesuai dengan ketentuan yang berlaku.", val: 5}, {text: "Menyarankan kakak Anda untuk berkonsultasi dengan konsultan pajak profesional guna mencari celah hukum.", val: 0}] },
{ text: "Setelah membantu seorang warga lanjut usia mengurus sertifikat tanah yang sempat tertahan lama karena kendala administrasi, warga tersebut datang ke rumah Anda membawa hasil kebun dan makanan rumahan sebagai tanda terima kasih yang tulus. Beliau bersikeras bahwa ini bukan suap, melainkan sedekah dan penghormatan kepada Anda yang telah bekerja jujur. Sikap Anda adalah...", options: [{text: "Menerima pemberian tersebut agar tidak melukai perasaan dan harga diri warga lanjut usia tersebut.", val: 0}, {text: "Menerima pemberian tersebut namun segera membagikannya kembali kepada tetangga atau fakir miskin.", val: 0}, {text: "Menolak dengan santun sambil menjelaskan bahwa melayani masyarakat adalah kewajiban yang sudah digaji negara.", val: 5}, {text: "Menerima hanya sebagian kecil sebagai bentuk menghargai niat baik, lalu melaporkannya ke Unit Pengendalian Gratifikasi.", val: 0}, {text: "Menyarankan warga tersebut untuk memberikan makanan itu kepada staf di kantor secara kolektif sebagai bentuk apresiasi.", val: 0}] },
{ text: "Anda menemukan bahwa sistem pelaporan kinerja instansi Anda memiliki kelemahan teknis yang memungkinkan data diinput dua kali (double counting) sehingga capaian organisasi terlihat jauh melampaui target. Pimpinan meminta Anda mendiamkan hal tersebut karena data tersebut akan digunakan untuk pengajuan kenaikan tunjangan kinerja (tukin) seluruh pegawai bulan depan. Tindakan Anda adalah...", options: [{text: "Menyusun nota dinas resmi mengenai kelemahan sistem tersebut kepada bagian IT dan pimpinan tertinggi.", val: 5}, {text: "Memperbaiki sistem secara mandiri tanpa membuat kegaduhan agar kenaikan tukin tetap dapat diproses.", val: 0}, {text: "Menyetujui kebijakan tersebut demi kesejahteraan rekan kerja yang sudah bekerja keras sepanjang tahun.", val: 0}, {text: "Meminta pimpinan untuk menunda pengajuan tukin sampai data diperbaiki secara manual satu per satu.", val: 0}, {text: "Mengonsultasikan risiko hukum dari manipulasi data tersebut kepada biro hukum sebelum bertindak.", val: 0}] },
{ text: "Anda menemukan bahwa seorang rekan kerja yang juga sahabat karib Anda sering meninggalkan kantor pada jam kerja untuk urusan bisnis pribadi. Sahabat Anda beralasan ia harus mencari penghasilan tambahan karena gaji ASN tidak cukup untuk biaya pengobatan anaknya. Ia meminta Anda untuk tetap mencatatkan kehadirannya di sistem presensi manual. Tindakan Anda adalah...", options: [{text: "Menolak permintaan tersebut dan menyarankan ia mengambil cuti resmi.", val: 0}, {text: "Melaporkan ketidakhadiran tersebut secara objektif pada atasan langsung.", val: 5}, {text: "Menyetujui permintaannya hanya saat kondisi kesehatan anaknya memburuk.", val: 0}, {text: "Mengingatkan sahabat Anda tanpa melaporkannya agar ia tidak terkena sanksi.", val: 0}, {text: "Mengajak rekan-rekan lain untuk memberikan bantuan dana agar ia tidak bolos.", val: 0}] },
{ text: "Instansi Anda sedang menyusun daftar penerima beasiswa pendidikan luar negeri. Pimpinan meminta Anda memasukkan nama putra dari seorang pejabat kementerian pusat yang selama ini mempermudah urusan anggaran instansi Anda. Putra pejabat tersebut memenuhi syarat minimum, namun ada kandidat lain yang memiliki kualifikasi jauh lebih unggul. Sikap integritas Anda adalah...", options: [{text: "Menyarankan penambahan kuota beasiswa agar kedua kandidat dapat diterima.", val: 0}, {text: "Menetapkan daftar penerima beasiswa murni berdasarkan peringkat nilai terbaik.", val: 5}, {text: "Meminta arahan tertulis dari pimpinan untuk melegitimasi keputusan tersebut.", val: 0}, {text: "Menempatkan putra pejabat pada daftar cadangan guna menghargai relasi pimpinan.", val: 0}, {text: "Mendiskusikan solusi pembagian kategori beasiswa yang berbeda bagi keduanya.", val: 0}] },
{ text: "Seorang mantan atasan yang dulu sangat berjasa dalam karier Anda menghubungi dan menanyakan informasi mengenai draf regulasi baru yang belum disahkan, karena ia ingin mempersiapkan strategi bisnis perusahaannya lebih awal. Beliau meyakinkan bahwa informasi tersebut tidak akan disebarkan ke pihak lain. Tindakan Anda adalah...", options: [{text: "Memberikan poin-poin garis besarnya saja tanpa melampirkan draf dokumen asli.", val: 0}, {text: "Menolak memberikan informasi tersebut dan menjelaskan bahwa dokumen masih rahasia.", val: 5}, {text: "Menyarankan beliau untuk menunggu hingga regulasi tersebut diumumkan secara resmi.", val: 0}, {text: "Meminta izin kepada atasan saat ini apakah informasi tersebut boleh dibagikan terbatas.", val: 0}, {text: "Menjelaskan secara umum mengenai arah kebijakan tanpa menyentuh detail teknis draf.", val: 0}] },
{ text: "Seorang rekan kerja senior yang sedang dalam pemeriksaan disiplin meminta Anda untuk memberikan testimoni yang meringankan dirinya, meskipun Anda tahu persis bahwa ia memang melakukan pelanggaran tersebut. Ia mengingatkan bahwa jika ia dipecat, keluarganya akan menderita. Sikap Anda adalah...", options: [{text: "Memberikan testimoni yang bersifat netral untuk menjaga perasaan rekan.", val: 0}, {text: "Menolak memberikan testimoni apa pun agar tidak terlibat dalam konflik.", val: 0}, {text: "Memberikan keterangan sesuai fakta yang sebenarnya secara transparan.", val: 5}, {text: "Menyarankan rekan tersebut untuk mengakui kesalahan agar sanksi ringan.", val: 0}, {text: "Meminta pendapat pimpinan sebelum memberikan keterangan kepada tim pemeriksa.", val: 0}] },
{ text: "Anda adalah anggota tim pengadaan barang yang mendapati bahwa salah satu vendor yang ikut tender adalah perusahaan milik sepupu Anda. Meskipun perusahaan tersebut sangat profesional dan memiliki harga termurah, Anda khawatir akan adanya persepsi negatif. Tindakan Anda adalah...", options: [{text: "Mengundurkan diri dari keanggotaan tim pengadaan untuk menghindari konflik.", val: 0}, {text: "Tetap dalam tim dan memberikan penilaian objektif berdasarkan data teknis.", val: 0}, {text: "Meminta sepupu Anda untuk menarik diri dari proses tender demi nama baik.", val: 0}, {text: "Melaporkan hubungan kekerabatan tersebut kepada ketua tim seleksi.", val: 5}, {text: "Menyarankan tim untuk mencari vendor lain yang memiliki kualitas setara.", val: 0}] },
{ text: "Pimpinan instansi Anda meminta Anda untuk memprioritaskan penyelesaian dokumen perizinan milik koleganya, padahal ada ratusan dokumen warga lain yang sudah mengantre lebih dulu. Pimpinan berargumen ini untuk kelancaran investasi daerah. Sikap Anda adalah...", options: [{text: "Mempercepat dokumen tersebut selama tidak ada aturan yang dilanggar secara fatal.", val: 0}, {text: "Mengerjakan sesuai urutan antrean tanpa memberikan perlakuan khusus kepada siapa pun.", val: 5}, {text: "Menugaskan staf lain untuk mengerjakannya agar Anda tidak melanggar prinsip pribadi.", val: 0}, {text: "Menjelaskan kepada pimpinan bahwa tindakan tersebut merusak standar pelayanan publik.", val: 0}, {text: "Memberikan pelayanan prioritas hanya jika kolega tersebut membawa surat tugas resmi.", val: 0}] },
{ text: "Instansi Anda memberikan fasilitas laptop dinas terbaru untuk menunjang pekerjaan di rumah selama masa pemulihan kesehatan Anda. Anak Anda yang sedang menyusun skripsi mengalami kerusakan laptop dan memohon untuk meminjam laptop dinas tersebut hanya untuk satu malam agar bisa menyelesaikan bab terakhirnya. Mengingat laptop tersebut sedang tidak Anda gunakan, sikap Anda adalah...", options: [{text: "Meminjamkan laptop tersebut dengan pengawasan ketat agar tidak ada data kantor yang terhapus.", val: 0}, {text: "Menolak meminjamkan dan menjelaskan bahwa fasilitas negara hanya untuk kepentingan jabatan.", val: 5}, {text: "Mengizinkan penggunaan laptop hanya untuk mengetik tanpa menghubungkannya ke jaringan internet.", val: 0}, {text: "Meminta izin kepada atasan terlebih dahulu sebelum memutuskan untuk meminjamkan kepada anak.", val: 0}, {text: "Menyarankan anak Anda untuk menggunakan komputer di warnet atau meminjam teman sejawatnya.", val: 0}] },
{ text: "Anda sedang memproses sengketa lahan antara sebuah perusahaan besar dan masyarakat adat. Seorang pengacara perusahaan tersebut mendatangi Anda dan menawarkan bantuan dana pendidikan bagi anak Anda yang sedang kuliah, tanpa meminta janji apa pun terkait hasil sengketa. Pengacara tersebut menyatakan ini murni bantuan sosial perusahaan (CSR) bagi ASN berprestasi. Sikap Anda adalah...", options: [{text: "Menolak bantuan tersebut untuk menjaga independensi Anda dalam menangani kasus sengketa.", val: 5}, {text: "Menerima bantuan tersebut selama tidak ada kontrak tertulis yang mengikat keputusan Anda.", val: 0}, {text: "Menyarankan agar bantuan dialokasikan langsung ke panti asuhan agar lebih tepat sasaran.", val: 0}, {text: "Melaporkan tawaran tersebut kepada pimpinan sebagai upaya gratifikasi yang terselubung.", val: 0}, {text: "Mengarahkan pengacara tersebut untuk mengikuti prosedur pengajuan beasiswa resmi di kementerian.", val: 0}] },
{ text: "Atasan Anda meminta Anda untuk mengubah tanggal pada sebuah dokumen kontrak (backdate) agar proyek yang terlambat pengerjaannya tetap bisa dibayar di tahun anggaran berjalan. Atasan menjamin bahwa hal ini sudah biasa dilakukan dan tidak akan ada masalah karena semua pihak sudah setuju demi kepentingan serapan anggaran. Sikap Anda adalah...", options: [{text: "Melakukan perubahan tanggal tersebut sesuai perintah pimpinan sebagai bentuk loyalitas organisasi.", val: 0}, {text: "Menolak melakukan perubahan tanggal karena hal tersebut merupakan bentuk pemalsuan data.", val: 5}, {text: "Menyarankan pimpinan untuk berkonsultasi dengan bagian hukum mengenai legalitas backdate.", val: 0}, {text: "Meminta staf lain untuk memproses dokumen tersebut agar Anda tidak terlibat secara langsung.", val: 0}, {text: "Menyetujui perintah tersebut selama ada surat perintah tertulis yang ditandatangani oleh atasan.", val: 0}] },
{ text: "Anda adalah anggota tim verifikasi tunjangan kinerja. Anda menemukan bahwa seorang rekan kerja, yang dikenal sebagai tulang punggung keluarga dan sedang mengalami kesulitan ekonomi, sering menitip absen (absensi palsu) agar potongan tunjangannya tidak besar. Rekan-rekan satu ruangan sepakat untuk mendiamkan hal ini sebagai bentuk solidaritas kemanusiaan. Sikap integritas Anda adalah...", options: [{text: "Mendiamkan hal tersebut selama kinerjanya di kantor tetap terlihat baik dan produktif.", val: 0}, {text: "Menegur rekan tersebut secara pribadi agar tidak mengulangi perbuatannya di masa depan.", val: 0}, {text: "Melaporkan temuan manipulasi absensi tersebut kepada atasan atau bagian kepegawaian.", val: 5}, {text: "Memberikan bantuan materi secara pribadi agar ia tidak perlu lagi melakukan absensi palsu.", val: 0}, {text: "Mengajak rekan-rekan satu ruangan untuk memberikan solusi tanpa harus melapor ke atasan.", val: 0}] },
{ text: "Instansi Anda sedang mengadakan rekrutmen pegawai non-ASN. Seorang sahabat lama yang pernah membantu biaya pendidikan Anda memohon agar Anda membantu meloloskan anaknya yang nilai tesnya berada sedikit di bawah ambang batas (passing grade). Sahabat Anda meyakinkan bahwa anaknya sangat kompeten namun hanya sedang kurang beruntung saat tes. Sikap Anda adalah...", options: [{text: "Menyarankan anak sahabat Anda untuk mengikuti rekrutmen di periode atau instansi lain.", val: 0}, {text: "Membantu memberikan bocoran pertanyaan wawancara agar nilai total anaknya meningkat.", val: 0}, {text: "Menolak membantu dan tetap menetapkan kelulusan berdasarkan peringkat nilai hasil tes.", val: 5}, {text: "Meminta izin kepada ketua panitia untuk memberikan sedikit kebijakan bagi anak sahabat.", val: 0}, {text: "Menjelaskan kepada sahabat Anda bahwa sistem rekrutmen saat ini sudah otomatis dan transparan.", val: 0}] },
{ text: "Anda adalah bendahara pengeluaran yang diperintahkan atasan untuk memindahkan sisa anggaran belanja modal ke rekening pribadi atasan dengan alasan untuk disimpan sementara guna menghindari proses pengembalian ke kas negara yang rumit di akhir tahun. Atasan berjanji dana tersebut akan tetap digunakan untuk keperluan kantor di tahun depan. Sikap Anda adalah...", options: [{text: "Mematuhi perintah tersebut karena atasan adalah penanggung jawab penuh anggaran.", val: 0}, {text: "Menolak perintah tersebut karena bertentangan dengan prosedur pengelolaan keuangan negara.", val: 5}, {text: "Menyarankan atasan untuk memindahkan dana tersebut ke rekening resmi koperasi kantor.", val: 0}, {text: "Melakukan pemindahan dana namun mencatatnya secara rahasia sebagai bukti perlindungan diri.", val: 0}, {text: "Mengonsultasikan perintah tersebut kepada bank persepsi untuk mencari jalan tengah yang legal.", val: 0}] },
{ text: "Anda bekerja di bagian kepegawaian dan menemukan bahwa atasan langsung Anda, yang selama ini membimbing karier Anda dengan sangat baik, memanipulasi data perjalanan dinas untuk kepentingan liburan pribadinya. Atasan Anda berjanji akan mempromosikan Anda pada periode berikutnya jika Anda membantu mengamankan dokumen tersebut. Sikap integritas Anda adalah...", options: [{text: "Mendiamkan hal tersebut sebagai bentuk balas budi atas bimbingan karier selama ini.", val: 0}, {text: "Menegur atasan secara pribadi agar segera menghentikan praktik manipulasi tersebut.", val: 0}, {text: "Menolak membantu dan melaporkan temuan tersebut melalui sistem pengaduan internal.", val: 5}, {text: "Meminta mutasi ke unit lain agar tidak terlibat dalam konflik kepentingan di unit tersebut.", val: 0}, {text: "Menyarankan atasan untuk mengembalikan dana yang telah digunakan secara diam-diam.", val: 0}] },
{ text: "Di tengah antrean pelayanan yang sangat panjang dan memicu kemarahan warga, seorang kolega menyarankan Anda untuk melewatkan tahap pengecekan keaslian dokumen fisik demi mempercepat layanan dan meredam kegaduhan. Kolega tersebut menjamin bahwa selama ini jarang ditemukan dokumen palsu. Sebagai petugas layanan, sikap Anda adalah...", options: [{text: "Mengikuti saran kolega demi kepuasan masyarakat dan kelancaran alur pelayanan.", val: 0}, {text: "Melakukan pengecekan acak (sampling) pada dokumen yang terlihat mencurigakan saja.", val: 0}, {text: "Tetap menjalankan prosedur verifikasi secara lengkap meskipun antrean semakin panjang.", val: 5}, {text: "Meminta warga menandatangani surat pernyataan tanggung jawab mutlak atas dokumennya.", val: 0}, {text: "Menyerahkan keputusan verifikasi kepada pimpinan unit agar beban risiko terbagi.", val: 0}] },
{ text: "Anda memiliki akses ke informasi tentang rencana pemekaran wilayah yang belum diumumkan kepada publik. Seorang kerabat dekat meminta informasi tersebut agar ia bisa membeli lahan di wilayah calon pusat pemerintahan baru dengan harga murah. Ia menjanjikan pembagian keuntungan yang besar bagi Anda di masa depan. Tindakan Anda adalah...", options: [{text: "Memberikan informasi secara lisan tanpa memberikan dokumen fisik agar tidak terlacak.", val: 0}, {text: "Menolak memberikan informasi tersebut karena merupakan rahasia negara yang dilindungi.", val: 5}, {text: "Menyarankan kerabat untuk melakukan analisis mandiri tanpa bantuan data rahasia Anda.", val: 0}, {text: "Menanyakan kepada atasan apakah informasi tersebut sudah bisa dibagikan secara terbatas.", val: 0}, {text: "Memberikan informasi tersebut dengan syarat keuntungan yang didapat digunakan untuk sosial.", val: 0}] },
{ text: "Anda sedang mengejar tenggat waktu laporan yang harus dikirim esok pagi, namun printer di meja Anda kehabisan tinta. Rekan kerja Anda menyarankan untuk menggunakan kertas dan tinta dari sisa proyek yang sudah selesai tahun lalu yang disimpan di gudang pribadi unit, karena jika meminta ke bagian perlengkapan sekarang akan memakan waktu lama. Sikap Anda adalah...", options: [{text: "Menggunakan sisa tinta tersebut demi selesainya laporan tepat waktu bagi kepentingan instansi.", val: 0}, {text: "Melaporkan ke bagian perlengkapan dan menunggu prosedur pengadaan tinta yang resmi.", val: 5}, {text: "Membeli tinta menggunakan uang pribadi agar laporan selesai tanpa menggunakan aset sisa proyek.", val: 0}, {text: "Meminjam tinta dari unit kerja lain yang masih memiliki persediaan resmi di meja mereka.", val: 0}, {text: "Menunda pengiriman laporan hingga tinta resmi tersedia agar tidak melanggar administrasi.", val: 0}] },
{ text: "Setelah membantu proses perizinan sebuah UMKM yang berjalan lancar tanpa biaya tambahan (zero pungli), pemilik UMKM tersebut merasa sangat terbantu dan mengirimkan paket berisi produk makanan usahanya ke kantor Anda sebagai sampel untuk dicicipi oleh seluruh rekan di ruangan Anda. Sikap Anda sebagai ASN yang melayani adalah...", options: [{text: "Menerima paket tersebut dan menikmatinya bersama rekan kantor sebagai bentuk apresiasi warga.", val: 0}, {text: "Menolak paket tersebut dan meminta pemilik UMKM membawanya pulang demi menjaga netralitas.", val: 5}, {text: "Menerima paket tersebut namun kemudian melaporkannya ke Unit Pengendalian Gratifikasi (UPG).", val: 0}, {text: "Mengarahkan pemilik UMKM untuk memberikan paket tersebut ke panti asuhan sebagai pengganti.", val: 0}, {text: "Mengambil sedikit sampel untuk dicicipi lalu mengembalikan sisanya kepada pemilik UMKM tersebut.", val: 0}] },
{ text: "Saat melakukan perjalanan dinas, Anda tanpa sengaja menghilangkan nota parkir bandara yang seharusnya dilampirkan dalam laporan pertanggungjawaban (LPJ). Rekan Anda menyarankan untuk menggunakan nota parkir milik orang lain yang ia temukan atau membuat nota tiruan yang nilainya sama agar proses pencairan uang harian Anda tidak terhambat. Tindakan Anda adalah...", options: [{text: "Menggunakan nota temuan rekan Anda karena nilai nominalnya tidak merugikan negara.", val: 0}, {text: "Membuat pernyataan tertulis mengenai kehilangan nota sesuai dengan fakta yang ada.", val: 5}, {text: "Membayar sendiri biaya parkir tersebut dan tidak memasukkannya ke dalam tagihan LPJ.", val: 0}, {text: "Meminta bantuan petugas parkir di hari lain untuk membuatkan nota dengan tanggal mundur.", val: 0}, {text: "Menunda pelaporan LPJ hingga nota yang hilang tersebut ditemukan kembali di rumah.", val: 0}] },
];

const twk_BelaNegara = [
{ text: "Andi, seorang ASN muda, diminta atasan langsungnya untuk memprioritaskan verifikasi berkas perusahaan milik kerabat sang atasan dalam proyek strategis nasional. Atasan berdalih perusahaan tersebut adalah aset lokal yang akan memperkuat ekonomi daerah. Andi menemukan adanya ketidaksesuaian kecil dalam dokumen teknis yang secara aturan dapat menggugurkan perusahaan tersebut. Tindakan yang paling mencerminkan esensi nilai Bela Negara dalam menghadapi dilema tersebut adalah...", options: [{text: "Meminta perusahaan tersebut segera memperbaiki dokumen agar proses administrasi negara tetap berjalan lancar dan akuntabel.", val: 0}, {text: "Melaporkan indikasi nepotisme atasan kepada unit pengawas internal demi menjaga marwah instansi dari praktik korupsi.", val: 0}, {text: "Menolak permintaan atasan dan memproses verifikasi sesuai standar yang berlaku demi menjaga integritas sistem pelayanan publik.", val: 5}, {text: "Membantu memberikan arahan teknis tambahan karena pemberdayaan pengusaha lokal merupakan wujud penguatan ketahanan ekonomi nasional.", val: 0}, {text: "Mendiskusikan solusi dengan rekan senior agar tetap dapat membantu atasan tanpa melanggar hukum yang berlaku secara fatal.", val: 0}] },
{ text: "Budi adalah seorang atase perdagangan yang sedang menegosiasikan perjanjian ekspor komoditas unggulan Indonesia di luar negeri. Pihak investor asing menawarkan klausul yang sangat menguntungkan secara finansial bagi perusahaan-perusahaan besar di Indonesia dalam jangka pendek, namun dalam jangka panjang, klausul tersebut berpotensi melemahkan kedaulatan cadangan sumber daya alam nasional. Di sisi lain, pemerintah pusat sedang membutuhkan suntikan dana cepat untuk stabilitas ekonomi domestik. Tindakan Budi yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Menerima klausul tersebut demi memastikan stabilitas ekonomi domestik tetap terjaga di masa krisis.", val: 0}, {text: " Meminta waktu tambahan untuk berkonsultasi dengan pakar hukum agar perjanjian tetap memiliki payung hukum yang kuat.", val: 0}, {text: " Menolak klausul tersebut dan mengajukan alternatif kontrak yang lebih adil meskipun keuntungan finansialnya lebih kecil.", val: 5}, {text: " Menyetujui perjanjian tersebut dengan catatan tambahan (addendum) agar kelak pemerintah bisa mengevaluasi ulang kontraknya.", val: 0}, {text: " Mengarahkan investor untuk bekerja sama dengan BUMN saja agar kontrol negara terhadap sumber daya tetap terjamin secara administratif.", val: 0}] },
{ text: "Sinta melihat sebuah unggahan di media sosial yang memuat data statistik yang terlihat valid namun digunakan untuk menyudutkan salah satu kelompok etnis dalam kebijakan ekonomi pemerintah. Unggahan tersebut viral dan memicu perdebatan panas yang mengarah pada sentimen disintegrasi. Sinta tahu bahwa data tersebut diambil secara parsial (tidak utuh) untuk menggiring opini negatif. Sebagai warga negara yang sadar akan nilai Bela Negara, respons Sinta yang paling tepat adalah...", options: [{text: " Melaporkan unggahan tersebut sebagai konten provokatif kepada pihak berwenang agar segera dilakukan pemblokiran akun.", val: 0}, {text: " Mengunggah data pembanding yang utuh dan memberikan penjelasan objektif di kolom komentar untuk meredam sentimen negatif.", val: 5}, {text: " Mengabaikan unggahan tersebut agar tidak memberikan panggung atau keterlibatan (engagement) yang membuat konten makin viral.", val: 0}, {text: " Mengajak teman-temannya untuk memberikan komentar positif di unggahan tersebut guna menyeimbangkan suasana diskusi.", val: 0}, {text: " Membuat konten baru yang bersifat edukatif mengenai pentingnya persatuan tanpa menyinggung secara langsung konten yang sedang viral tersebut.", val: 0}] },
{ text: "Seorang dokter yang bertugas di wilayah perbatasan yang terpencil dihadapkan pada situasi di mana pasokan obat-obatan dari pusat sangat terbatas. Suatu hari, terjadi wabah lokal yang membutuhkan penanganan cepat. Ada tawaran bantuan obat-obatan dan dana dari organisasi internasional non-pemerintah yang belum memiliki izin resmi dari kementerian terkait, namun obat tersebut sangat dibutuhkan saat itu juga untuk menyelamatkan nyawa warga di perbatasan. Tindakan dokter tersebut yang paling mewakili esensi Bela Negara adalah...", options: [{text: " Menerima bantuan tersebut demi kemanusiaan karena menyelamatkan nyawa warga negara adalah prioritas tertinggi dalam Bela Negara.", val: 0}, {text: " Menolak bantuan tersebut dan tetap menggunakan fasilitas negara yang ada sambil menunggu pengiriman resmi dari pusat.", val: 0}, {text: " Berkoordinasi secara darurat dengan otoritas keamanan setempat untuk melegitimasi penggunaan bantuan tersebut demi keselamatan publik.", val: 5}, {text: " Menerima bantuan tersebut secara diam-diam agar tidak menimbulkan kerumitan birokrasi yang dapat menghambat penanganan medis.", val: 0}, {text: " Menyarankan organisasi tersebut untuk menyerahkan bantuannya melalui jalur formal di tingkat provinsi agar tidak melanggar aturan.", val: 0}] },
{ text: "Seorang kepala daerah di wilayah pesisir mendapatkan tawaran investasi besar dari perusahaan asing untuk membangun resor mewah di area yang merupakan zona lindung bakau (mangrove). Perusahaan menjanjikan penyerapan ribuan tenaga kerja lokal dan peningkatan pendapatan daerah secara signifikan yang sangat dibutuhkan pascapandemi. Namun, riset lingkungan menunjukkan bahwa hilangnya bakau tersebut akan memperlemah benteng alami wilayah dari abrasi dan ancaman tsunami di masa depan. Tindakan kepala daerah yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Menerima investasi tersebut dengan syarat perusahaan wajib mengalokasikan dana CSR untuk pembangunan infrastruktur penahan tsunami buatan.", val: 0}, {text: " Menolak investasi tersebut dan mengarahkan pengembangan ekonomi daerah pada sektor ekowisata yang menjaga kelestarian hutan bakau.", val: 5}, {text: " Menyetujui pembangunan resor di titik yang paling minim dampak lingkungannya demi menjaga keseimbangan antara ekonomi dan ekologi.", val: 0}, {text: " Mengonsultasikan tawaran tersebut kepada pemerintah pusat agar keputusan yang diambil memiliki legitimasi hukum dan politik yang kuat.", val: 0}, {text: " Meminta perusahaan untuk memindahkan lokasi pembangunan ke wilayah lain yang tidak termasuk zona lindung meskipun nilai investasinya mengecil.", val: 0}] },
{ text: "Seorang peneliti di sebuah lembaga negara menemukan bahwa data efikasi sebuah inovasi teknologi yang akan diluncurkan pemerintah untuk publik ternyata belum mencapai standar keamanan yang memadai. Namun, pimpinan lembaga meminta peneliti tersebut tetap merilis hasil yang positif dengan alasan demi menjaga kepercayaan publik terhadap pemerintah dan menghindari kegaduhan politik di tengah situasi nasional yang sedang sensitif. Dalam konteks Bela Negara, respons terbaik peneliti tersebut adalah...", options: [{text: " Menuruti instruksi pimpinan demi menjaga stabilitas nasional dan integritas lembaga pemerintah di mata masyarakat.", val: 0}, {text: " Menyampaikan keberatan secara internal dan meminta waktu tambahan untuk menyempurnakan penelitian sebelum data dirilis.", val: 0}, {text: " Merilis data apa adanya secara transparan kepada publik sebagai bentuk tanggung jawab moral dan kejujuran seorang ilmuwan negara.", val: 0}, {text: " Menyusun laporan yang menonjolkan sisi positif inovasi tersebut namun tetap mencantumkan catatan kecil mengenai kekurangan teknisnya.", val: 0}, {text: " Menolak merilis data yang tidak akurat dan bersedia menanggung konsekuensi jabatan demi melindungi keselamatan masyarakat luas.", val: 5}] },
{ text: "Dalam sebuah forum kebudayaan internasional, seorang tokoh pemuda Indonesia melihat adanya upaya dari negara lain untuk mengklaim sebuah tradisi asli nusantara sebagai warisan budaya mereka melalui narasi sejarah yang telah dimodifikasi. Tokoh pemuda tersebut memiliki kesempatan untuk melakukan interupsi dan memprotes klaim tersebut, namun ia khawatir tindakan tersebut akan merusak suasana diplomatis yang sedang dibangun oleh kementerian luar negeri dalam kerja sama ekonomi dengan negara tersebut. Tindakan yang paling tepat dilakukan adalah...", options: [{text: " Menahan diri untuk tidak memprotes di forum resmi demi menjaga kelancaran negosiasi ekonomi yang sedang diperjuangkan pemerintah.", val: 0}, {text: " Melakukan interupsi dengan cara yang elegan untuk memaparkan bukti sejarah asli tradisi tersebut sebagai upaya menjaga identitas bangsa.", val: 5}, {text: " Mencatat klaim tersebut dan melaporkannya kepada kementerian terkait setelah acara selesai agar diselesaikan melalui jalur diplomasi formal.", val: 0}, {text: " Mengajak perwakilan negara tersebut berdiskusi secara personal di luar forum untuk mencari kesepahaman mengenai klaim budaya tersebut.", val: 0}, {text: " Membuat kampanye tandingan di media sosial dengan konten budaya asli Indonesia agar publik internasional tahu kebenaran yang sesungguhnya.", val: 0}] },
{ text: "Seorang penyuluh pertanian di sebuah daerah lumbung padi nasional menyadari bahwa banyak petani di wilayahnya mulai menjual lahan sawah mereka kepada pengembang industri karena tergiur harga tanah yang melonjak tinggi. Para petani berencana beralih profesi menjadi pekerja pabrik demi kesejahteraan instan. Di sisi lain, pemerintah daerah mendukung industrialisasi tersebut karena dianggap akan meningkatkan Pendapatan Asli Daerah (PAD) secara signifikan. Tindakan penyuluh tersebut yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Menghormati keputusan para petani karena kesejahteraan ekonomi keluarga adalah hak asasi yang harus didukung oleh negara.", val: 0}, {text: " Melaporkan fenomena alih fungsi lahan tersebut kepada kementerian terkait agar segera diterbitkan aturan larangan penjualan lahan.", val: 0}, {text: " Mengedukasi petani mengenai pentingnya menjaga lahan sawah sebagai pilar kedaulatan pangan bangsa demi keselamatan generasi mendatang.", val: 0}, {text: " Membantu petani melakukan negosiasi harga lahan dengan pengembang agar mereka mendapatkan modal yang cukup untuk usaha baru.", val: 0}, {text: " Mengusulkan kepada pemerintah daerah untuk membangun kawasan industri di lahan non-produktif agar fungsi lahan pangan tetap terjaga.", val: 5}] },
{ text: "Di sebuah desa yang menjunjung tinggi nilai gotong royong, seorang warga yang dikenal sangat dermawan dan sering membantu pembangunan masjid serta sekolah tertangkap tangan melakukan praktik perjudian daring berskala besar. Masyarakat desa merasa berhutang budi dan berencana melakukan aksi damai untuk meminta keringanan hukuman atau penghentian kasus kepada kepolisian setempat demi menghargai jasa-jasa sosial pelaku. Sebagai tokoh pemuda desa yang memahami nilai Bela Negara, respons Anda adalah...", options: [{text: " Mendukung aksi damai masyarakat sebagai bentuk apresiasi atas kontribusi sosial yang telah dilakukan pelaku bagi desa.", val: 0}, {text: " Meminta masyarakat untuk tetap tenang dan menyerahkan sepenuhnya proses hukum kepada pihak berwenang sebagai bentuk penghormatan terhadap supremasi hukum.", val: 0}, {text: " Menggalang dana bantuan hukum bagi pelaku sebagai wujud solidaritas sesama warga negara yang sedang mengalami masalah hukum.", val: 0}, {text: " Memberikan edukasi kepada masyarakat bahwa membela hukum negara adalah bentuk nyata Bela Negara yang lebih tinggi dibanding solidaritas kelompok.", val: 5}, {text: " Menyarankan agar dilakukan musyawarah antara tokoh masyarakat dan kepolisian untuk mencari jalan tengah yang bersifat kekeluargaan.", val: 0}] },
{ text: "Seorang ilmuwan muda Indonesia berhasil menciptakan alat pemurni air sederhana namun sangat efektif untuk daerah bencana yang harganya jauh lebih murah dibanding produk impor. Namun, alat tersebut belum memiliki sertifikasi internasional yang sering menjadi syarat utama pengadaan barang di instansi pemerintah. Saat terjadi bencana besar, pemerintah cenderung ingin mengimpor alat serupa agar aman secara administrasi. Tindakan ilmuwan tersebut yang mencerminkan esensi Bela Negara adalah...", options: [{text: " Menggratiskan alat buatannya untuk digunakan oleh relawan di lapangan tanpa melalui jalur birokrasi pemerintah agar cepat menolong korban.", val: 0}, {text: " Mendesak pemerintah melalui media sosial agar memprioritaskan produk lokal demi menunjukkan semangat kemandirian bangsa.", val: 0}, {text: " Meminta bantuan lembaga riset negara untuk mempercepat uji standarisasi nasional agar alat tersebut legal digunakan dalam pengadaan darurat.", val: 5}, {text: " Terus menyempurnakan alat tersebut secara mandiri hingga nantinya diakui secara internasional agar tidak dipandang sebelah mata oleh negara sendiri.", val: 0}, {text: " Menjual lisensi alat tersebut kepada perusahaan asing yang sudah memiliki sertifikat internasional agar alatnya bisa segera digunakan di Indonesia.", val: 0}] },
{ text: "Pemerintah sedang merencanakan kerja sama pembangunan infrastruktur energi terbarukan dengan konsorsium perusahaan multinasional. Kerja sama ini akan memberikan transfer teknologi besar-besaran bagi tenaga ahli Indonesia dalam 5 tahun ke depan. Namun, muncul gelombang protes dari sekelompok organisasi yang menuntut agar seluruh proyek dikerjakan 100% oleh perusahaan dalam negeri saat ini juga, meskipun perusahaan lokal tersebut belum memiliki teknologi inti yang dibutuhkan. Sebagai seorang analis kebijakan yang memahami Bela Negara, respons Anda adalah...", options: [{text: " Mendukung tuntutan organisasi tersebut sebagai bentuk keberanian bangsa untuk mandiri dan tidak bergantung pada teknologi asing.", val: 0}, {text: " Menyarankan pemerintah untuk membatalkan kerja sama asing demi menjaga kehormatan dan harga diri bangsa di mata internasional.", val: 0}, {text: " Melanjutkan kerja sama tersebut sambil memperketat klausul transfer teknologi agar tenaga kerja lokal mampu mandiri di masa depan.", val: 5}, {text: " Meminta perusahaan asing tersebut memberikan dana hibah yang besar sebagai kompensasi atas penggunaan ruang wilayah Indonesia.", val: 0}, {text: " Melakukan kampanye nasional tentang pentingnya mencintai produk dan jasa dalam negeri untuk meredam gejolak sosial yang terjadi.", val: 0}] },
{ text: "Seorang anggota TNI/Polri menemukan adanya indikasi penyimpangan prosedur keamanan dalam distribusi bantuan logistik di wilayah konflik yang dilakukan oleh rekan satu angkatannya sendiri demi efisiensi waktu. Rekan tersebut dikenal sangat berdedikasi dan telah berkali-kali bertaruh nyawa demi kedaulatan negara di wilayah tersebut. Melaporkan hal ini berisiko merusak moral satuan dan solidaritas yang sangat dibutuhkan di medan tugas. Tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Memaklumi penyimpangan tersebut selama tujuannya adalah demi kelancaran tugas negara dan keselamatan warga di wilayah konflik.", val: 0}, {text: " Menegur rekan tersebut secara pribadi dan memintanya untuk lebih berhati-hati agar tidak diketahui oleh atasan atau pihak luar.", val: 0}, {text: " Melaporkan temuan tersebut sesuai prosedur internal agar integritas institusi pertahanan negara tetap terjaga dan profesional.", val: 5}, {text: " Mengabaikan temuan tersebut demi menjaga kekompakan dan moral satuan yang sedang menghadapi ancaman nyata dari luar.", val: 0}, {text: " Mengajak rekan-rekan lain untuk menutupi kesalahan tersebut sebagai bentuk kesetiakawanan dalam suka dan duka di medan tugas.", val: 0}] },
{ text: "Sebuah festival seni internasional di luar negeri secara tidak sengaja salah mencantumkan asal muasal alat musik tradisional Indonesia sebagai milik negara tetangga dalam katalog resmi mereka. Hal ini memicu kemarahan netizen Indonesia yang mulai menyerang akun media sosial festival tersebut dengan komentar kasar. Sebagai delegasi kebudayaan Indonesia yang hadir di sana, tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Turut menyuarakan protes keras di media sosial agar penyelenggara tahu bahwa bangsa Indonesia sangat mencintai dan menjaga budayanya.", val: 0}, {text: " Melakukan aksi protes diam di depan lokasi festival untuk menarik perhatian media internasional terhadap kesalahan klaim tersebut.", val: 0}, {text: " Menghubungi penyelenggara secara resmi dengan menyertakan dokumen sejarah yang valid untuk mengoreksi katalog dan meminta klarifikasi publik.", val: 5}, {text: " Meminta pemerintah Indonesia segera memutus kerja sama kebudayaan dengan negara penyelenggara sebagai bentuk ketegasan bangsa.", val: 0}, {text: " Menampilkan pertunjukan alat musik tersebut secara besar-besaran di festival untuk membuktikan secara visual bahwa itu adalah milik Indonesia.", val: 0}] },
{ text: "Sebuah platform media sosial global menolak permintaan pemerintah Indonesia untuk menghapus konten yang secara halus mempromosikan paham yang bertentangan dengan Pancasila, dengan alasan kebebasan berpendapat. Konten tersebut mulai memengaruhi opini generasi muda di daerah perbatasan. Sebagai seorang ASN di bidang komunikasi dan informasi, tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Mengusulkan pemblokiran total platform tersebut di Indonesia sebagai bentuk ketegasan negara dalam melindungi ideologi bangsa.", val: 0}, {text: " Menggerakkan komunitas konten kreator lokal untuk memproduksi narasi tandingan yang kreatif dan edukatif tentang nilai-nilai Pancasila.", val: 5}, {text: " Melakukan aksi protes digital bersama netizen untuk menekan platform tersebut agar tunduk pada aturan hukum Indonesia.", val: 0}, {text: " Membiarkan konten tersebut selama tidak memicu kekerasan fisik, demi menjaga citra Indonesia sebagai negara demokrasi di mata dunia.", val: 0}, {text: " Meminta bantuan peretas (hacker) nasional untuk melumpuhkan akun-akun yang menyebarkan paham tersebut secara mandiri.", val: 0}] },
{ text: "Indonesia sedang mengembangkan pesawat tempur hasil kerja sama dengan negara maju. Di tengah jalan, negara mitra membatasi akses Indonesia terhadap teknologi kunci radar karena alasan keamanan nasional mereka. Beberapa tokoh menyarankan agar Indonesia membatalkan proyek tersebut dan beralih membeli pesawat tempur dari negara lain yang lebih kooperatif, meskipun secara teknologi lebih rendah. Respons yang paling tepat dalam perspektif Bela Negara adalah...", options: [{text: " Membatalkan kerja sama dan segera membeli pesawat dari negara lain demi memastikan kesiapan tempur TNI tidak terganggu.", val: 0}, {text: " Melanjutkan proyek tersebut sambil menugaskan peneliti dalam negeri untuk melakukan rekayasa balik (reverse engineering) pada teknologi yang dibatasi.", val: 0}, {text: " Melakukan diplomasi tingkat tinggi untuk mendesak negara mitra membuka akses teknologi sebagai syarat kelanjutan kontrak ekonomi lainnya.", val: 5}, {text: " Menghentikan sementara proyek dan fokus pada penguatan industri pertahanan dalam negeri agar mampu menciptakan radar mandiri di masa depan.", val: 0}, {text: " Menyetujui pembatasan tersebut asalkan harga pesawat dikurangi secara signifikan agar anggaran negara bisa dialokasikan untuk kebutuhan lain.", val: 0}] },
{ text: "Sebuah wilayah hutan adat di Kalimantan ditemukan memiliki cadangan mineral langka yang sangat penting untuk industri baterai kendaraan listrik dunia. Pemerintah ingin membuka tambang di sana untuk menjadikan Indonesia pusat industri hijau global. Namun, masyarakat adat menolak karena hutan tersebut adalah identitas budaya dan sumber kehidupan mereka secara turun-temurun. Sebagai pejabat yang berwenang, tindakan yang paling mencerminkan Bela Negara adalah...", options: [{text: " Meyakinkan masyarakat adat bahwa pengorbanan lahan mereka adalah wujud nyata cinta tanah air demi kemajuan ekonomi nasional.", val: 0}, {text: " Memaksakan pembukaan tambang demi kepentingan nasional yang lebih besar dengan memberikan kompensasi finansial yang sangat tinggi.", val: 0}, {text: " Membatalkan rencana tambang dan menetapkan wilayah tersebut sebagai taman nasional yang tidak boleh diganggu gugat oleh industri mana pun.", val: 0}, {text: " Mencari titik temu dengan melibatkan masyarakat adat dalam pengelolaan industri tersebut tanpa merusak area sakral dan ekosistem utama.", val: 5}, {text: " Melakukan studi banding ke negara lain untuk melihat cara mengelola tambang di wilayah adat tanpa menimbulkan gejolak sosial.", val: 0}] },
{ text: "Seorang atase pertahanan di luar negeri menemukan bahwa teknologi satelit yang akan dibeli pemerintah Indonesia memiliki celah keamanan (backdoor) yang bisa diakses oleh negara produsen. Namun, pembatalan kontrak akan merusak hubungan diplomatik dan kerja sama militer yang sedang sangat dibutuhkan untuk stabilitas kawasan. Tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Melanjutkan pembelian demi menjaga stabilitas diplomasi kawasan.", val: 0}, {text: " Menegosiasikan ulang kontrak dengan syarat audit teknologi total.", val: 5}, {text: " Membatalkan kontrak secara sepihak untuk melindungi rahasia negara.", val: 0}, {text: " Tetap membeli namun memperkuat sistem pertahanan siber internal.", val: 0}, {text: " Melaporkan temuan tersebut kepada Dewan Keamanan Nasional.", val: 0}] },
{ text: "Sebuah perusahaan besar milik pengusaha nasional yang banyak menyumbang bagi kegiatan kemanusiaan di Indonesia terbukti melakukan manipulasi pajak dalam jumlah masif. Banyak pihak menyarankan agar kasus ini diselesaikan secara kekeluargaan (non-yustisial) mengingat besarnya jasa perusahaan tersebut bagi ekonomi rakyat. Dalam perspektif Bela Negara, respons terbaik adalah...", options: [{text: " Mengutamakan penyelesaian administratif demi menjaga iklim ekonomi.", val: 0}, {text: " Memberikan sanksi ringan sebagai apresiasi atas jasa sosialnya.", val: 0}, {text: " Menindak tegas sesuai hukum untuk menegakkan keadilan sistem.", val: 5}, {text: " Melakukan mediasi agar kerugian negara diganti tanpa proses hukum.", val: 0}, {text: " Menyerahkan keputusan sepenuhnya kepada kebijakan pimpinan tertinggi.", val: 0}] },
{ text: "Di era globalisasi, banyak generasi muda Indonesia lebih bangga menggunakan bahasa asing dan mengadopsi gaya hidup luar negeri karena dianggap lebih modern. Hal ini mulai mengikis penggunaan bahasa daerah dan bahasa Indonesia di ruang publik. Sebagai warga negara yang sadar akan nilai Bela Negara, tindakan yang paling mendasar adalah...", options: [{text: " Mendukung pembatasan konten budaya asing di media massa nasional.", val: 0}, {text: " Mewajibkan penggunaan pakaian adat di instansi pendidikan dan kantor.", val: 0}, {text: " Menjadikan budaya lokal sebagai basis inovasi di kancah internasional.", val: 5}, {text: " Memperkuat literasi nilai kebangsaan melalui jalur keluarga dan sekolah.", val: 0}, {text: " Menolak segala bentuk budaya asing yang tidak sesuai dengan Pancasila.", val: 0}] },
{ text: "Sebuah daerah memiliki potensi sumber daya alam yang melimpah, namun pengelolaannya selama ini belum optimal bagi kesejahteraan warga lokal. Pemerintah pusat merencanakan pengambilalihan pengelolaan melalui Badan Usaha Milik Negara (BUMN) untuk menjamin pasokan energi nasional. Masyarakat lokal melalui tokoh adat menolak dan menuntut pengelolaan mandiri sepenuhnya agar hasil kekayaan tersebut tetap berada di daerah. Sebagai pejabat mediator, tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Mendukung penuh tuntutan masyarakat lokal demi keadilan ekonomi daerah.", val: 0}, {text: " Memastikan BUMN masuk dengan memberikan porsi saham bagi masyarakat adat.", val: 0}, {text: " Menjalankan mandat pusat untuk pengamanan energi nasional secara mutlak.", val: 0}, {text: " Memfasilitasi kerja sama yang menyeimbangkan kedaulatan energi dan hak lokal.", val: 5}, {text: " Menyerahkan keputusan pada mekanisme hukum di pengadilan tata usaha negara.", val: 0}] },
{ text: "Dodi adalah seorang pakar teknologi informasi yang bekerja di sebuah perusahaan rintisan (startup) asing yang sukses. Ia menemukan bahwa sistem yang sedang dikembangkannya memiliki potensi untuk digunakan memetakan data perilaku pemilih di Indonesia secara ilegal untuk kepentingan politik pihak luar. Jika ia mengundurkan diri, ia kehilangan karier cemerlangnya; jika ia melapor, ia dianggap melanggar kontrak kerahasiaan perusahaan. Tindakan Dodi yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Tetap bekerja namun secara diam-diam menanamkan sistem pengaman data.", val: 0}, {text: " Mengundurkan diri secara baik-baik tanpa membocorkan rahasia perusahaan.", val: 0}, {text: " Melaporkan temuan tersebut kepada otoritas keamanan siber negara Indonesia.", val: 5}, {text: " Berkonsultasi dengan pengacara untuk mencari celah hukum dalam kontraknya.", val: 0}, {text: " Meminta perusahaan untuk mengubah arah pengembangan sistem agar lebih etis.", val: 0}] },
{ text: "Seorang atlet muda Indonesia yang sedang berprestasi di tingkat dunia mendapatkan tawaran untuk berpindah kewarganegaraan dari negara maju. Negara tersebut menjamin fasilitas latihan terbaik, kesejahteraan seumur hidup, dan peluang medali emas olimpiade yang sulit didapatkan jika tetap di Indonesia karena keterbatasan fasilitas nasional. Tindakan atlet tersebut yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Menerima tawaran tersebut agar tetap bisa mengharumkan nama asal Indonesia di podium.", val: 0}, {text: " Menolak tawaran dan tetap bertahan di Indonesia meski dengan fasilitas terbatas.", val: 0}, {text: " Menerima tawaran dengan syarat tetap diperbolehkan membangun yayasan olahraga di Indonesia.", val: 0}, {text: " Bertahan di Indonesia dan menggunakan pengaruhnya untuk menarik investor olahraga nasional.", val: 5}, {text: " Meminta pemerintah Indonesia memberikan fasilitas yang sama agar ia tidak berpindah negara.", val: 0}] },
{ text: "Sebuah perusahaan asing menawarkan investasi besar-besaran untuk membangun dermaga logistik di pulau terluar Indonesia yang selama ini terisolasi. Pihak asing meminta hak pengelolaan eksklusif selama 50 tahun termasuk kontrol atas lalu lintas kapal yang keluar masuk demi keamanan aset mereka. Pemerintah daerah sangat mendukung karena ini akan mengentaskan kemiskinan lokal secara instan. Sebagai pengambil kebijakan, tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Menerima investasi demi percepatan kesejahteraan masyarakat di pulau terluar.", val: 0}, {text: " Menyetujui pembangunan dengan syarat tenaga kerja lokal diprioritaskan 100%.", val: 0}, {text: " Menolak klausul hak eksklusif demi menjaga kedaulatan penuh atas wilayah.", val: 5}, {text: " Mengalihkan lokasi pembangunan ke wilayah pedalaman agar lebih aman secara politik.", val: 0}, {text: " Meminta jaminan tertulis bahwa aset tersebut akan menjadi milik negara di akhir kontrak.", val: 0}] },
{ text: "Seorang manajer di sebuah BUMN menemukan bahwa sistem manajemen risiko perusahaannya sengaja dimanipulasi agar laporan keuangan terlihat surplus demi mendapatkan bonus tahunan bagi seluruh karyawan. Jika ia membongkar hal ini, reputasi perusahaan akan jatuh dan ribuan rekan kerjanya akan kehilangan bonus yang sangat diharapkan untuk kebutuhan keluarga mereka. Tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Mendiamkan hal tersebut demi menjaga moral dan kesejahteraan rekan kerja.", val: 0}, {text: " Melakukan perbaikan sistem secara perlahan tanpa harus menciptakan kegaduhan.", val: 0}, {text: " Melaporkan manipulasi tersebut demi transparansi dan kesehatan aset negara.", val: 5}, {text: " Mengundurkan diri sebagai bentuk protes moral atas ketidakjujuran manajemen.", val: 0}, {text: " Menyarankan manajemen untuk mengalokasikan bonus tersebut bagi kegiatan sosial.", val: 0}] },
{ text: "Seorang peneliti tanaman herbal di pedalaman menemukan spesies tanaman yang terbukti efektif menyembuhkan penyakit kronis. Sebuah perusahaan farmasi luar negeri menawarkan kontrak riset dengan pendanaan melimpah, namun mereka mensyaratkan bahwa seluruh paten hasil riset akan menjadi hak milik perusahaan tersebut tanpa mencantumkan asal-usul geografis tanaman tersebut. Tindakan peneliti yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Menerima kontrak agar obat tersebut cepat diproduksi untuk menolong umat manusia.", val: 0}, {text: " Menolak kontrak dan memilih melakukan riset mandiri meski dengan fasilitas terbatas.", val: 0}, {text: " Menegosiasikan hak paten bersama (joint patent) sebagai pengakuan kedaulatan aset bangsa.", val: 0}, {text: " Menyerahkan temuan tersebut kepada pemerintah agar dipatenkan sebagai milik negara.", val: 5}, {text: " Mempublikasikan temuan secara terbuka di internet agar tidak bisa diklaim secara sepihak.", val: 0}] },
{ text: "Seorang ahli siber di lembaga pertahanan menemukan bahwa sebuah organisasi kemanusiaan internasional yang sedang memberikan bantuan bencana di wilayah konflik Indonesia, secara teknis mengirimkan data pemetaan geografis mendetail ke server luar negeri yang bisa diakses oleh pihak intelijen asing. Organisasi tersebut berdalih data itu diperlukan untuk koordinasi logistik bantuan agar tepat sasaran bagi rakyat yang menderita. Tindakan ahli siber tersebut yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Membiarkan pengiriman data tersebut demi kelancaran bantuan kemanusiaan bagi rakyat di wilayah konflik.", val: 0}, {text: " Menegur organisasi tersebut secara lisan agar lebih berhati-hati dalam mengelola data sensitif negara.", val: 0}, {text: " Memutus akses pengiriman data secara sepihak untuk melindungi rahasia geospasial pertahanan nasional.", val: 0}, {text: " Melaporkan temuan tersebut kepada otoritas keamanan negara agar diambil tindakan hukum dan kedaulatan.", val: 5}, {text: " Meminta salinan data tersebut agar pemerintah Indonesia juga memiliki data yang sama untuk kepentingan pusat.", val: 0}] },
{ text: "Indonesia sedang mengajukan diri menjadi anggota organisasi ekonomi bergengsi dunia. Salah satu syaratnya adalah keterbukaan data perbankan yang sangat transparan. Namun, tim analis menemukan bahwa keterbukaan penuh tersebut akan mengungkap kelemahan sistemik pada beberapa bank milik negara yang jika diketahui pasar global dapat memicu pelarian modal besar-besaran (capital flight) dan melemahkan rupiah. Tindakan ketua tim analis yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Menunda pengiriman data hingga sistem perbankan nasional benar-benar kuat secara internal.", val: 0}, {text: " Melakukan modifikasi data agar kondisi ekonomi terlihat tetap stabil di mata organisasi dunia.", val: 0}, {text: " Melaporkan kondisi sebenarnya kepada pemerintah agar diambil langkah penyelamatan ekonomi nasional.", val: 5}, {text: " Tetap mengirimkan data secara transparan sebagai bukti komitmen Indonesia terhadap standar global.", val: 0}, {text: " Menyarankan pengunduran diri dari pencalonan anggota demi melindungi stabilitas moneter dalam negeri.", val: 0}] },
{ text: "Sebuah yayasan pendidikan luar negeri menawarkan bantuan dana dan kurikulum modern secara gratis untuk sekolah-sekolah di pelosok Indonesia. Kurikulum tersebut sangat maju dalam bidang sains dan teknologi, namun secara implisit menyelipkan nilai-nilai individualisme ekstrem yang perlahan mengikis semangat gotong royong dan nilai luhur Pancasila pada siswa. Sebagai pejabat pendidikan daerah, tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Menerima bantuan tersebut sepenuhnya demi mengejar ketertinggalan teknologi siswa di pelosok.", val: 0}, {text: " Menolak bantuan tersebut untuk mencegah masuknya pengaruh budaya asing yang merusak jati diri.", val: 0}, {text: " Menerima bantuan tersebut dengan syarat kurikulum sainsnya saja yang diterapkan tanpa nilai sosialnya.", val: 0}, {text: " Mengadopsi metode sainsnya namun mewajibkan integrasi nilai Pancasila dalam setiap mata pelajaran.", val: 5}, {text: " Meminta pemerintah pusat membuat kurikulum tandingan yang setara agar tidak perlu bantuan asing.", val: 0}] },
{ text: "Indonesia sedang mengembangkan teknologi reaktor nuklir untuk kemandirian energi nasional dengan bantuan riset dari negara maju. Di tengah proyek, negara mitra meminta akses penuh untuk memantau seluruh aktivitas data riset tersebut dengan alasan pengawasan keamanan global dan pencegahan penyalahgunaan senjata. Jika menolak, bantuan pendanaan dan transfer teknologi akan dihentikan, yang berarti proyek kemandirian energi ini terancam mangkrak. Tindakan tim ahli Indonesia yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Menerima pengawasan tersebut demi memastikan proyek kemandirian energi nasional tetap berjalan hingga tuntas.", val: 0}, {text: " Menolak akses penuh tersebut dan memilih melanjutkan riset secara mandiri meski harus memakan waktu jauh lebih lama.", val: 0}, {text: " Menawarkan kompromi berupa laporan berkala yang transparan tanpa memberikan akses langsung ke sistem data inti riset.", val: 5}, {text: " Mengajak negara mitra melakukan audit bersama di bawah pengawasan lembaga internasional yang bersifat netral.", val: 0}, {text: " Menghentikan kerja sama tersebut dan mencari mitra negara lain yang tidak memberikan syarat yang mengikat kedaulatan data.", val: 0}] },
{ text: "Seorang pejabat kementerian keuangan menemukan bahwa sebuah konsorsium besar yang memegang proyek strategis nasional melakukan praktik penghindaran pajak yang sangat rumit namun secara teknis legal di bawah celah aturan lama. Jika celah ini ditutup secara mendadak, konsorsium tersebut mengancam akan menarik seluruh investasinya yang dapat memicu krisis kepercayaan investor dan PHK massal di sektor terkait. Tindakan pejabat tersebut yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Membiarkan praktik tersebut untuk sementara waktu demi menjaga stabilitas ekonomi dan mencegah terjadinya PHK massal.", val: 0}, {text: " Melakukan negosiasi agar konsorsium tersebut memberikan kompensasi berupa investasi sosial bagi masyarakat sekitar proyek.", val: 0}, {text: " Melaporkan celah aturan tersebut kepada pimpinan untuk segera dilakukan revisi regulasi demi keadilan pajak nasional.", val: 5}, {text: " Memberikan peringatan rahasia kepada perusahaan agar memperbaiki praktik pajaknya sebelum aturan baru resmi diberlakukan.", val: 0}, {text: " Meminta pendapat ahli hukum internasional untuk mencari jalan tengah yang tidak merugikan iklim investasi maupun negara.", val: 0}] },
{ text: "Dalam menghadapi ancaman terorisme lintas negara, lembaga intelijen negara meminta akses ke data enkripsi percakapan warga di sebuah platform komunikasi digital populer untuk mendeteksi sel tidur (sleeper cells). Hal ini memicu perdebatan mengenai pelanggaran privasi warga negara. Namun, jika akses ditolak, potensi serangan yang mengancam nyawa ribuan rakyat menjadi sangat tinggi. Sebagai penasihat kebijakan, tindakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Mendukung pemberian akses penuh kepada intelijen karena keselamatan rakyat adalah hukum tertinggi bagi negara.", val: 0}, {text: " Menolak pemberian akses tersebut demi melindungi hak asasi dan privasi warga negara sebagai pilar demokrasi.", val: 0}, {text: " Mengizinkan akses terbatas yang hanya bisa dibuka dengan perintah pengadilan dan pengawasan lembaga independen.", val: 5}, {text: " Menyarankan pengembangan teknologi pemantauan mandiri oleh negara tanpa harus bergantung pada data platform digital.", val: 0}, {text: " Melakukan sosialisasi kepada warga agar secara sukarela melaporkan aktivitas mencurigakan di lingkungan masing-masing.", val: 0}] },
{ text: "Indonesia sedang memimpin inisiatif pembentukan pakta perdagangan regional untuk memperkuat posisi tawar komoditas lokal di pasar global. Salah satu negara mitra kunci, yang memiliki pengaruh besar dalam stabilitas keamanan kawasan, mensyaratkan agar Indonesia melonggarkan aturan standarisasi industri dalam negeri bagi produk mereka sebagai bentuk timbal balik atas dukungan keamanan. Jika menolak, pakta ini terancam gagal dan posisi ekonomi Indonesia di masa depan akan sulit bersaing dengan blok dagang lain. Keputusan yang paling menunjukkan keteguhan pada prinsip Bela Negara dalam situasi diplomasi ekonomi tersebut adalah...", options: [{text: " Menyetujui pelonggaran tersebut secara terbatas hanya pada sektor non-vital demi menjaga keberlangsungan aliansi keamanan kawasan.", val: 0}, {text: " Menawarkan kerja sama investasi di bidang manufaktur sebagai pengganti pelonggaran standar agar kedaulatan industri tetap terjaga.", val: 0}, {text: " Menolak persyaratan tersebut dan tetap pada standar nasional guna melindungi daya saing dan martabat industri dalam negeri.", val: 5}, {text: " Meminta waktu untuk melakukan kajian dampak sosial-ekonomi guna mencari celah kompromi yang tidak merugikan kedua belah pihak.", val: 0}, {text: " Menggalang dukungan dari negara mitra lain yang lebih kecil untuk menekan negara kunci tersebut agar membatalkan persyaratannya.", val: 0}] },
{ text: "Andi adalah seorang auditor negara yang menemukan kebocoran data strategis terkait cadangan mineral langka di sebuah BUMN tambang. Data tersebut bocor akibat kelalaian sistem keamanan yang dikelola oleh perusahaan rintisan milik rekan seperjuangannya yang selama ini banyak membantu riset-riset strategis pemerintah. Jika Andi melaporkan temuan ini secara terbuka, perusahaan rekannya akan hancur dan riset penting lainnya akan terhenti. Namun, jika dibiarkan, data tersebut dapat disalahgunakan oleh spekulan asing. Langkah manakah yang paling merepresentasikan tanggung jawab Andi sebagai warga negara yang sadar akan nilai Bela Negara?", options: [{text: "Memberikan teguran keras dan waktu singkat bagi perusahaan rekannya untuk memperbaiki sistem sebelum melakukan audit ulang.", val: 0}, {text: " Melaporkan kebocoran tersebut kepada otoritas berwenang agar langkah mitigasi penyelamatan data negara dapat segera dilakukan.", val: 5}, {text: " Membantu rekan tersebut memperbaiki sistem keamanan secara mandiri agar kerahasiaan data negara kembali terjamin tanpa kegaduhan.", val: 0}, {text: " Menyusun laporan audit dengan catatan perbaikan internal tanpa harus mempublikasikan detail kebocoran kepada pihak luar.", val: 0}, {text: " Mengonsultasikan masalah tersebut kepada pimpinan lembaga auditor untuk mencari solusi yang paling minim risiko bagi semua pihak.", val: 0}] },
{ text: "Sebuah tim ilmuwan Indonesia berhasil mengembangkan vaksin untuk penyakit endemik lokal dengan biaya produksi yang sangat murah. Namun, sebuah organisasi kesehatan internasional menawarkan hibah vaksin serupa secara gratis dalam jumlah besar untuk 10 tahun ke depan, dengan syarat Indonesia harus menghentikan produksi mandiri vaksin lokal tersebut demi standarisasi global. Pemerintah daerah sangat mendesak agar hibah diterima karena dapat menghemat anggaran kesehatan secara masif. Sebagai pembuat kebijakan nasional, tindakan yang paling selaras dengan semangat Bela Negara adalah...", options: [{text: " Menerima hibah tersebut untuk jangka pendek sambil terus menyempurnakan kualitas vaksin lokal agar kelak bisa bersaing.", val: 0}, {text: " Menolak hibah tersebut secara tegas dan mengalokasikan anggaran negara untuk mempercepat produksi massal vaksin dalam negeri.", val: 5}, {text: " Menyetujui hibah tersebut dengan syarat organisasi internasional bersedia melakukan transfer teknologi kepada ilmuwan lokal.", val: 0}, {text: " Melakukan uji perbandingan antara kedua vaksin secara transparan dan memilih yang paling efektif bagi kesehatan masyarakat.", val: 0}, {text: " Menerima sebagian hibah untuk daerah terpencil dan tetap mengizinkan produksi lokal untuk kebutuhan wilayah perkotaan.", val: 0}] },
{ text: "Sebuah perusahaan teknologi asing menawarkan pemasangan menara pemancar internet gratis di wilayah perbatasan Indonesia yang selama ini terisolasi, dengan syarat mereka diberikan akses penuh untuk mengelola pusat data (data center) yang terbangun tanpa pengawasan otoritas keamanan nasional karena alasan kerahasiaan operasional perusahaan. Meskipun pemerintah daerah sangat mendukung karena akan mempercepat digitalisasi warga desa, tindakan yang paling mencerminkan keberpihakan pada prinsip kedaulatan negara dalam situasi tersebut adalah...", options: [{text: " Menerima tawaran tersebut demi percepatan akses informasi dan pendidikan warga perbatasan.", val: 0}, {text: " Menyetujui pembangunan dengan syarat perusahaan wajib mempekerjakan tenaga ahli lokal.", val: 0}, {text: " Menolak persyaratan akses data sepihak guna melindungi keamanan informasi strategis negara.", val: 5}, {text: " Mengalihkan lokasi pembangunan ke wilayah perkotaan agar lebih mudah diawasi pemerintah.", val: 0}, {text: " Meminta jaminan tertulis bahwa data warga tidak akan diperjualbelikan kepada pihak ketiga.", val: 0}] },
{ text: "Dalam sebuah audit proyek strategis nasional, seorang analis menemukan bahwa penggunaan bahan baku lokal yang dipaksakan oleh kebijakan pimpinan ternyata memiliki kualitas di bawah standar yang dapat membahayakan keselamatan publik dalam jangka panjang. Pimpinan meminta analis tersebut untuk memaklumi temuan ini sebagai bentuk dukungan terhadap industri dalam negeri dan penguatan ekonomi nasional agar tidak bergantung pada impor. Langkah yang paling menunjukkan integritas Bela Negara yang benar dalam dilema tersebut adalah...", options: [{text: " Mendukung pimpinan demi menjaga citra positif industri dalam negeri di mata masyarakat.", val: 0}, {text: " Memberikan catatan perbaikan teknis tanpa harus merubah status kelayakan proyek tersebut.", val: 0}, {text: " Menolak laporan yang tidak akurat demi menjamin keselamatan publik dan martabat negara.", val: 5}, {text: " Menyarankan penggunaan bahan impor secara diam-diam agar kualitas proyek tetap terjaga.", val: 0}, {text: " Melakukan pengujian ulang dengan standar yang lebih rendah agar bahan lokal bisa lulus.", val: 0}] },
{ text: "Indonesia mendapatkan tawaran hibah berupa sistem peringatan dini bencana alam dari sebuah negara maju dengan teknologi tercanggih, namun sistem tersebut mengharuskan seluruh data seismik dan pergerakan tanah di Indonesia terhubung langsung ke satelit negara pemberi hibah sebelum diolah oleh instansi terkait di dalam negeri. Mengingat Indonesia adalah wilayah rawan bencana, kebijakan yang paling selaras dengan semangat kemandirian dan bela negara adalah...", options: [{text: " Menerima hibah tersebut karena keselamatan nyawa rakyat dari bencana adalah prioritas utama.", val: 0}, {text: " Menolak hibah tersebut dan memprioritaskan pengembangan teknologi serupa oleh ilmuwan lokal.", val: 5}, {text: " Menerima hibah tersebut dengan syarat pusat pengolahan data tetap berada di wilayah Indonesia.", val: 0}, {text: " Mengajak negara tetangga untuk bersama-sama menggunakan hibah tersebut agar lebih transparan.", val: 0}, {text: " Menyetujui hibah tersebut hanya untuk wilayah yang belum terjangkau oleh alat sensor nasional.", val: 0}] },
{ text: "Di tengah masifnya penggunaan platform media sosial global, muncul tren konten kreatif yang mempromosikan gaya hidup konsumerisme ekstrem dan nilai-nilai individualisme yang perlahan mengikis budaya gotong royong di kalangan generasi muda Indonesia. Sebagai seorang pembuat kebijakan digital, tindakan yang paling mencerminkan strategi Bela Negara dalam menghadapi fenomena penjajahan budaya modern ini adalah...", options: [{text: " Menutup akses platform media sosial asing yang terbukti banyak memuat konten yang tidak sesuai dengan kepribadian bangsa Indonesia.", val: 0}, {text: " Memberikan insentif dan ruang luas bagi kreator konten lokal untuk memproduksi karya yang mengusung kearifan lokal secara modern.", val: 5}, {text: " Mewajibkan seluruh platform digital asing untuk menyaring konten secara ketat sesuai dengan standar nilai moral dan etika Pancasila.", val: 0}, {text: " Mengimbau masyarakat untuk membatasi penggunaan media sosial dan beralih ke aktivitas sosial kemasyarakatan yang bersifat fisik.", val: 0}, {text: " Melakukan sensor massal terhadap akun-akun luar negeri yang memiliki pengaruh besar namun tidak sejalan dengan budaya nusantara.", val: 0}] },
{ text: "Sebuah konsorsium internasional menawarkan investasi pembangunan pelabuhan logistik terbesar di wilayah Indonesia Timur dengan janji pertumbuhan ekonomi lokal yang sangat cepat, namun mereka mensyaratkan penggunaan sistem navigasi dan keamanan laut milik mereka sendiri secara eksklusif dengan alasan standar keselamatan internasional. Mengingat lokasi tersebut berdekatan dengan jalur pelayaran strategis dan wilayah militer, kebijakan yang paling mencerminkan esensi Bela Negara adalah...", options: [{text: " Menerima investasi tersebut sepenuhnya demi mengejar ketertinggalan ekonomi rakyat di wilayah Indonesia Timur.", val: 0}, {text: " Menyetujui syarat tersebut asalkan otoritas militer Indonesia tetap diberikan akses untuk memantau data secara berkala.", val: 0}, {text: " Menolak persyaratan sistem navigasi asing dan mewajibkan integrasi dengan sistem pertahanan laut nasional secara mutlak.", val: 5}, {text: " Meminta kompensasi berupa pembangunan fasilitas publik lainnya agar masyarakat mendapatkan manfaat yang seimbang.", val: 0}, {text: " Menyarankan lokasi pembangunan dipindahkan ke wilayah lain yang tidak memiliki nilai strategis secara militer.", val: 0}] },
{ text: "Seorang ilmuwan data yang bekerja di instansi pemerintah menemukan bahwa algoritma sistem bantuan sosial nasional yang baru dikembangkan memiliki celah yang memungkinkan data kependudukan warga negara dapat dipetakan secara mendalam oleh pihak ketiga. Jika ia melaporkan hal ini secara formal, peluncuran program bantuan yang sangat dinanti masyarakat miskin akan tertunda selama berbulan-bulan akibat perbaikan sistem. Tindakan yang paling mewakili esensi Bela Negara dalam situasi dilematis ini adalah...", options: [{text: " Tetap meluncurkan program tersebut sesuai jadwal demi menyelamatkan ekonomi rakyat kecil yang sedang membutuhkan bantuan.", val: 0}, {text: " Melaporkan temuan celah keamanan tersebut secara resmi dan merekomendasikan penundaan hingga sistem benar-benar aman.", val: 5}, {text: " Meluncurkan program namun secara bertahap melakukan perbaikan sistem tanpa harus memberitahu publik mengenai celah tersebut.", val: 0}, {text: " Meminta perusahaan pengembang sistem untuk bertanggung jawab penuh secara hukum jika di masa depan terjadi kebocoran data.", val: 0}, {text: " Menyarankan penggunaan data sementara yang tidak sensitif agar program tetap berjalan meskipun tidak akurat 100%.", val: 0}] },
];

const twk_Bhineka = [
{ text: "Di tengah pesatnya digitalisasi birokrasi, seorang ASN di bidang komunikasi publik menemukan bahwa algoritma media sosial resmi instansi cenderung memperkuat interaksi hanya dengan kelompok masyarakat yang memiliki pandangan serupa dengan kebijakan pemerintah, sementara kritik dari kelompok marginal seringkali tenggelam atau tidak terakomodasi. Dalam konteks merawat kemajemukan bangsa di ruang siber, langkah strategis yang paling mencerminkan esensi nilai Bhinneka Tunggal Ika dalam menghadapi situasi tersebut adalah...", options: [{text: "Meningkatkan kuantitas konten moderasi untuk menangkal narasi yang memecah belah.", val: 0}, {text: "Melakukan kurasi manual untuk memastikan seluruh spektrum suara publik mendapat ruang.", val: 5}, {text: "Mengarahkan tim IT untuk memprioritaskan keamanan data dari serangan peretas asing.", val: 0}, {text: "Mensosialisasikan aturan etika bermedia sosial kepada seluruh lapisan masyarakat.", val: 0}, {text: "Menyesuaikan narasi kebijakan agar dapat diterima oleh semua kelompok kepentingan.", val: 0}] },
{ text: "Pemerintah pusat sedang melaksanakan proyek strategis nasional di sebuah wilayah adat yang memiliki sistem hukum lokal dan struktur sosial yang sangat kuat namun bertentangan dengan beberapa efisiensi prosedur teknis pembangunan. Sebagai pejabat pelaksana yang ditugaskan menjembatani kepentingan pusat dan daerah, tindakan yang paling menunjukkan implementasi sintesis nilai Ika (kesatuan) tanpa menegasi Bhinneka (keberagaman) adalah...", options: [{text: "Menjalankan prosedur teknis sesuai regulasi nasional dengan memberikan ganti rugi yang adil.", val: 0}, {text: "Melakukan pendekatan personal kepada tokoh adat agar bersedia menerima modernisasi.", val: 0}, {text: "Mengintegrasikan elemen nilai lokal ke dalam sistem operasional dan desain proyek.", val: 5}, {text: "Menunda proyek sampai masyarakat setempat memiliki kesadaran hukum nasional yang sama.", val: 0}, {text: "Meminta jaminan keamanan dari aparat untuk memastikan proyek berjalan tanpa hambatan.", val: 0}] },
{ text: "Dalam sebuah rapat penentuan kebijakan distribusi bantuan sosial, terjadi perdebatan sengit di mana beberapa rekan sejawat Anda mengusulkan untuk memprioritaskan wilayah yang mayoritas penduduknya memiliki kesamaan latar belakang sosiokultural dengan kepemimpinan saat ini demi stabilitas dukungan politik. Di sisi lain, terdapat wilayah tertinggal dengan latar belakang berbeda yang sangat membutuhkan bantuan namun minim dukungan politik. Sikap Anda sebagai ASN yang memegang teguh komitmen kebangsaan adalah...", options: [{text: "Mendukung usulan mayoritas demi menjaga keharmonisan internal instansi.", val: 0}, {text: "Mengusulkan pembagian bantuan dilakukan secara rata tanpa melihat skala prioritas.", val: 0}, {text: "Mendesak penerapan kriteria objektif berdasarkan basis data kemiskinan yang valid.", val: 5}, {text: "Menyarankan pemberian bantuan tambahan bagi wilayah yang mendukung kebijakan.", val: 0}, {text: "Mengambil jalan tengah dengan membagi porsi bantuan berdasarkan jumlah penduduk.", val: 0}] },
{ text: "Sebagai ketua tim seleksi promosi jabatan di sebuah instansi pusat, Anda menghadapi situasi di mana hasil asesmen kompetensi menunjukkan bahwa kandidat terbaik secara teknis berasal dari latar belakang identitas yang sama dengan mayoritas pegawai di unit tersebut. Di sisi lain, terdapat kebijakan internal untuk meningkatkan representasi pegawai dari wilayah tertinggal (minoritas) guna menciptakan lingkungan kerja yang lebih inklusif, namun skor kompetensi kandidat minoritas tersebut sedikit di bawah ambang batas keunggulan. Langkah yang paling mencerminkan prinsip Tunggal Ika (Kesatuan) yang berkeadilan adalah...", options: [{text: "Memilih kandidat mayoritas demi menjaga stabilitas dan produktivitas tim yang sudah ada.", val: 0}, {text: "Meloloskan kandidat minoritas sebagai bentuk afirmasi nyata terhadap keberagaman bangsa.", val: 0}, {text: "Mengusulkan program pendampingan intensif bagi kandidat minoritas sebelum menempatkannya.", val: 0}, {text: "Menetapkan standar kelulusan baru yang lebih akomodatif terhadap latar belakang sosiokultural.", val: 0}, {text: "Mengutamakan kandidat dengan skor tertinggi sambil merancang sistem mentoring lintas budaya.", val: 5}] },
{ text: "Dalam sebuah forum negosiasi perdagangan internasional, delegasi Indonesia mendapatkan tawaran investasi besar yang sangat menguntungkan ekonomi nasional. Namun, salah satu syarat investor adalah standarisasi produk yang mengharuskan penghapusan metode pengolahan tradisional berbasis komunitas adat di beberapa daerah karena dianggap tidak memenuhi kriteria efisiensi global. Sebagai bagian dari delegasi, tindakan yang paling menunjukkan sikap menghargai kebhinnekaan sebagai kekuatan bangsa adalah...", options: [{text: "Menerima syarat tersebut demi mempercepat pertumbuhan ekonomi dan kesejahteraan umum.", val: 0}, {text: "Menolak investasi secara tegas karena mengancam kedaulatan budaya dan tradisi lokal.", val: 0}, {text: "Menegosiasikan ruang khusus bagi produk tradisional dalam skema pasar niche (khusus).", val: 5}, {text: "Meminta komunitas adat untuk segera memodifikasi metode mereka agar sesuai standar investor.", val: 0}, {text: "Menyarankan pembangunan pabrik modern di wilayah lain yang tidak memiliki tradisi kuat.", val: 0}] },
{ text: "Seorang ASN yang bertugas di bagian pelayanan perizinan mendapati seorang warga dari kelompok rentan yang kesulitan memenuhi persyaratan administratif digital karena kendala bahasa dan keterbatasan akses teknologi. Rekan kerja Anda menyarankan agar warga tersebut diminta pulang dan mencari pendamping mandiri agar tidak menghambat antrean pelayanan yang sedang padat. Tindakan Anda yang paling mencerminkan esensi nilai kemanusiaan dalam bingkai Bhinneka Tunggal Ika adalah...", options: [{text: "Memberikan pengecualian syarat administrasi bagi warga tersebut sebagai bentuk empati.", val: 0}, {text: "Menyediakan ruang konsultasi khusus dan memandu proses digitalisasi secara langsung.", val: 5}, {text: "Meminta bantuan tokoh masyarakat setempat untuk menjelaskan prosedur kepada warga itu.", val: 0}, {text: "Tetap meminta warga mengikuti prosedur standar demi menjaga azas keadilan bagi antrean lain.", val: 0}, {text: "Menyarankan warga tersebut untuk menggunakan jasa calo resmi yang terdaftar di instansi.", val: 0}] },
{ text: "Seorang pimpinan tinggi di sebuah kementerian teknis menghadapi penolakan internal dari sekelompok pegawai senior terkait kebijakan rotasi jabatan yang menempatkan figur-figur muda berprestasi dari berbagai latar belakang etnis di posisi strategis. Kelompok senior berargumen bahwa rotasi tersebut merusak adat istiadat kerja dan kohesivitas internal yang selama ini terjaga lewat sistem senioritas. Dalam menjaga integrasi nasional sekaligus profesionalisme birokrasi, tindakan pimpinan yang paling mencerminkan filosofi Bhinneka Tunggal Ika adalah...", options: [{text: "Menangguhkan rotasi jabatan hingga tercipta konsensus antara kelompok senior dan junior.", val: 0}, {text: "Melakukan dialog persuasif mengenai pentingnya pembauran latar belakang untuk inovasi organisasi.", val: 0}, {text: "Tetap melaksanakan rotasi berdasarkan meritokrasi sambil memberikan peran penasihat bagi senior.", val: 5}, {text: "Memberikan kompensasi berupa tunjangan khusus bagi pegawai senior yang posisinya tergeser.", val: 0}, {text: "Menyesuaikan kriteria rotasi agar komposisi etnis dan usia tetap seimbang secara proporsional.", val: 0}] },
{ text: "Dalam proyek pengadaan pangan untuk bantuan darurat di wilayah yang mengalami krisis, seorang Pejabat Pembuat Komitmen (PPK) diminta untuk segera menyediakan paket bantuan dalam jumlah besar dengan standar nutrisi nasional. Namun, distribusi komoditas standar tersebut berpotensi mematikan rantai pasok petani lokal yang memiliki jenis pangan berbeda namun secara budaya lebih diterima oleh masyarakat setempat. Langkah strategis yang paling menunjukkan pemahaman mendalam tentang nilai Bhinneka dalam kebijakan publik adalah...", options: [{text: "Mengutamakan komoditas standar nasional demi efisiensi pengadaan dan akuntabilitas audit.", val: 0}, {text: "Melakukan penyesuaian spesifikasi pengadaan yang mengakomodasi komoditas pangan lokal.", val: 5}, {text: "Membagi paket bantuan menjadi dua bagian: 50% standar nasional dan 50% produk lokal.", val: 0}, {text: "Mengedukasi masyarakat setempat agar mulai terbiasa mengonsumsi pangan standar nasional.", val: 0}, {text: "Menunda pengadaan hingga ditemukan vendor tunggal yang mampu menyediakan semua jenis pangan.", val: 0}] },
{ text: "Sebagai seorang camat di wilayah yang baru saja mengalami konflik horizontal antar kelompok masyarakat akibat provokasi di media sosial, Anda diminta menyusun program Rekonsiliasi Jangka Panjang. Jika program tersebut ingin menyentuh akar filosofi Bhinneka Tunggal Ika yang substansial, maka fokus utama dari program yang Anda susun adalah...", options: [{text: "Membangun monumen perdamaian yang melibatkan simbol-simbol seluruh kelompok yang bertikai.", val: 0}, {text: "Memperbanyak personel keamanan di titik-titik rawan untuk mencegah terjadinya konflik susulan.", val: 0}, {text: "Menciptakan proyek kolaborasi ekonomi yang mengharuskan interaksi lintas kelompok secara intensif.", val: 5}, {text: "Mengadakan forum dialog antar tokoh agama dan tokoh adat secara rutin di kantor kecamatan.", val: 0}, {text: "Memberikan bantuan sosial secara merata kepada seluruh pihak yang terdampak konflik tersebut.", val: 0}] },
{ text: "Di sebuah kawasan pemukiman urban yang heterogen, muncul kecenderungan dari kelompok penghuni tertentu untuk membuat peraturan internal yang membatasi penggunaan fasilitas umum hanya bagi kalangan mereka sendiri dengan alasan keamanan dan kenyamanan privasi. Hal ini memicu kecemburuan sosial dari warga sekitar yang merasa teralienasi di tanah mereka sendiri. Sebagai ASN yang bertugas di otoritas wilayah tersebut, tindakan yang paling mencerminkan upaya merawat integrasi nasional sesuai semangat Bhinneka Tunggal Ika adalah...", options: [{text: "Mendukung aturan tersebut selama disepakati oleh mayoritas penghuni di dalam kawasan.", val: 0}, {text: "Memfasilitasi dialog untuk merumuskan ulang aturan yang lebih inklusif bagi seluruh warga.", val: 5}, {text: "Menyarankan pembangunan pagar pembatas yang lebih permanen agar tidak terjadi gesekan fisik.", val: 0}, {text: "Memberikan bantuan sosial kepada warga sekitar agar tidak mempermasalahkan aturan tersebut.", val: 0}, {text: "Menyerahkan sepenuhnya penyelesaian masalah kepada aparat keamanan untuk menjaga ketertiban.", val: 0}] },
{ text: "Sebuah perusahaan besar mendapatkan izin pemerintah untuk mengembangkan lahan di wilayah perbukitan yang secara administratif adalah milik negara, namun secara turun-temurun diyakini oleh masyarakat lokal sebagai hutan keramat pelindung sumber air. Masyarakat menolak proyek tersebut meskipun dijanjikan lapangan kerja luas. Sebagai mediator yang memegang prinsip wawasan kebangsaan, langkah yang paling tepat untuk menyinergikan kepentingan pembangunan dan penghormatan terhadap keragaman adalah...", options: [{text: "Memastikan perusahaan memberikan kompensasi finansial yang sangat tinggi kepada setiap kepala keluarga.", val: 0}, {text: "Menjalankan proyek sesuai regulasi karena izin negara memiliki derajat hukum tertinggi dibanding klaim adat.", val: 0}, {text: "Mendorong kolaborasi untuk mengubah hutan tersebut menjadi kawasan ekowisata berbasis kearifan lokal.", val: 5}, {text: "Meminta tokoh masyarakat untuk mengalah demi kepentingan nasional yang lebih besar dan luas.", val: 0}, {text: "Melakukan relokasi paksa terhadap warga agar proyek strategis nasional tidak terhambat oleh hambatan lokal.", val: 0}] },
{ text: "Menjelang pemilihan kepala desa di wilayah yang memiliki komposisi penduduk sangat beragam, media sosial lokal dipenuhi oleh kampanye yang menggunakan narasi Putra Daerah sebagai syarat mutlak kepemimpinan untuk menjamin perlindungan kepentingan kelompok tertentu. Narasi ini mulai memicu ketegangan antara warga pendatang dan warga asli. Sikap paling tepat dari seorang ASN yang berdomisili di wilayah tersebut untuk meredam konflik identitas adalah...", options: [{text: "Bersikap netral dan tidak ikut campur dalam perdebatan karena merupakan hak politik warga.", val: 0}, {text: "Mengampanyekan pentingnya memilih pemimpin berdasarkan kapasitas dan integritas lintas identitas.", val: 5}, {text: "Meminta pihak kepolisian untuk segera menangkap pihak yang menyebarkan narasi putra daerah.", val: 0}, {text: "Mendukung salah satu kandidat yang dinilai paling moderat dan mampu merangkul semua pihak.", val: 0}, {text: "Menyarankan agar kandidat pendatang mengundurkan diri demi menjaga stabilitas keamanan desa.", val: 0}] },
{ text: "Maraknya platform belanja daring global memungkinkan produk manufaktur luar negeri masuk ke pasar domestik dengan harga yang sangat murah, sehingga mengancam keberlangsungan pengrajin tradisional di berbagai daerah yang memiliki nilai budaya tinggi namun biaya produksi lebih besar. Dalam menyikapi fenomena ini, kebijakan pemerintah yang paling mencerminkan upaya perlindungan Bhinneka (kekayaan lokal) tanpa mengisolasi diri dari Ika (pergaulan ekonomi global) adalah...", options: [{text: "Menutup akses platform belanja daring global untuk melindungi produk dalam negeri.", val: 0}, {text: "Memberikan subsidi tunai kepada pengrajin tradisional agar harga produknya tetap bersaing.", val: 0}, {text: "Mewajibkan platform digital memberikan porsi promosi dan kurasi khusus bagi produk lokal.", val: 5}, {text: "Menyarankan pengrajin lokal untuk meninggalkan metode tradisional dan beralih ke mesin.", val: 0}, {text: "Menetapkan pajak tinggi bagi setiap warga negara yang membeli produk dari luar negeri.", val: 0}] },
{ text: "Pemerintah sedang gencar melakukan hilirisasi industri nikel di wilayah Indonesia Timur guna meningkatkan nilai tambah ekonomi nasional. Namun, kedatangan ribuan tenaga kerja lintas daerah dan mancanegara ke lokasi industri tersebut mulai menciptakan gesekan sosial dengan penduduk lokal terkait perbedaan gaya hidup, sistem nilai, dan persaingan peluang usaha kecil. Sikap seorang ASN yang ditugaskan di wilayah tersebut untuk menjaga stabilitas integrasi bangsa adalah...", options: [{text: "Membatasi interaksi antara tenaga kerja luar dengan penduduk lokal untuk mencegah konflik.", val: 0}, {text: "Meminta penduduk lokal untuk sepenuhnya beradaptasi dengan budaya kerja tenaga kerja asing.", val: 0}, {text: "Menginisiasi forum kolaborasi yang melibatkan pengusaha lokal dalam rantai pasok industri.", val: 5}, {text: "Mengutamakan penegakan hukum yang kaku terhadap setiap gesekan kecil di masyarakat.", val: 0}, {text: "Menyarankan perusahaan untuk memulangkan tenaga kerja luar demi ketenangan warga.", val: 0}] },
{ text: "Seorang ASN yang bertugas di bagian pendaftaran haji dan umrah mendapati bahwa instansinya sedang menjadi sorotan media karena adanya tuntutan dari kelompok minoritas yang menginginkan perlakuan dan fasilitas administrasi yang setara untuk perjalanan spiritual mereka, meskipun secara regulasi teknis prosedurnya belum selengkap layanan mayoritas. Di tengah tekanan opini publik yang terbelah, sikap yang paling sesuai dengan esensi Bhinneka Tunggal Ika adalah...", options: [{text: "Menolak tuntutan tersebut karena harus mengutamakan pelayanan pada kelompok mayoritas.", val: 0}, {text: "Bersikap pasif dan menunggu instruksi tertulis dari pimpinan pusat agar aman secara karier.", val: 0}, {text: "Memberikan penjelasan yang santun mengenai batasan regulasi sambil membantu mencarikan solusi teknis.", val: 5}, {text: "Mendukung sepenuhnya tuntutan tersebut secara terbuka di media sosial pribadi sebagai bentuk empati.", val: 0}, {text: "Mengabaikan keluhan tersebut demi menjaga stabilitas dan ketenangan di lingkungan kerja.", val: 0}] },
{ text: "Dalam upaya mewujudkan Satu Data Indonesia, pemerintah menghadapi tantangan berupa disparitas infrastruktur digital antara kota besar dengan wilayah pedalaman yang dihuni oleh masyarakat adat. Ada usulan untuk menerapkan sistem identitas digital terpusat guna mempermudah akses layanan publik secara nasional. Namun, hal ini berisiko meminggirkan warga di pelosok yang tidak memiliki perangkat teknologi atau memiliki hambatan budaya terhadap pendataan tertentu. Ditinjau dari perspektif Bhinneka Tunggal Ika sebagai instrumen integrasi, kebijakan yang paling tepat adalah...", options: [{text: "Menunda digitalisasi identitas nasional sampai infrastruktur di seluruh pelosok negeri setara.", val: 0}, {text: "Menjalankan digitalisasi secara masif dan mewajibkan warga pelosok untuk segera beradaptasi.", val: 0}, {text: "Mengembangkan sistem identitas hibrida yang mengakomodasi teknologi sekaligus kearifan lokal.", val: 5}, {text: "Memberikan bantuan perangkat digital gratis kepada setiap individu di wilayah pedalaman.", val: 0}, {text: "Menyerahkan urusan pendataan warga pelosok kepada otoritas adat tanpa campur tangan pusat.", val: 0}] },
{ text: "Untuk meningkatkan daya saing global, muncul desakan agar seluruh kurikulum pendidikan di Indonesia diseragamkan dengan standar internasional yang berfokus pada sains dan teknologi. Hal ini berpotensi mereduksi porsi pendidikan berbasis budaya dan bahasa daerah yang dianggap tidak relevan dengan kebutuhan pasar kerja modern. Keputusan strategis yang paling menunjukkan fungsi Bhinneka Tunggal Ika sebagai kekuatan dinamis bangsa adalah...", options: [{text: "Menolak standar internasional karena dianggap sebagai bentuk penjajahan budaya baru.", val: 0}, {text: "Mengadopsi standar internasional sepenuhnya agar lulusan Indonesia mampu bersaing di luar negeri.", val: 0}, {text: "Mengintegrasikan capaian standar global ke dalam konteks dan muatan kearifan lokal daerah.", val: 5}, {text: "Membiarkan setiap daerah menentukan kurikulumnya sendiri tanpa perlu adanya standar nasional.", val: 0}, {text: "Menjadikan bahasa daerah sebagai mata pelajaran opsional yang tidak wajib diikuti siswa.", val: 0}] },
{ text: "Sebuah wilayah kaya mineral di Indonesia dihuni oleh komunitas lintas etnis yang selama puluhan tahun hidup berdampingan secara damai lewat pembagian zona ekonomi tradisional. Ketika perusahaan negara masuk untuk melakukan eksploitasi skala besar, muncul faksionalisme di mana kelompok yang diuntungkan secara ekonomi mendukung perusahaan, sementara kelompok yang terdampak lingkungan menolak. Sebagai representasi negara di wilayah tersebut, landasan berpikir yang harus Anda gunakan dalam memitigasi konflik tersebut adalah...", options: [{text: "Mendukung kelompok mayoritas agar stabilitas keamanan di wilayah tersebut tetap kondusif.", val: 0}, {text: "Mengedepankan musyawarah yang berorientasi pada pengakuan hak seluruh kelompok identitas.", val: 5}, {text: "Meminta perusahaan untuk hanya mempekerjakan warga asli guna meredam kecemburuan.", val: 0}, {text: "Menggunakan pendekatan hukum formal karena izin negara bersifat mutlak dan mengikat.", val: 0}, {text: "Memberikan insentif ekonomi lebih kepada kelompok yang melakukan penolakan agar luluh.", val: 0}] },
{ text: "Di sebuah wilayah perbatasan laut, nelayan lokal seringkali bergesekan dengan kapal asing yang melakukan pencurian ikan. Namun, di sisi lain, beberapa komunitas nelayan lokal secara ekonomi bergantung pada perdagangan ilegal dengan kapal asing tersebut karena kurangnya akses pasar ke wilayah Indonesia lainnya. Dalam upaya menegakkan kedaulatan negara tanpa merusak kohesi sosial masyarakat perbatasan yang beragam, langkah negara yang paling mencerminkan prinsip Tunggal Ika adalah...", options: [{text: "Melakukan tindakan hukum tegas dan represif kepada seluruh nelayan yang berinteraksi dengan pihak asing.", val: 0}, {text: "Mengintegrasikan pasar hasil laut lokal ke dalam rantai pasok nasional melalui pembangunan konektivitas.", val: 5}, {text: "Memberikan bantuan pangan gratis secara berkelanjutan agar nelayan tidak lagi berdagang dengan pihak asing.", val: 0}, {text: "Memperbolehkan perdagangan ilegal dalam skala kecil demi menjaga stabilitas ekonomi warga perbatasan.", val: 0}, {text: "Melakukan relokasi nelayan perbatasan ke wilayah pedalaman agar lebih mudah dalam pengawasan negara.", val: 0}] },
{ text: "Muncul sebuah tren di mana motif tradisional dari suatu suku di Indonesia digunakan secara massal oleh merek fesyen internasional tanpa izin dan tanpa mencantumkan asal-usul budayanya. Di dalam negeri, terjadi perdebatan; satu pihak menganggap ini promosi budaya, pihak lain menganggap ini pencurian identitas. Sebagai ASN yang bergerak di bidang kebudayaan, tindakan yang paling mencerminkan upaya perlindungan terhadap kebhinnekaan sebagai kekayaan nasional adalah...", options: [{text: "Menuntut merek internasional tersebut untuk menghentikan penggunaan motif agar budaya tidak luntur.", val: 0}, {text: "Memfasilitasi pendaftaran Hak Kekayaan Intelektual Komunal (HKIK) atas karya-karya budaya daerah.", val: 5}, {text: "Mengajak masyarakat untuk memboikot produk internasional tersebut sebagai bentuk rasa nasionalisme.", val: 0}, {text: "Menyarankan pengrajin lokal untuk meniru desain internasional tersebut agar tetap terlihat modern.", val: 0}, {text: "Mengabaikan hal tersebut karena budaya memang bersifat dinamis dan dapat digunakan oleh siapa saja.", val: 0}] },
{ text: "Dalam sebuah krisis kesehatan masyarakat yang mengharuskan adanya tindakan medis darurat secara massal, muncul penolakan dari sekelompok kecil masyarakat di wilayah tertentu karena alasan keyakinan budaya yang berbeda dengan standar medis pemerintah. Dalam konteks menjaga ketertiban umum tanpa mencederai prinsip menghargai kebhinnekaan, langkah kebijakan yang paling tepat adalah...", options: [{text: "Mewajibkan tindakan medis tersebut dengan pengawalan aparat demi keselamatan nasional.", val: 0}, {text: "Memberikan pengecualian bagi kelompok tersebut agar tidak memicu kerusuhan sosial di daerah.", val: 0}, {text: "Menggunakan pendekatan persuasif melibatkan tokoh adat/agama untuk mengontekstualisasikan medis.", val: 5}, {text: "Menunda seluruh program medis nasional sampai semua kelompok masyarakat memberikan persetujuan.", val: 0}, {text: "Meminta kelompok tersebut untuk mengisolasi diri secara mandiri dari masyarakat umum lainnya.", val: 0}] },
{ text: "Di tengah situasi politik yang memanas, seorang ASN yang bertugas di daerah terpencil aktif menggunakan media sosial pribadinya untuk mempromosikan keindahan alam dan produk UMKM lintas etnis di wilayahnya sebagai upaya pemersatu. Namun, salah satu unggahannya yang menampilkan kebersamaan dengan tokoh masyarakat tertentu dianggap oleh sebagian kelompok sebagai bentuk dukungan politik implisit, padahal tujuannya murni untuk kohesi sosial. Menghadapi potensi polarisasi ini, tindakan yang paling mencerminkan prinsip Tunggal Ika dalam profesionalisme ASN adalah...", options: [{text: "Menghapus semua unggahan media sosial agar tidak menimbulkan spekulasi dan menjaga karier.", val: 0}, {text: "Memberikan klarifikasi terbuka mengenai nilai-nilai kebangsaan yang mendasari unggahan tersebut.", val: 5}, {text: "Meminta maaf kepada kelompok yang keberatan dan berhenti mempromosikan budaya lokal.", val: 0}, {text: "Melaporkan pihak-pihak yang menyalahartikan unggahan tersebut kepada aparat penegak hukum.", val: 0}, {text: "Mengalihkan akun pribadi menjadi akun dinas agar setiap unggahan memiliki payung hukum.", val: 0}] },
{ text: "Pemerintah sedang merancang regulasi sertifikasi wajib bagi seluruh produk industri kreatif untuk menembus pasar internasional. Namun, beberapa kelompok pengrajin tradisional di pelosok keberatan karena persyaratan sertifikasi tersebut mengharuskan perubahan pada bahan baku alami yang selama ini menjadi identitas budaya mereka (misalnya penggunaan pewarna alami yang tidak masuk standar kimia tertentu). Langkah kebijakan yang paling tepat untuk menjaga kedaulatan budaya dalam bingkai persatuan ekonomi adalah...", options: [{text: "Mewajibkan seluruh pengrajin mengikuti standar global agar ekonomi nasional terus meningkat.", val: 0}, {text: "Memberikan pengecualian sertifikasi bagi produk tradisional namun melarangnya untuk diekspor.", val: 0}, {text: "Menciptakan protokol sertifikasi khusus Warisan Budaya yang diakui secara internasional.", val: 5}, {text: "Membiarkan pengrajin berproduksi secara tradisional hanya untuk konsumsi masyarakat lokal.", val: 0}, {text: "Memberikan bantuan dana bagi pengrajin agar mampu membeli bahan baku kimia sesuai standar.", val: 0}] },
{ text: "Sebuah instansi pemerintah menerapkan sistem Work From Anywhere (WFA) secara permanen untuk efisiensi. Namun, evaluasi menunjukkan bahwa pegawai dari latar belakang wilayah yang infrastruktur internetnya buruk mengalami penurunan performa dan mulai merasa terpinggirkan dari pergaulan organisasi pusat. Fenomena ini mulai menimbulkan sentimen pusat versus daerah di internal organisasi. Tindakan pimpinan yang paling mencerminkan filosofi Bhinneka Tunggal Ika adalah...", options: [{text: "Membatalkan kebijakan WFA dan mewajibkan semua pegawai kembali bekerja di kantor pusat.", val: 0}, {text: "Memberikan sanksi disiplin bagi pegawai daerah yang performanya menurun akibat kendala sinyal.", val: 0}, {text: "Membangun hub kantor satelit di berbagai wilayah untuk menjamin kesetaraan akses kerja.", val: 5}, {text: "Mengutamakan promosi jabatan bagi pegawai yang mampu bekerja secara digital dengan cepat.", val: 0}, {text: "Menyarankan pegawai daerah untuk pindah ke kota besar agar tetap bisa bersaing dalam sistem.", val: 0}] },
{ text: "Di sebuah pemukiman padat penduduk yang dihuni oleh berbagai suku, terdapat tradisi tahunan menyalakan api unggun besar dan kembang api sebagai simbol pembersihan diri yang telah dilakukan secara turun-temurun. Namun, seiring bertambah padatnya bangunan permanen yang mudah terbakar, sebagian warga pendatang merasa khawatir dan keberatan karena menganggap tradisi tersebut mengancam keselamatan lingkungan. Sikap warga yang paling mencerminkan esensi nilai Bhinneka Tunggal Ika dalam menyelesaikan ketegangan sosial tersebut adalah...", options: [{text: "Mendukung penghentian total tradisi tersebut demi menjamin keselamatan jiwa dan harta benda seluruh warga.", val: 0}, {text: "Tetap menjalankan tradisi sesuai warisan leluhur karena identitas budaya tidak boleh dikalahkan oleh ketakutan.", val: 0}, {text: "Mengalihwujudkan simbol ritual ke dalam bentuk lain yang lebih aman tanpa menghilangkan esensi maknanya.", val: 5}, {text: "Meminta bantuan aparat kepolisian untuk membubarkan warga yang tetap bersikeras menjalankan tradisi.", val: 0}, {text: "Menyerahkan sepenuhnya kepada ketua adat untuk menentukan apakah tradisi tetap lanjut atau dihentikan.", val: 0}] },
{ text: "Sebuah komunitas warga di perumahan elite seringkali menggunakan jalan umum di depan kompleks mereka untuk kegiatan internal kelompoknya dan secara sepihak membatasi akses bagi pedagang kaki lima atau kurir dari luar dengan alasan ketertiban. Hal ini memicu ketegangan dengan warga dari perkampungan sekitar yang merasa hak akses publiknya terganggu. Tindakan paling tepat dari pengurus lingkungan untuk merawat integrasi nasional di tingkat akar rumput adalah...", options: [{text: "Memperketat pengamanan agar tidak ada orang luar yang masuk demi menjaga kenyamanan warga perumahan.", val: 0}, {text: "Memberikan santunan berkala kepada warga kampung sekitar agar mereka memaklumi pembatasan akses tersebut.", val: 0}, {text: "Menghilangkan segala bentuk penyekatan fisik dan membangun ruang kolaborasi ekonomi antara kedua wilayah.", val: 5}, {text: "Menyarankan warga kampung sekitar untuk mencari jalan alternatif lain agar tidak mengganggu warga elite.", val: 0}, {text: "Melaporkan tindakan penyekatan tersebut kepada pemerintah daerah agar diambil tindakan hukum yang tegas.", val: 0}] },
{ text: "Di media sosial, muncul diskusi publik mengenai penggunaan atribut kebudayaan tertentu dalam ritual keagamaan yang memicu perdebatan sengit antara kelompok yang ingin menjaga kemurnian ajaran dengan kelompok yang ingin mempertahankan sinkretisme budaya. Perdebatan ini mulai mengarah pada aksi saling lapor dan ujaran kebencian. Sebagai warga negara yang sadar akan kemajemukan, cara bersikap yang paling sesuai dengan prinsip Bhinneka Tunggal Ika adalah...", options: [{text: "Memilih untuk tidak berpendapat sama sekali agar tidak memperkeruh suasana dan menghindari konflik.", val: 0}, {text: "Mendukung kelompok yang ingin menjaga kemurnian budaya agar identitas bangsa tidak tergerus oleh paham luar.", val: 0}, {text: "Mengedukasi publik tentang sejarah panjang akulturasi budaya sebagai perekat identitas nasional Indonesia.", val: 5}, {text: "Mendesak pemerintah untuk melarang diskusi mengenai isu sensitif di media sosial demi stabilitas keamanan.", val: 0}, {text: "Membela salah satu pihak yang dianggap memiliki argumen paling logis dan mendasar secara keilmuan.", val: 0}] },
{ text: "Di sebuah kompleks perumahan yang dihuni oleh warga dari berbagai latar belakang suku dan agama, terdapat sebuah lapangan serbaguna. Kelompok remaja dari salah satu suku dominan sering menggunakan lapangan tersebut untuk latihan tari daerah mereka hampir setiap sore, sehingga kelompok remaja lain merasa tidak memiliki kesempatan untuk berolahraga. Ketegangan mulai muncul ketika ada warga yang mengusulkan agar latihan tari tersebut dilarang karena dianggap mengganggu ketertiban. Sikap sebagai warga yang menjunjung nilai Bhinneka Tunggal Ika dalam menghadapi situasi ini adalah...", options: [{text: "Mendukung pelarangan latihan tari demi menjaga ketenangan dan ketertiban lingkungan pemukiman.", val: 0}, {text: "Menyarankan agar kelompok tari tersebut mencari tempat latihan lain yang lebih tertutup dan privat.", val: 0}, {text: "Mengusulkan penyusunan jadwal penggunaan lapangan yang adil bagi semua jenis kegiatan warga.", val: 5}, {text: "Meminta kelompok mayoritas untuk selalu mengalah kepada kelompok minoritas demi toleransi.", val: 0}, {text: "Menyerahkan keputusan sepenuhnya kepada pengurus RT untuk menghindari keterlibatan personal.", val: 0}] },
{ text: "Sebuah desa wisata dikenal karena arsitektur rumah tradisionalnya yang khas dan seragam. Namun, beberapa warga generasi muda mulai merenovasi rumah mereka dengan gaya minimalis modern dan menggunakan material baru demi alasan kenyamanan dan efisiensi biaya. Sebagian tetua desa khawatir hal ini akan merusak wajah desa dan menghilangkan daya tarik budaya yang menjadi pemersatu warga. Tindakan masyarakat desa yang paling tepat dalam bingkai keberagaman yang dinamis adalah...", options: [{text: "Membuat peraturan desa yang melarang keras segala bentuk perubahan arsitektur rumah tradisional.", val: 0}, {text: "Membiarkan setiap warga mengubah bentuk rumahnya karena merupakan hak milik pribadi yang absolut.", val: 0}, {text: "Mendiskusikan standar renovasi yang memadukan kenyamanan modern tanpa mengubah fasad tradisional.", val: 5}, {text: "Mengusir warga yang tetap merenovasi rumahnya dengan gaya modern dari wilayah desa wisata tersebut.", val: 0}, {text: "Meminta bantuan pemerintah untuk memberikan dana renovasi penuh agar warga tidak mengubah bentuk rumah.", val: 0}] },
{ text: "Dalam sebuah rapat warga di suatu kampung, muncul penolakan terhadap rencana pindahnya sekelompok warga pendatang yang memiliki profesi dan gaya hidup yang dianggap sangat berbeda dengan nilai-nilai lokal yang selama ini dianut warga asli. Ada kekhawatiran bahwa kehadiran mereka akan merusak moralitas dan kerukunan desa. Cara pandang yang harus dikedepankan oleh masyarakat umum dalam menyikapi fenomena ini sesuai filosofi Bhinneka Tunggal Ika adalah...", options: [{text: "Menolak warga baru tersebut jika tidak bersedia membuat surat pernyataan mengikuti semua adat lokal.", val: 0}, {text: "Menerima mereka dengan syarat mereka harus membatasi interaksi sosial dengan warga asli kampung.", val: 0}, {text: "Menyadari bahwa keberagaman latar belakang adalah keniscayaan yang harus diterima dengan keterbukaan.", val: 5}, {text: "Meminta pemerintah desa untuk melakukan seleksi ketat berdasarkan latar belakang suku warga baru.", val: 0}, {text: "Mengadakan upacara adat penyambutan yang mewajibkan warga baru tersebut mengubah identitasnya.", val: 0}] },
{ text: "Dalam upaya modernisasi kearsipan nasional, pemerintah meluncurkan proyek digitalisasi besar-besaran terhadap manuskrip kuno yang disimpan oleh berbagai komunitas adat di pedalaman. Namun, beberapa komunitas keberatan jika pengetahuan tradisional dalam manuskrip tersebut diakses secara bebas oleh publik dunia melalui internet karena dianggap sakral dan memiliki risiko komersialisasi tanpa izin. Sikap yang paling mencerminkan prinsip Tunggal Ika dalam menjaga kedaulatan pengetahuan lokal di era digital adalah...", options: [{text: "Tetap melakukan digitalisasi secara penuh demi kepentingan ilmu pengetahuan dan kemajuan peradaban.", val: 0}, {text: "Menunda proyek digitalisasi hingga masyarakat adat secara mandiri memiliki teknologi proteksi data.", val: 0}, {text: "Mengembangkan platform akses terbatas yang memberikan hak kontrol kepada komunitas pemilik budaya.", val: 5}, {text: "Membayar ganti rugi yang besar kepada masyarakat adat sebagai kompensasi atas publikasi manuskrip.", val: 0}, {text: "Menyarankan masyarakat adat untuk merahasiakan manuskrip tersebut dan tidak perlu didigitalisasi.", val: 0}] },
{ text: "Pemerintah kota sedang merancang sistem transportasi publik terpadu yang sangat efisien, cepat, dan berbasis aplikasi untuk mengurangi kemacetan. Namun, kehadiran sistem ini berisiko mematikan moda transportasi tradisional khas daerah tersebut (seperti delman atau becak hias) yang selama ini menjadi ikon pariwisata dan tumpuan ekonomi masyarakat kecil. Langkah strategis yang paling sesuai dengan semangat menghargai keberagaman ekonomi dan budaya adalah...", options: [{text: "Menghapuskan seluruh moda tradisional agar sistem transportasi kota terlihat modern dan profesional.", val: 0}, {text: "Membiarkan moda tradisional beroperasi secara bebas tanpa aturan agar terjadi persaingan alami.", val: 0}, {text: "Mengintegrasikan moda tradisional sebagai transportasi pengumpan (feeder) di rute-rute wisata khusus.", val: 5}, {text: "Memberikan santunan penutupan usaha bagi pengemudi moda tradisional agar mereka beralih profesi.", val: 0}, {text: "Mewajibkan seluruh pengemudi moda tradisional untuk mengganti armada mereka dengan kendaraan listrik.", val: 0}] },
{ text: "Sebuah daerah sedang mengembangkan pusat perkantoran pemerintahan baru dengan konsep smart building yang sangat hemat energi dan menggunakan teknologi material terbaru. Namun, para ahli budaya lokal mengingatkan bahwa desain bangunan tersebut sepenuhnya mengabaikan filosofi tata ruang tradisional yang selama ini diyakini masyarakat sebagai penyeimbang hubungan manusia dengan alam. Sebagai pengambil kebijakan, tindakan yang paling mencerminkan filosofi Bhinneka Tunggal Ika adalah...", options: [{text: "Melanjutkan pembangunan sesuai desain awal karena efisiensi energi adalah prioritas utama masa depan.", val: 0}, {text: "Menghentikan proyek tersebut dan membangun kembali dengan gaya tradisional murni tanpa teknologi modern.", val: 0}, {text: "Melakukan modifikasi desain yang mengadopsi prinsip filosofi lokal ke dalam struktur bangunan modern.", val: 5}, {text: "Meminta tokoh budaya untuk membuat upacara ritual saja tanpa perlu mengubah desain bangunan.", val: 0}, {text: "Membangun monumen kecil di depan gedung sebagai simbol penghormatan terhadap budaya lokal.", val: 0}] },
];

const twk_Pancasila = [
{ text: "Sebuah perusahaan teknologi multinasional menawarkan investasi besar untuk membangun infrastruktur pusat data di Indonesia dengan syarat pemerintah memberikan akses eksklusif terhadap pengelolaan data strategis nasional demi efisiensi operasional. Di satu sisi, investasi ini sangat dibutuhkan untuk mempercepat transformasi ekonomi digital dan menyerap tenaga kerja lokal di tengah persaingan global yang ketat, namun di sisi lain, terdapat risiko ketergantungan teknologi dan kerentanan keamanan data warga negara. Menghadapi dilema ini, langkah yang paling mencerminkan pengamalan prinsip persatuan dan kedaulatan bangsa dalam kerangka Pancasila adalah...", options: [{text: "Menerima investasi dengan syarat perusahaan wajib mempekerjakan tenaga ahli lokal sebanyak mungkin.", val: 0}, {text: "Menolak investasi secara tegas demi menjaga martabat dan harga diri bangsa dari dominasi asing.", val: 0}, {text: "Menyetujui kerjasama namun tetap memegang kendali penuh atas regulasi dan enkripsi data nasional.", val: 5}, {text: "Melakukan negosiasi ulang agar pembagian keuntungan ekonomi lebih besar bagi kas negara.", val: 0}, {text: "Meminta pendapat publik melalui survei sebelum mengambil keputusan terkait investasi asing.", val: 0}] },
{ text: "Seorang pejabat pengadaan barang dan jasa di tingkat daerah menemukan bahwa alokasi anggaran untuk subsidi pupuk bagi petani kecil tahun ini mengalami pemotongan signifikan karena dialihkan untuk pembiayaan proyek mercusuar fisik di pusat kota. Meskipun proyek fisik tersebut memiliki nilai estetika tinggi dan didukung oleh pimpinan daerah, kebijakan ini berpotensi menyebabkan kelangkaan pupuk yang akan menghantam ekonomi ribuan keluarga petani di wilayah pelosok. Sebagai ASN yang menjunjung tinggi nilai keadilan sosial, tindakan yang paling tepat untuk diambil dalam situasi ini adalah...", options: [{text: "Melaksanakan perintah pimpinan sepenuhnya karena kepatuhan adalah prinsip utama seorang ASN.", val: 0}, {text: "Melakukan koordinasi untuk mencari sumber pendanaan alternatif guna menambal kekurangan subsidi.", val: 0}, {text: "Memberikan saran teknis berbasis data mengenai urgensi subsidi bagi stabilitas ekonomi masyarakat.", val: 5}, {text: "Mengajak rekan kerja untuk memprotes kebijakan tersebut agar pimpinan membatalkan proyek fisik.", val: 0}, {text: "Menjalankan tugas dengan sebaik-baiknya sambil memastikan sisa anggaran tersalurkan tepat sasaran.", val: 0}] },
{ text: "Pemerintah berencana merelokasi pasar tradisional yang kumuh menjadi kawasan pusat bisnis modern demi meningkatkan Pendapatan Asli Daerah (PAD). Namun, sebagian besar pedagang menolak karena khawatir akan biaya sewa yang mahal dan hilangnya ikatan sosial di lokasi lama, meski pemerintah telah menjamin fasilitas yang lebih bersih dan aman. Dalam semangat kerakyatan yang dipimpin oleh hikmat kebijaksanaan, cara terbaik untuk menyelesaikan konflik kepentingan ini agar mencapai mufakat yang berkualitas adalah...", options: [{text: "Menunda proyek tersebut sampai seluruh pedagang tanpa terkecuali menyetujui rencana pemerintah.", val: 0}, {text: "Melakukan sosialisasi searah secara masif untuk meyakinkan pedagang tentang manfaat pembangunan.", val: 0}, {text: "Menunjuk perwakilan pedagang untuk menandatangani kesepakatan tanpa perlu melibatkan massa.", val: 0}, {text: "Membuka ruang dialog partisipatif untuk merumuskan skema harga sewa yang terjangkau bagi pedagang.", val: 5}, {text: "Memberikan kompensasi uang tunai yang besar sebagai ganti rugi agar pedagang bersedia pindah segera.", val: 0}] },
{ text: "Seorang aparatur sipil negara (ASN) di bagian pelayanan perizinan dihadapkan pada situasi di mana seorang warga lanjut usia memohon percepatan izin usaha kecil demi membiayai pengobatan anaknya yang kritis. Secara prosedural, permohonan tersebut harus menunggu antrean selama dua minggu, namun sistem digital memungkinkan adanya intervensi manual untuk kasus darurat dengan persetujuan atasan yang saat itu sedang dinas luar kota. Di satu sisi, ASN tersebut harus taat pada Standar Operasional Prosedur (SOP) demi keadilan administratif, namun di sisi lain, nilai kemanusiaan menuntut tindakan segera. Tindakan yang paling mencerminkan internalisasi nilai keberadaban dan integritas adalah...", options: [{text: "Menolak permohonan tersebut secara sopan demi menjaga integritas sistem dan antrean publik.", val: 0}, {text: "Memberikan bantuan materiil pribadi kepada warga tersebut tanpa mengubah prosedur perizinan.", val: 0}, {text: "Melaporkan urgensi kasus tersebut kepada atasan melalui kanal digital untuk mendapatkan diskresi sah.", val: 5}, {text: "Mengarahkan warga tersebut untuk mencari bantuan ke lembaga sosial agar beban biaya pengobatan tertutupi.", val: 0}, {text: "Mempercepat proses perizinan secara diam-diam karena alasan kemanusiaan jauh lebih mulia dari prosedur.", val: 0}] },
{ text: "Di sebuah instansi pemerintah, berkembang diskusi hangat di antara para pegawai mengenai gerakan ideologi transnasional yang menawarkan sistem tata negara berbasis agama tertentu sebagai solusi atas kemiskinan dan ketidakadilan. Beberapa rekan kerja mulai terpengaruh dan menganggap bahwa ideologi tersebut lebih relevan dibanding Pancasila karena dianggap lebih religius. Sebagai seorang ASN yang memegang teguh nilai Ketuhanan Yang Maha Esa dalam bingkai keberagaman, sikap yang paling menunjukkan pemahaman substansial terhadap konsensus nasional adalah...", options: [{text: "Melaporkan rekan kerja tersebut kepada pihak keamanan agar segera diberikan sanksi pemecatan.", val: 0}, {text: "Menghindari perdebatan tersebut demi menjaga harmoni dan kedamaian di lingkungan kerja.", val: 0}, {text: "Menegaskan bahwa Pancasila adalah alat pemersatu yang mengakomodasi nilai agama dalam ruang publik.", val: 5}, {text: "Mempelajari ideologi tersebut secara mendalam untuk mencari titik temu dengan nilai-nilai Pancasila.", val: 0}, {text: "Mengusulkan diskusi formal dengan ahli ideologi untuk menguji validitas argumentasi rekan tersebut.", val: 0}] },
{ text: "Pemerintah pusat menetapkan sebuah wilayah pesisir sebagai Kawasan Strategis Pariwisata Nasional yang diproyeksikan menarik investasi asing dalam jumlah besar dan meningkatkan devisa negara. Namun, proyek ini berisiko membatasi akses nelayan tradisional terhadap area tangkap yang telah mereka kelola secara turun-temurun, yang berpotensi memicu ketimpangan ekonomi jangka panjang antara investor dan penduduk asli. Dalam perspektif keadilan sosial bagi seluruh rakyat Indonesia, kebijakan yang paling tepat untuk menjamin keseimbangan kepentingan adalah...", options: [{text: "Memberikan pelatihan keterampilan kerja di sektor perhotelan bagi seluruh nelayan yang terdampak.", val: 0}, {text: "Memastikan adanya zonasi eksklusif bagi nelayan tradisional di tengah kawasan pariwisata modern.", val: 5}, {text: "Mengalihkan seluruh nelayan ke wilayah tangkap baru yang lebih jauh dengan bantuan modal kapal.", val: 0}, {text: "Mengharuskan investor menyetorkan sebagian keuntungan langsung ke rekening warga lokal setiap bulan.", val: 0}, {text: "Membatalkan proyek pariwisata jika terdapat satu pun kelompok warga yang merasa keberatan.", val: 0}] },
{ text: "Sebuah instansi pemerintah sedang menguji coba sistem kecerdasan buatan (AI) untuk melakukan seleksi awal penerimaan bantuan sosial agar lebih akurat dan bebas nepotisme. Namun, hasil audit internal menunjukkan bahwa algoritma tersebut secara tidak sengaja mendiskriminasi kelompok masyarakat di wilayah terpencil karena minimnya data digital mereka di masa lalu. Sebagai pejabat yang bertanggung jawab, di tengah desakan untuk segera meluncurkan sistem demi efisiensi anggaran, langkah yang paling mencerminkan kebijaksanaan dalam permusyawaratan adalah...", options: [{text: "Tetap meluncurkan sistem sesuai jadwal sambil memperbaiki data secara bertahap di masa depan.", val: 0}, {text: "Membatalkan penggunaan AI dan kembali ke sistem manual untuk menjamin keadilan bagi warga terpencil.", val: 0}, {text: "Mengadakan konsultasi publik dengan perwakilan warga terdampak untuk merumuskan parameter koreksi algoritma.", val: 5}, {text: "Memberikan pengecualian khusus bagi warga terpencil dengan melakukan verifikasi fisik secara terpisah.", val: 0}, {text: "Menugaskan tim teknis untuk meningkatkan akurasi data tanpa perlu menunda waktu peluncuran sistem.", val: 0}] },
{ text: "Pemerintah sedang gencar mendorong hilirisasi industri dengan melarang ekspor bahan mentah demi meningkatkan nilai tambah dalam negeri. Kebijakan ini mendapat protes keras dari organisasi dagang internasional yang mengancam akan menjatuhkan sanksi ekonomi yang dapat berdampak pada kenaikan harga barang impor di pasar domestik. Sebagai ASN yang bertugas di bidang ekonomi, cara pandang yang paling sesuai dengan semangat keadilan sosial dalam merespons tekanan tersebut adalah...", options: [{text: "Menyarankan pelonggaran kebijakan ekspor secara terbatas untuk menghindari sanksi internasional.", val: 0}, {text: "Memperkuat kolaborasi industri dalam negeri agar mampu mengolah bahan mentah secara mandiri dan kompetitif.", val: 5}, {text: "Memberikan subsidi besar bagi masyarakat agar daya beli tetap terjaga saat terjadi kenaikan harga barang.", val: 0}, {text: "Fokus pada kampanye nasionalisme agar masyarakat bersedia menderita demi kedaulatan ekonomi jangka panjang.", val: 0}, {text: "Mengajukan gugatan balik ke pengadilan internasional sebagai bentuk perlawanan terhadap dominasi asing.", val: 0}] },
{ text: "Dalam sebuah rapat koordinasi lintas instansi, terjadi perbedaan tajam antara kelompok yang menginginkan pendekatan keamanan ketat dalam menangani konflik lahan dan kelompok yang menginginkan pendekatan dialog budaya. Perdebatan ini mulai mengarah pada sentimen identitas yang dapat memicu keretakan kerja sama antar lembaga. Sebagai penengah yang menjunjung tinggi nilai persatuan, sikap yang paling menunjukkan integritas bangsa adalah...", options: [{text: "Meminta kedua pihak untuk mengesampingkan perbedaan dan mengikuti instruksi pimpinan tertinggi.", val: 0}, {text: "Mengusulkan pembentukan tim independen yang terdiri dari pakar hukum untuk memutus perkara secara adil.", val: 0}, {text: "Merumuskan pendekatan terpadu yang menyinergikan aspek kepastian hukum dengan kearifan lokal.", val: 5}, {text: "Mendukung pihak yang memiliki dasar hukum paling kuat agar konflik tidak berlarut-larut secara teknis.", val: 0}, {text: "Menyarankan agar pembahasan dihentikan sementara sampai suasana emosional mendingin kembali.", val: 0}] },
{ text: "Sebagai anggota tim siber nasional, Anda menemukan adanya celah keamanan pada sistem data kependudukan yang sangat rahasia. Jika Anda segera menutup celah tersebut secara sepihak, proses pembaruan sistem akan terhenti dan menyebabkan gangguan layanan publik nasional selama 24 jam. Namun, jika Anda melaporkannya melalui jalur birokrasi formal, proses verifikasi yang lambat berisiko dimanfaatkan oleh pihak luar untuk mencuri data sensitif warga negara sebelum tindakan diambil. Mengingat ancaman terhadap integritas kedaulatan data di tengah desakan efisiensi layanan, langkah yang paling tepat adalah...", options: [{text: "Menutup celah keamanan seketika meskipun layanan publik terhenti demi menjamin perlindungan data rakyat.", val: 0}, {text: "Melakukan perbaikan sementara secara bertahap sambil terus berkoordinasi melalui jalur birokrasi resmi.", val: 0}, {text: "Mengambil tindakan teknis darurat untuk mengamankan data sambil menyiapkan jalur mitigasi bagi layanan publik.", val: 5}, {text: "Menunggu instruksi resmi dari pimpinan agar tindakan yang diambil memiliki landasan hukum yang kuat.", val: 0}, {text: "Menyebarkan peringatan kepada publik agar warga waspada terhadap potensi kebocoran data pribadi mereka.", val: 0}] },
{ text: "Pemerintah berkomitmen melakukan transisi energi hijau dengan menutup tambang batu bara di sebuah daerah untuk dialihkan menjadi kawasan hutan lindung dan energi terbarukan. Kebijakan ini merupakan langkah krusial untuk menghadapi krisis iklim global, namun berdampak langsung pada hilangnya mata pencaharian ribuan buruh tambang lokal yang tidak memiliki keahlian di bidang lain. Menghadapi pertentangan antara penyelamatan lingkungan global dan kelangsungan hidup warga lokal, solusi yang paling mencerminkan prinsip keadilan sosial adalah...", options: [{text: "Tetap melanjutkan penutupan tambang demi komitmen lingkungan dengan memberikan pesangon tunai yang besar.", val: 0}, {text: "Menunda penutupan tambang sampai seluruh buruh tambang mencapai usia pensiun agar tidak ada pemecatan.", val: 0}, {text: "Mewajibkan perusahaan energi terbarukan yang baru untuk mengalokasikan sahamnya kepada warga lokal.", val: 0}, {text: "Merancang program transisi ekonomi yang mengintegrasikan pelatihan keterampilan baru dengan pembukaan lapangan kerja hijau.", val: 5}, {text: "Memberikan hak kelola lahan hutan lindung kepada warga lokal untuk dijadikan kawasan wisata mandiri.", val: 0}] },
{ text: "Di sebuah daerah pelosok yang masih memegang teguh adat istiadat tertentu, Anda bertugas sebagai tenaga kesehatan ASN. Terdapat sebuah prosedur medis darurat yang harus segera dilakukan untuk menyelamatkan nyawa seorang warga, namun tokoh adat setempat menolak karena prosedur tersebut dianggap melanggar aturan tak tertulis warisan leluhur. Jika Anda memaksa, akan terjadi konflik sosial yang besar antara instansi pemerintah dan warga desa, namun jika Anda membiarkan, nyawa pasien tidak tertolong. Tindakan yang paling menunjukkan nilai kemanusiaan yang adil dan beradab adalah...", options: [{text: "Menghargai keputusan tokoh adat dan keluarga sebagai bentuk penghormatan terhadap kearifan lokal.", val: 0}, {text: "Melakukan prosedur medis secara diam-diam tanpa sepengetahuan tokoh adat demi keselamatan pasien.", val: 0}, {text: "Mengajak tokoh adat berdialog secara persuasif dengan melibatkan pihak yang mereka percayai untuk mencari jalan tengah medis.", val: 5}, {text: "Meminta bantuan aparat keamanan untuk mengawal jalannya prosedur medis agar tidak terjadi perlawanan.", val: 0}, {text: "Mengalihkan tanggung jawab kepada fasilitas kesehatan di daerah lain yang lebih terbuka secara budaya.", val: 0}] },
{ text: "Seorang analis data di kementerian ekonomi menemukan adanya indikasi kuat bahwa salah satu komoditas pangan utama akan mengalami lonjakan harga ekstrem dalam tiga bulan ke depan akibat kegagalan panen di beberapa wilayah sentral. Jika informasi ini dibuka sepenuhnya kepada publik sekarang, dikhawatirkan akan terjadi aksi borong (panic buying) yang justru mempercepat kelangkaan dan inflasi. Namun, jika informasi ini dirahasiakan, petani dan pelaku usaha kecil tidak memiliki waktu untuk melakukan mitigasi mandiri. Tindakan yang paling tepat dalam kerangka keadilan sosial bagi seluruh rakyat adalah...", options: [{text: "Membuka data tersebut secara transparan di media massa agar publik dapat bersiap secara mandiri sejak dini.", val: 0}, {text: "Merahasiakan data dari publik sambil berkoordinasi dengan perusahaan besar untuk mengamankan stok pangan nasional.", val: 0}, {text: "Menyusun rekomendasi kebijakan intervensi pasar dan bantuan sosial sebelum mengumumkan situasi secara terukur.", val: 5}, {text: "Fokus melakukan kampanye diversifikasi pangan kepada masyarakat agar ketergantungan pada satu komoditas berkurang.", val: 0}, {text: "Menunggu instruksi pimpinan terkait waktu yang tepat untuk merilis data guna menghindari tanggung jawab pribadi.", val: 0}] },
{ text: "Indonesia sedang menjalin kerja sama investasi infrastruktur yang sangat vital dengan sebuah negara tetangga. Namun, di saat yang sama, kapal nelayan dan patroli dari negara tersebut sering kali melakukan pelanggaran batas wilayah di perairan kaya sumber daya milik Indonesia dengan alasan klaim historis. Jika Indonesia bertindak terlalu keras secara militer, investasi tersebut terancam batal dan ekonomi daerah perbatasan akan terhenti. Jika bersikap pasif, kedaulatan wilayah akan perlahan tergerus. Sikap yang paling mencerminkan prinsip persatuan dan kedaulatan bangsa adalah...", options: [{text: "Menghentikan seluruh kerja sama ekonomi sampai negara tersebut meminta maaf dan mengakui batas wilayah.", val: 0}, {text: "Mengalihkan area penangkapan nelayan lokal ke wilayah lain yang lebih aman guna menghindari konflik fisik.", val: 0}, {text: "Meningkatkan patroli keamanan di wilayah perbatasan sambil tetap menjalankan jalur diplomasi formal yang tegas.", val: 5}, {text: "Menerima klaim historis tersebut secara informal asalkan kompensasi investasi yang diberikan ditingkatkan.", val: 0}, {text: "Menugaskan kementerian terkait untuk fokus pada pembangunan ekonomi agar warga perbatasan tidak bergantung pada laut.", val: 0}] },
{ text: "Di sebuah platform media sosial internal instansi, seorang pegawai mengunggah opini pribadi yang menyudutkan ritual keagamaan tertentu dengan dalih kebebasan berpendapat dan rasionalitas. Unggahan tersebut memicu perdebatan panas dan mulai mengganggu produktivitas serta suasana kerja antarpegawai yang berbeda keyakinan. Sebagai rekan kerja yang menjunjung tinggi nilai Ketuhanan Yang Maha Esa dalam kerangka Bhinneka Tunggal Ika, langkah paling bijaksana yang dapat dilakukan untuk mendinginkan suasana tanpa melanggar hak individu adalah...", options: [{text: "Melaporkan pegawai tersebut kepada tim disiplin agar segera diberikan sanksi administratif yang berat.", val: 0}, {text: "Menghapus komentar-komentar yang saling menyerang secara manual agar diskusi tersebut hilang dari linimasa.", val: 0}, {text: "Mengajak pegawai tersebut berdialog secara pribadi tentang pentingnya menghargai ruang publik yang inklusif.", val: 5}, {text: "Mendukung argumen pegawai tersebut jika secara logika benar agar kebebasan berpendapat tetap terjamin.", val: 0}, {text: "Mengabaikan unggahan tersebut dan meminta rekan kerja lain untuk tidak terpancing emosi agar suasana kondusif.", val: 0}] },
{ text: "Indonesia memiliki cadangan mineral strategis yang sangat besar yang menjadi incaran banyak negara maju untuk industri baterai kendaraan listrik global. Namun, untuk mengolahnya di dalam negeri, diperlukan investasi besar yang menyebabkan ketergantungan pada teknologi satu negara tertentu yang memiliki sejarah konflik kepentingan dengan Indonesia. Jika pemerintah membuka keran ekspor mentah, ekonomi akan tumbuh instan namun kedaulatan industri jangka panjang terancam. Jika memaksa hilirisasi dengan negara tersebut, risiko intervensi politik meningkat. Langkah yang paling mencerminkan prinsip persatuan dan kedaulatan bangsa adalah...", options: [{text: "Melarang total ekspor mineral tersebut dan menunggu sampai putra daerah mampu menciptakan teknologi pengolahan sendiri.", val: 0}, {text: "Membuka kerja sama dengan berbagai negara secara kompetitif untuk menghindari ketergantungan pada satu kekuatan dominan.", val: 5}, {text: "Menyetujui syarat negara investor tersebut asalkan mereka memberikan jaminan tidak akan mencampuri urusan dalam negeri.", val: 0}, {text: "Mengutamakan pertumbuhan ekonomi jangka pendek melalui ekspor mentah guna memperkuat cadangan devisa negara.", val: 0}, {text: "Menyerahkan pengelolaan sumber daya tersebut kepada pihak swasta nasional sepenuhnya tanpa campur tangan pemerintah.", val: 0}] },
{ text: "Sebuah perusahaan besar sedang melakukan pembangunan proyek infrastruktur strategis nasional di atas tanah yang secara administratif sah milik negara, namun secara spiritual dianggap keramat oleh suku asli setempat. Masyarakat menolak pembangunan tersebut meskipun perusahaan menjanjikan lapangan kerja luas dan pembangunan sekolah. Sebagai ASN yang ditugaskan sebagai mediator, tindakan yang paling menunjukkan penghormatan terhadap kemanusiaan yang adil dan beradab adalah...", options: [{text: "Menjalankan pembangunan sesuai hukum karena legalitas negara harus berada di atas kepercayaan kelompok tertentu.", val: 0}, {text: "Memberikan ganti rugi berupa uang dalam jumlah sangat besar agar masyarakat bersedia melepaskan tanah keramatnya.", val: 0}, {text: "Memfasilitasi dialog untuk mencari penyesuaian desain proyek yang dapat melindungi area keramat tanpa membatalkan pembangunan.", val: 5}, {text: "Meminta tokoh masyarakat setempat untuk meyakinkan warganya bahwa kemajuan ekonomi jauh lebih penting dari tradisi.", val: 0}, {text: "Menunda proyek tersebut tanpa batas waktu untuk menghindari terjadinya gesekan fisik yang merusak citra pemerintah.", val: 0}] },
{ text: "Kementerian Anda mulai menggunakan sistem pemeringkatan otomatis bagi penerima beasiswa pendidikan berdasarkan algoritma yang menilai prestasi dan kondisi ekonomi. Namun, ditemukan fakta bahwa sistem tersebut secara otomatis memberi skor rendah bagi pelamar dari daerah tertinggal karena kualitas akreditasi sekolah mereka yang rendah, meskipun secara individu mereka adalah siswa terbaik di daerahnya. Kondisi ini menyebabkan beasiswa tetap menumpuk pada pelajar di kota besar. Sebagai pengambil kebijakan, langkah yang paling sesuai dengan semangat keadilan sosial adalah...", options: [{text: "Mempertahankan algoritma tersebut karena objektivitas data adalah kunci utama dalam mencegah korupsi.", val: 0}, {text: "Menghapus sistem otomatisasi dan kembali menggunakan penilaian manual sepenuhnya demi keadilan personal.", val: 0}, {text: "Menambahkan variabel indeks kesulitan wilayah ke dalam algoritma untuk memberikan bobot tambahan bagi pelamar dari daerah tertinggal.", val: 5}, {text: "Memberikan kuota khusus bagi pelamar dari kota besar yang gagal lolos agar tidak terjadi kecemburuan sosial.", val: 0}, {text: "Menyarankan siswa di daerah tertinggal untuk pindah ke sekolah di kota besar agar bisa bersaing di sistem tersebut.", val: 0}] },
{ text: "Sebuah wilayah di negara tetangga mengalami konflik saudara yang hebat, menyebabkan ribuan pengungsi masuk ke wilayah perairan Indonesia secara ilegal menggunakan kapal kayu yang tidak layak. Jika pemerintah menerima mereka, dikhawatirkan akan muncul gesekan sosial dengan warga lokal yang juga masih hidup dalam kemiskinan, serta beban anggaran yang besar. Namun, jika kapal-kapal tersebut dipukul mundur ke laut lepas, risiko kematian massal di lautan sangat tinggi dan mencederai citra Indonesia sebagai bangsa yang menjunjung kemanusiaan. Dalam perspektif persatuan dan martabat bangsa, tindakan yang paling tepat adalah...", options: [{text: "Menolak masuknya pengungsi demi menjaga stabilitas ekonomi dan keamanan warga negara sendiri.", val: 0}, {text: "Menampung seluruh pengungsi di permukiman warga agar terjadi proses asimilasi budaya secara alami.", val: 0}, {text: "Menyediakan tempat penampungan sementara yang terisolasi sambil mendesak organisasi internasional untuk segera melakukan relokasi.", val: 5}, {text: "Memberikan bantuan logistik dan bahan bakar yang cukup di tengah laut agar mereka dapat melanjutkan perjalanan ke negara lain.", val: 0}, {text: "Menyerahkan keputusan sepenuhnya kepada pemerintah daerah setempat untuk menghindari konflik kebijakan pusat.", val: 0}] },
{ text: "Anda adalah pejabat pembuat komitmen dalam proyek pengadaan obat-obatan darurat untuk menangani wabah yang sedang meluas. Perusahaan yang menawarkan harga paling rendah dan kualitas terbaik ternyata dimiliki oleh kerabat jauh pimpinan instansi Anda. Meskipun proses lelang dilakukan secara transparan melalui sistem digital, publik mulai mencium potensi nepotisme yang dapat merusak citra instansi. Jika Anda membatalkan pemenang tersebut, pengadaan akan tertunda dan nyawa banyak orang terancam. Tindakan yang paling mencerminkan keberadaban dan integritas profesional adalah...", options: [{text: "Membatalkan hasil lelang untuk menjaga nama baik instansi dari tuduhan nepotisme publik.", val: 0}, {text: "Melanjutkan proses pengadaan karena secara prosedural legal dan demi menyelamatkan nyawa masyarakat.", val: 5}, {text: "Meminta perusahaan tersebut mengundurkan diri secara sukarela demi menjaga moralitas birokrasi.", val: 0}, {text: "Mengalihkan proses pengambilan keputusan kepada lembaga audit eksternal untuk menjamin objektivitas.", val: 0}, {text: "Mengumumkan secara terbuka hasil lelang beserta bukti kualitas dan harga untuk menunjukkan transparansi total.", val: 0}] },
{ text: "Pesatnya pertumbuhan ekonomi berbagi (sharing economy) melalui aplikasi transportasi dan pengantaran daring telah membuka jutaan lapangan kerja baru, namun di sisi lain menciptakan hubungan kerja yang rentan karena pengemudi dianggap sebagai mitra bukan karyawan, sehingga mereka tidak memiliki jaminan hari tua atau asuransi kesehatan yang memadai. Pemerintah ditekan untuk membuat regulasi yang ketat, namun jika regulasi terlalu berat bagi perusahaan teknologi, mereka mengancam akan melakukan PHK massal atau menaikkan tarif yang membebani konsumen luas. Langkah yang paling sesuai dengan keadilan sosial adalah...", options: [{text: "Membiarkan mekanisme pasar berjalan agar efisiensi ekonomi tetap terjaga bagi konsumen luas.", val: 0}, {text: "Mewajibkan perusahaan memberikan status karyawan tetap kepada seluruh mitra pengemudi tanpa pengecualian.", val: 0}, {text: "Merumuskan regulasi jaminan sosial khusus yang iurannya ditanggung bersama oleh perusahaan, mitra, dan subsidi negara.", val: 5}, {text: "Menyarankan pengemudi untuk mencari pekerjaan lain yang memiliki standar perlindungan hukum lebih baik.", val: 0}, {text: "Memberikan insentif pajak bagi perusahaan agar mereka secara sukarela meningkatkan kesejahteraan mitranya.", val: 0}] },
{ text: "Dalam sebuah audit internal, Anda menemukan bahwa atasan langsung Anda—yang selama ini sangat berjasa membantu karier Anda—telah mengalihkan dana bantuan sosial untuk kegiatan seremoni instansi agar terlihat berprestasi di mata publik. Atasan Anda berdalih bahwa hal ini dilakukan demi menjaga citra baik lembaga agar tetap dipercaya rakyat. Sebagai ASN yang menjunjung nilai kemanusiaan dan kejujuran, sikap yang paling tepat adalah...", options: [{text: "Mendukung kebijakan tersebut demi menjaga stabilitas dan nama baik instansi.", val: 0}, {text: "Melaporkan temuan tersebut melalui sistem pengaduan internal secara anonim.", val: 5}, {text: "Menegur atasan secara pribadi agar mengembalikan dana tersebut tanpa melapor.", val: 0}, {text: "Fokus menjalankan tugas sendiri karena bukan kewenangan Anda untuk mengaudit.", val: 0}, {text: "Meminta pindah divisi agar tidak terlibat dalam konflik kepentingan tersebut.", val: 0}] },
{ text: "Pemerintah berencana mendigitalisasi seluruh sistem pembayaran transportasi publik di sebuah kota untuk meningkatkan transparansi dan efisiensi anggaran. Namun, kebijakan ini secara teknis akan memutus akses bagi kelompok warga lanjut usia dan masyarakat ekonomi bawah yang tidak memiliki ponsel pintar. Demi mewujudkan keadilan sosial, kebijakan pendamping yang paling tepat untuk diambil adalah...", options: [{text: "Menunda digitalisasi sampai seluruh warga memiliki ponsel pintar.", val: 0}, {text: "Tetap menjalankan digitalisasi penuh untuk mendidik masyarakat.", val: 0}, {text: "Menyediakan kartu pembayaran fisik yang dapat dibeli secara tunai di berbagai titik.", val: 5}, {text: "Memberikan bantuan ponsel gratis bagi seluruh warga yang tidak mampu.", val: 0}, {text: "Membebaskan biaya perjalanan khusus bagi warga yang belum melek teknologi.", val: 0}] },
{ text: "Sebuah perusahaan raksasa dari luar negeri bersedia membangun industri manufaktur di wilayah terpencil Indonesia dengan syarat mereka diizinkan membawa seluruh tenaga kerja, termasuk pekerja kasar, dari negara asal dengan alasan percepatan pembangunan. Pemerintah daerah sangat menginginkan proyek ini untuk menaikkan pertumbuhan ekonomi lokal yang stagnan. Sikap yang paling mencerminkan prinsip persatuan dan kedaulatan bangsa adalah...", options: [{text: "Menyetujui syarat tersebut sepenuhnya agar investasi tetap masuk dan ekonomi tumbuh.", val: 0}, {text: "Menolak investasi tersebut karena mengancam kesempatan kerja bagi warga lokal.", val: 0}, {text: "Menegosiasikan kuota tenaga kerja asing hanya untuk posisi ahli yang tidak tersedia di dalam negeri.", val: 5}, {text: "Meminta investor memberikan kompensasi berupa dana hibah sebagai ganti penggunaan tenaga asing.", val: 0}, {text: "Menyerahkan keputusan sepenuhnya kepada masyarakat lokal melalui pemungutan suara.", val: 0}] },
{ text: "Sebuah lembaga riset internasional menawarkan hibah sistem deteksi bencana berbasis satelit canggih yang sangat dibutuhkan Indonesia untuk meminimalisir korban jiwa. Namun, sistem tersebut mewajibkan Indonesia membagi seluruh data topografi dan aktivitas bawah laut secara real-time ke server pusat mereka di luar negeri dengan alasan kalibrasi sensor. Sebagai pengambil kebijakan, langkah yang paling mencerminkan prinsip kedaulatan bangsa adalah...", options: [{text: "Menerima hibah tersebut karena keselamatan nyawa rakyat adalah hukum tertinggi.", val: 0}, {text: "Menolak hibah karena data topografi strategis berkaitan erat dengan pertahanan negara.", val: 0}, {text: "Menegosiasikan agar proses pengolahan data tetap berada di server lokal milik Indonesia.", val: 5}, {text: "Meminta pendapat pihak ketiga yang netral untuk menilai risiko keamanan data tersebut.", val: 0}, {text: "Menerima hibah sementara sambil membangun sistem serupa secara mandiri di dalam negeri.", val: 0}] },
{ text: "Di tengah situasi kelangkaan obat akibat gangguan distribusi global, sebuah rumah sakit pemerintah menerima bantuan obat esensial dalam jumlah besar dari organisasi swasta. Namun, obat tersebut belum memiliki izin edar resmi dari otoritas kesehatan nasional karena prosedur administrasi yang birokratis, meskipun telah teruji klinis di negara asalnya. Jika menunggu izin, risiko kematian pasien meningkat tajam. Tindakan yang paling mencerminkan nilai kemanusiaan yang beradab adalah...", options: [{text: "Menggunakan obat tersebut segera demi menyelamatkan nyawa pasien tanpa izin otoritas.", val: 0}, {text: "Menolak bantuan tersebut karena penggunaan obat tanpa izin melanggar hukum negara.", val: 0}, {text: "Mendorong otoritas kesehatan untuk mengeluarkan izin darurat (emergency use) secara cepat.", val: 5}, {text: "Meminta pasien atau keluarga menandatangani surat pernyataan risiko jika ingin menggunakan obat.", val: 0}, {text: "Menyimpan obat tersebut di gudang sampai izin edar resmi diterbitkan oleh pemerintah.", val: 0}] },
{ text: "Pemerintah menetapkan kebijakan pajak karbon tinggi bagi industri transportasi untuk menekan emisi gas rumah kaca sesuai komitmen global. Dampaknya, biaya logistik naik dan menyebabkan harga kebutuhan pokok di wilayah pelosok yang bergantung pada distribusi darat meningkat drastis, sehingga membebani daya beli masyarakat miskin. Dalam perspektif keadilan sosial, kebijakan penyeimbang yang paling tepat adalah...", options: [{text: "Memberikan pengecualian pajak karbon bagi seluruh perusahaan logistik nasional.", val: 0}, {text: "Menurunkan target komitmen lingkungan global agar harga kebutuhan pokok tetap stabil.", val: 0}, {text: "Mengalihkan pendapatan pajak karbon untuk subsidi langsung distribusi logistik wilayah pelosok.", val: 5}, {text: "Menyarankan masyarakat pelosok untuk beralih ke sumber pangan lokal guna menghindari inflasi.", val: 0}, {text: "Menyerahkan mekanisme harga sepenuhnya kepada pasar agar terjadi keseimbangan baru.", val: 0}] },
{ text: "Indonesia terpilih menjadi tuan rumah ajang olahraga internasional yang diprediksi meningkatkan ekonomi sektor pariwisata secara signifikan. Namun, lembaga penyelenggara dunia menuntut syarat agar bendera satu negara yang sedang berkonflik secara politik dengan Indonesia tetap dikibarkan, meski hal ini berpotensi memicu demonstrasi besar di dalam negeri. Dalam bingkai menjaga kedaulatan dan martabat bangsa, sikap yang paling tepat adalah...", options: [{text: "Membatalkan status tuan rumah demi menjaga stabilitas dan perasaan rakyat Indonesia.", val: 0}, {text: "Menyetujui syarat tersebut sepenuhnya agar ekonomi nasional tumbuh melalui pariwisata.", val: 0}, {text: "Menerima syarat tersebut sambil melakukan edukasi publik mengenai komitmen diplomasi internasional.", val: 5}, {text: "Meminta lembaga dunia memberikan pengecualian khusus demi menghormati posisi politik Indonesia.", val: 0}, {text: "Mengizinkan pengibaran bendera hanya di area terbatas yang tidak terjangkau oleh kamera publik.", val: 0}] },
{ text: "Dalam upaya meningkatkan penerimaan pajak negara, pemerintah menerapkan sistem pemantauan aset otomatis melalui teknologi perbankan. Namun, sistem ini hanya efektif memantau pelaku usaha formal, sementara pelaku usaha sektor informal yang berpenghasilan tinggi namun tidak terdaftar tetap tidak tersentuh pajak. Sebagai pejabat fiskal, langkah yang paling mencerminkan prinsip keadilan sosial adalah...", options: [{text: "Menangguhkan sistem tersebut sampai seluruh sektor informal berhasil masuk dalam basis data.", val: 0}, {text: "Meningkatkan tarif pajak bagi sektor formal untuk menutupi potensi kerugian dari sektor informal.", val: 0}, {text: "Menjalankan sistem yang ada sambil mempercepat integrasi data sektor informal ke dalam sistem perpajakan.", val: 5}, {text: "Memberikan insentif berupa potongan pajak bagi sektor formal karena telah dipantau secara ketat.", val: 0}, {text: "Fokus pada edukasi kesadaran pajak tanpa perlu melakukan pemantauan ketat yang merusak privasi.", val: 0}] },
{ text: "Sebuah kota berencana menerapkan aturan kendaraan listrik di pusat kota demi mengurangi polusi udara yang sudah di level berbahaya. Namun, ribuan pengemudi transportasi konvensional melakukan protes karena mereka tidak memiliki modal untuk mengganti armada. Dalam semangat hikmat kebijaksanaan, langkah yang paling tepat diambil oleh pemerintah daerah adalah...", options: [{text: "Tetap memberlakukan aturan tersebut demi kesehatan publik yang merupakan kepentingan lebih luas.", val: 0}, {text: "Membatalkan aturan kendaraan listrik sampai seluruh pengemudi siap secara ekonomi.", val: 0}, {text: "Menyediakan skema kredit bersubsidi atau kerja sama pengelolaan armada bagi pengemudi terdampak.", val: 5}, {text: "Memberikan kompensasi uang tunai satu kali agar para pengemudi dapat mencari pekerjaan lain.", val: 0}, {text: "Menyerahkan urusan tersebut kepada mekanisme pasar untuk menentukan pemenangnya.", val: 0}] },
{ text: "Indonesia memiliki cadangan karbon yang besar melalui hutan hujan tropisnya. Sebuah konsorsium global menawarkan investasi hijau bernilai fantastis untuk restorasi hutan, namun dengan syarat mereka memiliki hak eksklusif untuk memperdagangkan kredit karbon tersebut di pasar internasional tanpa intervensi regulasi harga dari pemerintah Indonesia. Di tengah kebutuhan dana untuk pemulihan ekonomi, langkah yang paling mencerminkan prinsip kedaulatan bangsa adalah...", options: [{text: "Menerima investasi tersebut sepenuhnya karena restorasi hutan adalah prioritas kemanusiaan global.", val: 0}, {text: "Menolak investasi karena hak eksklusif pihak asing atas sumber daya alam melanggar kedaulatan negara.", val: 0}, {text: "Menegosiasikan skema bagi hasil dan kendali pemerintah atas batas minimum harga karbon nasional.", val: 5}, {text: "Meminta lembaga internasional lain untuk memberikan hibah tanpa syarat agar hutan tetap terjaga.", val: 0}, {text: "Menyerahkan urusan perdagangan karbon kepada mekanisme pasar bebas agar nilai investasinya maksimal.", val: 0}] },
{ text: "Sebuah industri manufaktur besar yang mempekerjakan puluhan ribu buruh terancam bangkrut akibat perubahan pola konsumsi digital. Pemerintah mempertimbangkan untuk memberikan dana talangan (bailout) dari APBN untuk menyelamatkan perusahaan tersebut agar tidak terjadi PHK massal. Namun, langkah ini diprotes oleh pelaku UMKM yang merasa tidak pernah mendapatkan bantuan serupa saat mereka kesulitan. Kebijakan yang paling sesuai dengan semangat keadilan sosial adalah...", options: [{text: "Memberikan dana talangan kepada perusahaan besar tersebut karena skala dampaknya yang luas bagi ekonomi.", val: 0}, {text: "Menolak memberikan dana talangan agar terjadi kompetisi pasar yang sehat dan adil bagi semua pelaku usaha.", val: 0}, {text: "Memberikan pinjaman lunak bagi industri tersebut dengan syarat wajib melakukan transformasi digital dan menyerap produk UMKM.", val: 5}, {text: "Membiarkan perusahaan tersebut bangkrut dan fokus memberikan tunjangan pengangguran bagi buruh yang terkena PHK.", val: 0}, {text: "Menjual aset perusahaan tersebut kepada investor asing agar dana hasil penjualan bisa dibagikan kepada buruh.", val: 0}] },
{ text: "Dalam rapat penentuan lokasi pembangunan bendungan, mayoritas warga desa yang tinggal di daerah aliran sungai setuju karena akan mendapatkan ganti rugi yang menguntungkan. Namun, sekelompok kecil warga yang tinggal di hulu menolak karena bendungan tersebut akan menenggelamkan situs pemakaman leluhur mereka yang memiliki nilai sejarah tinggi. Dalam semangat hikmat kebijaksanaan, langkah terbaik yang harus diambil oleh pemimpin daerah adalah...", options: [{text: "Melanjutkan pembangunan sesuai keinginan mayoritas warga demi efisiensi dan kemajuan ekonomi.", val: 0}, {text: "Membatalkan proyek tersebut sepenuhnya untuk menghormati perasaan kelompok warga yang menolak.", val: 0}, {text: "Membuka ruang dialog untuk merumuskan teknis pemindahan situs yang layak atau penyesuaian desain bendungan.", val: 5}, {text: "Mengadakan pemungutan suara ulang (voting) untuk melegitimasi keputusan berdasarkan jumlah pendukung terbanyak.", val: 0}, {text: "Memberikan kompensasi materiil tambahan yang jauh lebih besar bagi warga yang situs leluhurnya terkena dampak.", val: 0}] },
{ text: "Seorang ASN bagian kepegawaian menemukan bahwa salah satu kandidat terbaik untuk posisi strategis memiliki hubungan kekerabatan dengan pimpinan tertinggi instansi. Meskipun kandidat tersebut memang yang paling kompeten berdasarkan skor ujian, publik akan tetap mencurigai adanya nepotisme jika ia terpilih. Langkah yang paling mencerminkan nilai kemanusiaan yang adil dan beradab adalah...", options: [{text: "Membatalkan kandidat tersebut demi menjaga citra instansi dari isu nepotisme.", val: 0}, {text: "Meluluskan kandidat tersebut karena ia adalah yang paling kompeten secara objektif.", val: 0}, {text: "Melakukan pengujian ulang secara terbuka yang melibatkan pihak eksternal sebagai saksi.", val: 5}, {text: "Menyarankan kandidat tersebut untuk melamar di instansi lain agar lebih aman.", val: 0}, {text: "Mengurangi poin kandidat tersebut secara sengaja agar persaingan terlihat lebih ketat.", val: 0}] },
{ text: "Sebuah provinsi di perbatasan memiliki ketergantungan ekonomi yang sangat tinggi pada negara tetangga, termasuk penggunaan mata uang asing dalam transaksi sehari-hari karena sulitnya akses distribusi rupiah. Pemerintah ingin mewajibkan penggunaan rupiah secara penuh, namun hal ini diprotes warga karena dikhawatirkan mengganggu perdagangan lintas batas yang menjadi tumpuan hidup mereka. Sikap yang paling tepat sesuai semangat persatuan adalah...", options: [{text: "Membiarkan penggunaan mata uang asing tetap berjalan demi stabilitas ekonomi warga.", val: 0}, {text: "Memberikan sanksi tegas bagi setiap warga yang masih bertransaksi dengan mata uang asing.", val: 0}, {text: "Mempercepat pembangunan infrastruktur distribusi dan perbankan sambil mewajibkan rupiah.", val: 5}, {text: "Menutup perbatasan secara total agar warga fokus pada pasar domestik di dalam negeri.", val: 0}, {text: "Mengizinkan penggunaan mata uang asing hanya untuk transaksi dengan pihak luar negeri saja.", val: 0}] },
{ text: "Pemerintah daerah meluncurkan aplikasi aspirasi publik untuk menampung keluhan warga secara langsung. Namun, fitur voting di aplikasi tersebut sering kali didominasi oleh kelompok pengguna internet tertentu yang terorganisir, sehingga kebijakan yang dihasilkan hanya menguntungkan kelompok tersebut dan mengabaikan aspirasi warga yang tidak memiliki akses internet. Langkah yang paling bijaksana sesuai prinsip kerakyatan adalah...", options: [{text: "Menjadikan hasil voting aplikasi sebagai satu-satunya dasar pengambilan kebijakan pemerintah.", val: 0}, {text: "Menghapus aplikasi tersebut karena dianggap tidak representatif terhadap seluruh warga.", val: 0}, {text: "Menggunakan data aplikasi sebagai referensi awal, namun tetap melakukan musyawarah tatap muka di lapangan.", val: 5}, {text: "Meminta warga yang tidak memiliki akses internet untuk segera belajar menggunakan aplikasi tersebut.", val: 0}, {text: "Hanya mendengarkan aspirasi yang masuk melalui surat fisik karena lebih sulit dimanipulasi.", val: 0}] },
];

const twk_NKRI = [
{ text: "Sebuah perusahaan rintisan teknologi nasional yang sedang berkembang pesat menghadapi dilema ketika sebagian besar investor menyarankan untuk memindahkan pusat operasional dan server mereka ke luar negeri demi efisiensi biaya dan kemudahan regulasi global. CEO perusahaan tersebut menyadari bahwa meskipun secara ekonomi menguntungkan, langkah ini berisiko mengurangi kemandirian data nasional dan melemahkan peran strategis putra-putri daerah dalam inovasi teknologi domestik. Di sisi lain, mempertahankan operasional di dalam negeri menuntut perjuangan ekstra dalam menghadapi birokrasi yang masih berbenah. Sikap manajerial yang paling tepat untuk merepresentasikan esensi menjaga keutuhan NKRI dalam dimensi kedaulatan digital adalah...", options: [{text: "Menolak seluruh tawaran investasi asing demi menjaga kemurnian aset bangsa.", val: 0}, {text: "Mengikuti saran investor sepenuhnya untuk menjamin keberlanjutan ekonomi perusahaan.", val: 0}, {text: "Mempertahankan server di dalam negeri sebagai wujud penguasaan aset strategis negara.", val: 5}, {text: "Meminta subsidi kepada pemerintah sebagai syarat untuk tetap bertahan di dalam negeri.", val: 0}, {text: "Memindahkan operasional secara bertahap sambil tetap merekrut tenaga kerja lokal.", val: 0}] },
{ text: "Seorang kepala daerah di wilayah perbatasan sering mendapati warga lokal lebih banyak melakukan transaksi menggunakan mata uang negara tetangga dan lebih memilih menyekolahkan anak-anak mereka di luar negeri karena akses fasilitas yang lebih dekat dan modern. Alih-alih melakukan tindakan represif atau sekadar memberikan bantuan sosial sementara, kepala daerah tersebut memutuskan untuk menginisiasi pembangunan pusat ekonomi kreatif dan kurikulum pendidikan yang berbasis pada keunggulan komoditas lokal yang terhubung langsung dengan pasar nasional. Tindakan ini mencerminkan penguatan konsep NKRI melalui pendekatan...", options: [{text: "Penyeragaman budaya agar identitas nasional tidak luntur oleh pengaruh asing.", val: 0}, {text: "Penguatan ketahanan nasional melalui integrasi kesejahteraan dan rasa memiliki.", val: 5}, {text: "Penegakan hukum yang tegas terhadap warga yang tidak menggunakan mata uang Rupiah.", val: 0}, {text: "Peningkatan kehadiran aparat keamanan di wilayah perbatasan secara masif.", val: 0}, {text: "Pemberian insentif materi agar warga bersedia memindahkan sekolah anaknya.", val: 0}] },
{ text: "Dalam sebuah rapat koordinasi antarinstansi, terjadi perdebatan sengit mengenai alokasi anggaran pembangunan. Perwakilan dari daerah yang memberikan kontribusi pendapatan negara paling besar menuntut porsi anggaran yang jauh lebih banyak untuk daerahnya, dengan alasan keadilan kontribusi. Di sisi lain, perwakilan dari daerah tertinggal meminta prioritas anggaran untuk mengejar ketimpangan infrastruktur dasar. Sebagai seorang aparatur sipil negara yang menjunjung tinggi prinsip kesatuan dalam keberagaman di bawah naungan NKRI, argumen yang harus Anda kedepankan adalah...", options: [{text: "Mendukung daerah penyumbang besar karena mereka adalah mesin penggerak ekonomi utama.", val: 0}, {text: "Memberikan seluruh anggaran kepada daerah tertinggal sebagai wujud rasa belas kasihan.", val: 0}, {text: "Mengusulkan pembagian anggaran secara rata tanpa melihat kondisi objektif setiap wilayah.", val: 0}, {text: "Mendorong alokasi berdasarkan prinsip pemerataan berkeadilan untuk integrasi nasional.", val: 5}, {text: "Menyarankan daerah untuk mencari pendanaan mandiri tanpa bergantung pada pusat.", val: 0}] },
{ text: "Dalam sebuah forum kerja sama ekonomi regional, seorang delegasi muda Indonesia mendapatkan tawaran kolaborasi riset strategis dari perusahaan multinasional asing yang menjanjikan pendanaan besar dan prestise internasional. Namun, salah satu klausul kontrak mensyaratkan bahwa seluruh data genetik dan keanekaragaman hayati yang dikumpulkan dari pedalaman Kalimantan harus menjadi hak milik intelektual eksklusif perusahaan tersebut tanpa keterlibatan otoritas sains nasional. Delegasi tersebut memahami bahwa riset ini bisa mempercepat penemuan obat-obat baru bagi kemanusiaan, namun di sisi lain ia menyadari adanya ancaman terhadap kedaulatan sumber daya hayati. Tindakan yang paling mencerminkan integritas terhadap keutuhan NKRI dalam konteks kedaulatan sumber daya adalah...", options: [{text: "Menerima tawaran tersebut demi percepatan kemajuan ilmu pengetahuan global.", val: 0}, {text: "Menolak tegas segala bentuk kerja sama dengan pihak asing yang bersifat komersial.", val: 0}, {text: "Menegosiasikan kepemilikan bersama atas basis data riset demi kepentingan nasional.", val: 5}, {text: "Mengarahkan perusahaan asing tersebut untuk bekerja sama dengan pihak swasta lokal.", val: 0}, {text: "Melaporkan tawaran tersebut kepada pihak keamanan karena dianggap sebagai spionase.", val: 0}] },
{ text: "Seorang manajer media sosial di sebuah instansi pemerintah mendapati bahwa sebuah tagar yang mempromosikan sentimen kedaerahan yang sempit dan provokatif sedang menjadi trending topic. Tagar tersebut muncul sebagai reaksi atas ketidakpuasan sekelompok masyarakat terhadap kebijakan pembangunan infrastruktur pusat yang dianggap tidak berpihak pada kearifan lokal tertentu. Alih-alih melakukan penyensoran massal yang dapat memicu kemarahan publik lebih lanjut atau membalas dengan narasi nasionalisme yang kaku, manajer tersebut memutuskan untuk memproduksi konten yang menonjolkan bagaimana infrastruktur baru tersebut justru dapat menjadi jembatan bagi produk kearifan lokal untuk menembus pasar nasional. Pendekatan ini merupakan manifestasi dari menjaga NKRI melalui...", options: [{text: "Penegakan supremasi hukum digital untuk meredam potensi disintegrasi bangsa.", val: 0}, {text: "Transformasi narasi keberagaman menjadi kekuatan ekonomi yang saling terintegrasi.", val: 5}, {text: "Penggunaan pengaruh otoritas negara untuk mengarahkan opini publik secara masif.", val: 0}, {text: "Modernisasi budaya lokal agar sesuai dengan standar pembangunan pemerintah pusat.", val: 0}, {text: "Pemberian kompensasi ekonomi bagi daerah yang merasa tidak puas dengan kebijakan.", val: 0}] },
{ text: "Di sebuah perusahaan BUMN yang memiliki kantor cabang di seluruh Indonesia, terdapat kebijakan rotasi pegawai secara nasional untuk memperkuat pemahaman lintas budaya. Seorang pegawai senior yang sangat kompeten menolak dipindahkan ke wilayah pelosok Indonesia Timur dengan alasan fasilitas kesehatan di sana kurang memadai untuk keluarganya dan merasa kontribusinya lebih efektif jika tetap di Jakarta. Ia mengusulkan agar posisi di pelosok diberikan kepada pegawai baru yang belum berkeluarga. Jika dilihat dari prinsip pengabdian terhadap keutuhan dan pemerataan kualitas pelayanan negara dalam bingkai NKRI, respon pimpinan yang paling tepat adalah...", options: [{text: "Mengizinkan pegawai tersebut tetap di Jakarta demi menjaga produktivitas perusahaan.", val: 0}, {text: "Memaksa pegawai tersebut pindah dengan ancaman pemutusan hubungan kerja.", val: 0}, {text: "Memberikan tunjangan kesehatan yang sangat besar khusus bagi keluarga pegawai tersebut.", val: 0}, {text: "Menjelaskan bahwa rotasi adalah instrumen pemerataan kompetensi untuk kemajuan seluruh wilayah.", val: 5}, {text: "Menghapus kebijakan rotasi karena dianggap membebani efisiensi biaya operasional.", val: 0}] },
{ text: "Sebuah delegasi peneliti muda Indonesia dalam konferensi internasional mendapatkan tawaran pendanaan riset yang sangat besar dari sebuah yayasan asing untuk memetakan kekayaan hayati dan genetik di wilayah pedalaman Papua. Namun, dalam kontrak tersebut terdapat klausul tersembunyi bahwa seluruh hak paten dan data mentah hasil riset akan menjadi milik eksklusif yayasan tersebut, sementara peneliti Indonesia hanya dicantumkan sebagai kontributor. Menghadapi situasi ini, tindakan yang paling mencerminkan kesadaran terhadap keutuhan dan kedaulatan NKRI dalam dimensi kemandirian bangsa adalah...", options: [{text: "Menerima tawaran tersebut demi percepatan publikasi ilmiah internasional bagi peneliti lokal.", val: 0}, {text: "Menolak tawaran secara diplomatis dan mengusulkan kolaborasi setara yang menjaga kedaulatan data nasional.", val: 5}, {text: "Melaporkan yayasan tersebut kepada otoritas keamanan internasional karena dianggap melakukan pencurian data.", val: 0}, {text: "Meminta pemerintah untuk membiayai riset tersebut dengan jumlah yang sama agar tidak bergantung pada asing.", val: 0}, {text: "Menandatangani kontrak tersebut namun secara diam-diam menyimpan salinan data untuk kepentingan negara.", val: 0}] },
{ text: "Di tengah masifnya penggunaan media sosial, muncul tren desa global di mana generasi muda merasa lebih terikat pada komunitas hobi internasional daripada identitas lokalnya. Dalam sebuah lingkungan kerja, seorang manajer melihat adanya kecenderungan staf muda yang lebih bangga menggunakan simbol-simbol budaya asing dan merasa bahwa konsep nasionalisme sudah usang di era digital yang tanpa batas. Respons manajer yang paling tepat untuk menguatkan kembali pilar NKRI tanpa mematikan kreativitas karyawan adalah...", options: [{text: "Mewajibkan penggunaan pakaian adat setiap hari kerja untuk menanamkan rasa cinta tanah air.", val: 0}, {text: "Melarang penggunaan bahasa asing dalam komunikasi formal maupun informal di lingkungan kantor.", val: 0}, {text: "Mengintegrasikan narasi keberhasilan inovasi lokal ke dalam proyek perusahaan agar muncul rasa bangga nasional.", val: 5}, {text: "Memberikan sanksi administratif bagi karyawan yang menunjukkan sikap tidak loyal terhadap budaya bangsa.", val: 0}, {text: "Mengabaikan hal tersebut karena menganggap perbedaan budaya adalah bagian dari profesionalitas modern.", val: 0}] },
{ text: "Seorang pejabat pengadaan barang di suatu instansi pusat dihadapkan pada dua pilihan vendor untuk proyek infrastruktur strategis nasional. Vendor A adalah perusahaan asing dengan teknologi mutakhir dan harga lebih murah, namun seluruh material dan tenaga ahlinya dibawa dari luar negeri. Vendor B adalah konsorsium perusahaan lokal dengan teknologi yang sedikit di bawah Vendor A dan harga lebih mahal, namun menjanjikan penggunaan 90% material dalam negeri dan transfer teknologi kepada teknisi lokal. Keputusan yang paling sejalan dengan prinsip penguatan struktur NKRI adalah...", options: [{text: "Memilih Vendor A demi efisiensi anggaran negara dan kualitas infrastruktur yang terbaik.", val: 0}, {text: "Memilih Vendor B untuk memperkuat struktur ekonomi domestik dan kemandirian teknologi bangsa.", val: 5}, {text: "Membagi proyek menjadi dua bagian agar kedua vendor dapat bekerja sama secara adil.", val: 0}, {text: "Melakukan tender ulang untuk mencari vendor asing lain yang lebih murah dari Vendor A.", val: 0}, {text: "Menyerahkan keputusan sepenuhnya kepada pimpinan tertinggi untuk menghindari tanggung jawab.", val: 0}] },
{ text: "Seorang peneliti di sebuah lembaga strategis nasional menemukan bahwa sebuah wilayah terluar Indonesia memiliki potensi mineral langka yang sangat dibutuhkan untuk teknologi baterai dunia. Penemuan ini memicu minat besar dari korporasi global yang menawarkan investasi masif untuk membangun kawasan industri eksklusif di sana, namun dengan syarat wilayah tersebut harus memiliki regulasi otonomi khusus yang longgar terhadap pengawasan pusat demi efisiensi operasional. Sebagai bagian dari tim perumus kebijakan, argumen Anda yang paling mencerminkan upaya menjaga keutuhan NKRI dalam aspek kedaulatan wilayah adalah...", options: [{text: "Mendukung investasi tersebut sepenuhnya demi meningkatkan kesejahteraan ekonomi warga di wilayah terluar.", val: 0}, {text: "Menolak investasi asing dan membiarkan mineral tersebut tetap tersimpan hingga negara mampu mengelolanya sendiri.", val: 0}, {text: "Menerima investasi dengan syarat pembangunan infrastruktur sosial bagi masyarakat lokal sebagai kompensasi.", val: 0}, {text: "Menekankan bahwa integrasi regulasi nasional dan pengawasan pusat adalah harga mati dalam pengelolaan aset strategis.", val: 5}, {text: "Menyarankan pembentukan zona ekonomi independen yang dikelola sepenuhnya oleh pihak swasta internasional.", val: 0}] },
{ text: "Dalam sebuah proyek pengembangan aplikasi layanan publik nasional, seorang pengembang perangkat lunak senior menyadari bahwa arsitektur sistem yang diminta oleh atasan menggunakan teknologi cloud milik penyedia luar negeri yang belum memiliki pusat data di Indonesia. Meskipun secara teknis lebih stabil dan murah, hal ini berpotensi membuat data kependudukan sensitif tersimpan di yurisdiksi hukum negara lain. Di tengah tekanan deadline dan keterbatasan anggaran, tindakan pengembang tersebut yang paling mencerminkan pengamalan nilai NKRI di era digital adalah...", options: [{text: "Melaksanakan perintah atasan agar proyek selesai tepat waktu dan anggaran tidak membengkak.", val: 0}, {text: "Mengusulkan penggunaan penyedia layanan lokal meskipun harus melakukan penyesuaian anggaran dan waktu.", val: 5}, {text: "Melakukan enkripsi data tingkat tinggi sehingga pihak penyedia cloud luar negeri tidak bisa membacanya.", val: 0}, {text: "Meminta jaminan tertulis dari perusahaan asing tersebut bahwa mereka tidak akan menyalahgunakan data.", val: 0}, {text: "Mengundurkan diri dari proyek karena tidak ingin terlibat dalam potensi pelanggaran kedaulatan data.", val: 0}] },
{ text: "Seorang diplomat muda Indonesia yang bertugas di organisasi internasional mendapati bahwa ada gerakan dari organisasi non-pemerintah global yang secara masif menyebarkan narasi bahwa pemisahan diri sebuah wilayah di Indonesia adalah solusi terbaik untuk menjaga kelestarian lingkungan dan hak asasi manusia di wilayah tersebut. Diplomat tersebut diminta untuk memberikan tanggapan resmi dalam forum tersebut. Strategi diplomasi yang paling tepat untuk mempertahankan eksistensi NKRI tanpa mengabaikan nilai-nilai kemanusiaan adalah...", options: [{text: "Membantah semua laporan tersebut sebagai hoaks dan menolak berdiskusi lebih lanjut dengan mereka.", val: 0}, {text: "Menjelaskan bahwa masalah internal Indonesia tidak boleh dicampuri oleh pihak asing sesuai hukum internasional.", val: 0}, {text: "Memaparkan program pembangunan inklusif dan perlindungan hak masyarakat adat yang telah dijalankan pemerintah.", val: 5}, {text: "Mengancam akan memutus kerja sama lingkungan dengan organisasi internasional jika narasi tersebut diteruskan.", val: 0}, {text: "Menyetujui adanya pengawasan internasional secara langsung di wilayah tersebut untuk membuktikan kebenaran.", val: 0}] },
{ text: "Seorang atasan di instansi pusat menugaskan timnya untuk melakukan digitalisasi arsip nasional yang berisi data demografi sensitif penduduk di wilayah perbatasan. Karena keterbatasan infrastruktur server lokal, muncul usulan dari anggota tim untuk menggunakan layanan penyimpanan awan (cloud) milik perusahaan asing yang lebih murah dan stabil agar proyek cepat selesai. Sebagai ASN yang memahami prinsip kedaulatan NKRI di ruang digital, sikap Anda adalah menolak usulan tersebut dan mendorong penggunaan infrastruktur dalam negeri meskipun lebih mahal karena hal ini berkaitan dengan potensi penguasaan data strategis oleh yurisdiksi hukum asing yang dapat mengancam...", options: [{text: "Rahasia jabatan dan kode etik profesi sebagai aparatur negara.", val: 0}, {text: "Efisiensi anggaran negara dalam jangka panjang.", val: 0}, {text: "Ketahanan nasional dan kemandirian informasi bangsa.", val: 5}, {text: "Stabilitas ekonomi nasional dari intervensi pasar global.", val: 0}, {text: "Hubungan diplomatik dengan negara penyedia layanan tersebut.", val: 0}] },
{ text: "Dalam sebuah rapat koordinasi pembangunan lintas provinsi, perwakilan dari daerah yang kaya sumber daya alam menuntut otonomi penuh dalam pengelolaan hasil tambang dan menolak sistem bagi hasil ke pusat dengan alasan bahwa kekayaan tersebut adalah hak mutlak penduduk asli daerah tersebut. Situasi ini memicu ketegangan dengan daerah tetangga yang miskin sumber daya namun menjadi penyokong tenaga kerja. Argumen yang paling tepat untuk meredam konflik tersebut berdasarkan konsep NKRI sebagai negara kesatuan adalah bahwa kekayaan alam di seluruh wilayah Indonesia pada hakikatnya merupakan...", options: [{text: "Milik masyarakat adat yang harus dilindungi secara hukum.", val: 0}, {text: "Modal utama untuk mengejar ketertinggalan ekonomi daerah terkait.", val: 0}, {text: "Aset nasional yang dikelola untuk kemakmuran bersama seluruh rakyat.", val: 5}, {text: "Instrumen untuk meningkatkan daya tawar daerah terhadap pemerintah pusat.", val: 0}, {text: "Komoditas perdagangan internasional untuk menambah devisa negara.", val: 0}] },
{ text: "Seorang profesional Indonesia yang bekerja di perusahaan riset global diminta oleh kantor pusatnya untuk memimpin proyek pemetaan keanekaragaman hayati secara mendetail di zona ekonomi eksklusif (ZEE) Indonesia. Ia menyadari bahwa hasil riset tersebut akan dipatenkan oleh perusahaan asing tanpa memberikan hak royalti atau akses data kepada pemerintah Indonesia. Meskipun proyek ini menawarkan promosi jabatan yang besar, ia memilih untuk mensyaratkan keterlibatan lembaga riset nasional dalam proyek tersebut. Tindakan ini merupakan bentuk pembelaan terhadap NKRI dalam aspek...", options: [{text: "Perlindungan hak asasi manusia bagi para peneliti lokal.", val: 0}, {text: "Penegakan hukum internasional tentang batas wilayah laut.", val: 0}, {text: "Penguatan integritas pribadi dalam persaingan karier global.", val: 0}, {text: "Penjagaan kedaulatan intelektual dan kekayaan sumber daya hayati.", val: 5}, {text: "Formalitas administratif dalam kerja sama investasi asing.", val: 0}] },
{ text: "Sebuah perusahaan teknologi komunikasi multinasional menawarkan bantuan infrastruktur jaringan internet gratis ke seluruh desa tertinggal di wilayah perbatasan Indonesia dengan syarat mereka diizinkan mengelola penuh lalu lintas data dan memasang perangkat transmisi tanpa perlu verifikasi teknis dari kementerian terkait. Sebagai pejabat yang berwenang, Anda dihadapkan pada tekanan publik yang menginginkan akses internet cepat namun juga menyadari adanya risiko keamanan nasional. Tindakan yang paling tepat untuk menunjukkan sikap menjaga keutuhan NKRI dalam aspek kedaulatan ruang udara dan informasi adalah...", options: [{text: "Menerima tawaran tersebut demi mempercepat pemerataan informasi dan kesejahteraan rakyat di perbatasan.", val: 0}, {text: "Menolak tawaran tersebut karena segala bentuk bantuan asing di wilayah perbatasan berpotensi menjadi spionase.", val: 0}, {text: "Menyetujui kerja sama dengan syarat seluruh perangkat dan lalu lintas data tetap berada di bawah kendali teknis otoritas nasional.", val: 5}, {text: "Mengalihkan bantuan tersebut ke wilayah perkotaan agar lebih mudah diawasi oleh pemerintah pusat.", val: 0}, {text: "Meminta perusahaan tersebut memberikan kompensasi finansial yang besar sebagai jaminan keamanan data warga.", val: 0}] },
{ text: "Dalam sebuah perundingan sengketa batas wilayah laut di forum internasional, pihak negara tetangga menawarkan klaim bersama (joint development) atas wilayah yang tumpang tindih yang kaya akan cadangan gas alam, dengan janji pembagian keuntungan yang sangat menguntungkan Indonesia. Namun, klaim tersebut secara implisit mengharuskan Indonesia mengakui garis batas yang tidak sesuai dengan konvensi hukum laut internasional yang selama ini dipegang teguh. Sebagai diplomat, langkah yang paling mencerminkan prinsip mempertahankan eksistensi NKRI adalah...", options: [{text: "Menerima tawaran klaim bersama untuk menghindari konflik militer dan meningkatkan pendapatan devisa negara.", val: 0}, {text: "Menolak tawaran tersebut dan bersikeras pada garis batas sesuai hukum internasional meskipun kehilangan potensi pendapatan.", val: 5}, {text: "Mengusulkan untuk menunda perundingan sampai kondisi ekonomi Indonesia jauh lebih stabil untuk bernegosiasi.", val: 0}, {text: "Menerima sebagian kecil klaim tersebut asalkan perusahaan nasional diberikan peran utama dalam pengelolaan gas.", val: 0}, {text: "Menyerahkan keputusan sepenuhnya kepada mahkamah internasional tanpa melakukan upaya negosiasi bilateral.", val: 0}] },
{ text: "Seorang kepala lembaga riset nasional mendapati bahwa banyak peneliti terbaiknya direkrut oleh laboratorium luar negeri dengan gaji fantastis untuk mengerjakan proyek yang menggunakan sampel kekayaan hayati asli Indonesia yang dibawa keluar secara ilegal di masa lalu. Meskipun secara pribadi ia ingin mendukung karier para peneliti tersebut, ia memutuskan untuk membuat kebijakan ketat yang mewajibkan seluruh riset mengenai kekayaan hayati Indonesia harus bermuara pada pengembangan industri farmasi dalam negeri. Kebijakan ini merupakan manifestasi dari menjaga NKRI melalui...", options: [{text: "Perlindungan hak kerja dan kesejahteraan bagi tenaga ahli nasional agar tidak pindah ke luar negeri.", val: 0}, {text: "Penegakan aturan administratif mengenai keluar masuknya personil riset di lingkungan lembaga.", val: 0}, {text: "Penguatan kedaulatan ekonomi dan kemandirian bangsa atas kekayaan sumber daya alam.", val: 5}, {text: "Pencegahan konflik kepentingan antara peneliti dengan perusahaan multinasional asing.", val: 0}, {text: "Modernisasi fasilitas laboratorium agar peneliti tidak lagi membutuhkan kerja sama dengan luar negeri.", val: 0}] },
{ text: "Seorang aparatur sipil negara (ASN) ditugaskan untuk memimpin unit kerja di daerah yang memiliki adat istiadat sangat kuat dan berbeda jauh dengan budaya asalnya. Dalam sebuah rapat desa mengenai penggunaan lahan untuk fasilitas publik, terdapat penolakan dari tokoh adat karena lahan tersebut dianggap sakral, padahal secara hukum negara lahan itu adalah milik pemerintah. Menghadapi situasi ini, tindakan yang paling sesuai dengan prinsip menjaga keutuhan NKRI melalui pendekatan kewilayahan adalah...", options: [{text: "Tetap melaksanakan pembangunan sesuai hukum negara karena kedaulatan pemerintah pusat bersifat mutlak.", val: 0}, {text: "Membatalkan proyek pembangunan demi menjaga ketenangan dan menghindari konflik dengan masyarakat adat.", val: 0}, {text: "Melakukan dialog persuasif untuk mencari solusi teknis yang menghormati nilai lokal tanpa mengorbankan fungsi pembangunan nasional.", val: 5}, {text: "Melaporkan tokoh adat tersebut ke pihak kepolisian karena dianggap menghambat program strategis pemerintah.", val: 0}, {text: "Menyarankan agar proyek tersebut dipindahkan ke daerah lain yang masyarakatnya lebih kooperatif dengan pemerintah.", val: 0}] },
{ text: "Dalam sebuah proyek pengadaan sistem informasi pelayanan terpadu, instansi Anda mendapatkan tawaran hibah perangkat lunak dari organisasi internasional. Setelah diperiksa, sistem tersebut mewajibkan seluruh data operasional disimpan dalam mirroring server di luar negeri untuk alasan pemeliharaan teknis oleh pihak donor. Sebagai penanggung jawab teknis, argumen Anda yang paling tepat untuk menolak klausul tersebut berdasarkan esensi pilar NKRI adalah...", options: [{text: "Penggunaan layanan luar negeri akan membebani biaya komunikasi data instansi.", val: 0}, {text: "Penyimpanan data di luar negeri melanggar prosedur administrasi pengadaan barang dan jasa.", val: 0}, {text: "Kedaulatan data nasional merupakan bagian dari pertahanan negara yang tidak boleh berpindah tangan ke pihak asing.", val: 5}, {text: "Perangkat lunak dalam negeri lebih mudah dioperasikan oleh pegawai dibandingkan perangkat asing.", val: 0}, {text: "Organisasi internasional tersebut tidak memiliki izin usaha resmi di wilayah hukum Indonesia.", val: 0}] },
{ text: "Seorang kepala daerah sering memberikan pernyataan di media sosial yang cenderung membandingkan kemajuan daerahnya dengan ketertinggalan daerah lain, sehingga memicu persaingan tidak sehat dan kecemburuan antarwarga lintas provinsi. Jika ditinjau dari prinsip negara kesatuan, perilaku tersebut dianggap tidak tepat karena mengabaikan hakikat bahwa kemajuan suatu daerah dalam bingkai NKRI seharusnya...", options: [{text: "Menjadi alat kompetisi utama untuk mendapatkan alokasi anggaran pusat yang lebih besar.", val: 0}, {text: "Dipandang sebagai keberhasilan kolektif bangsa dan pendorong pemerataan bagi daerah lainnya.", val: 5}, {text: "Diisolasi agar tidak menimbulkan arus migrasi penduduk dari daerah yang lebih miskin.", val: 0}, {text: "Digunakan sebagai dasar untuk meminta otonomi yang lebih luas dari pemerintah pusat.", val: 0}, {text: "Dikelola secara mandiri sepenuhnya tanpa perlu campur tangan atau bantuan dari provinsi tetangga.", val: 0}] },
{ text: "Seorang diplomat Indonesia dalam sebuah forum internasional mengenai keamanan maritim mendapatkan tekanan dari beberapa negara besar untuk membuka wilayah perairan pedalaman Indonesia sebagai jalur pelayaran internasional bebas tanpa syarat, dengan alasan untuk kelancaran logistik global. Di sisi lain, pembukaan jalur ini tanpa pengawasan ketat berpotensi mengancam kedaulatan wilayah dan keamanan sumber daya laut nasional. Sikap diplomat tersebut yang paling mencerminkan prinsip NKRI adalah...", options: [{text: "Menolak keras usulan tersebut dan membatasi akses kapal asing ke seluruh wilayah perairan Indonesia.", val: 0}, {text: "Menerima usulan tersebut sepenuhnya untuk menunjukkan posisi Indonesia sebagai negara yang mendukung ekonomi global.", val: 0}, {text: "Menegaskan bahwa kedaulatan perairan pedalaman adalah mutlak namun terbuka untuk kerja sama yang diatur oleh hukum nasional.", val: 5}, {text: "Meminta bantuan militer dari negara sekutu untuk menjaga wilayah perairan dari tekanan negara besar tersebut.", val: 0}, {text: "Menyarankan agar pengelolaan jalur pelayaran tersebut diserahkan sepenuhnya kepada organisasi maritim internasional.", val: 0}] },
{ text: "Di sebuah kementerian, muncul perdebatan mengenai rencana integrasi sistem basis data kependudukan nasional. Beberapa pihak mengusulkan untuk memberikan akses data terbatas kepada perusahaan riset teknologi asing demi mendapatkan algoritma pengolahan data paling mutakhir secara cuma-cuma. Sebagai analis kebijakan, argumen Anda untuk menolak usulan tersebut berdasarkan prinsip kedaulatan negara adalah...", options: [{text: "Kerja sama dengan pihak asing akan mempersulit birokrasi dalam pengelolaan data internal.", val: 0}, {text: "Kemandirian nasional atas data strategis warga negara adalah fondasi keamanan dan kedaulatan digital.", val: 5}, {text: "Perusahaan riset lokal akan merasa dianaktirikan jika proyek ini diberikan kepada pihak asing.", val: 0}, {text: "Algoritma dari luar negeri belum tentu sesuai dengan karakteristik sosiologis penduduk Indonesia.", val: 0}, {text: "Biaya untuk melakukan integrasi data dengan pihak asing jauh lebih mahal dibandingkan secara mandiri.", val: 0}] },
{ text: "Seorang gubernur di wilayah yang baru saja mengalami pemekaran daerah menolak untuk mengadopsi standar sistem pelaporan keuangan nasional dengan alasan bahwa daerahnya memiliki karakteristik unik dan ingin membangun sistemnya sendiri agar lebih otonom. Sikap gubernur tersebut berpotensi melemahkan konsep NKRI dalam dimensi kesatuan sistem administrasi karena...", options: [{text: "Menghambat proses pemerataan pembangunan ekonomi di daerah-daerah tetangga.", val: 0}, {text: "Menunjukkan adanya ego kedaerahan yang mengabaikan standar integrasi nasional.", val: 5}, {text: "Memerlukan anggaran yang sangat besar untuk membangun sistem yang baru dari awal.", val: 0}, {text: "Mengurangi tingkat kepercayaan investor asing terhadap kepastian hukum di daerah tersebut.", val: 0}, {text: "Bertentangan dengan prinsip otonomi daerah yang seharusnya memberikan kebebasan penuh.", val: 0}] },
{ text: "Sebuah wilayah di perbatasan Indonesia memiliki ketergantungan ekonomi yang sangat tinggi terhadap negara tetangga karena akses logistik dari pusat yang jauh lebih mahal. Menghadapi kondisi ini, muncul desakan dari tokoh masyarakat setempat agar wilayah tersebut diberikan status Zona Ekonomi Bebas yang memiliki otoritas penuh untuk membuat perjanjian dagang bilateral dengan negara tetangga tanpa melalui ratifikasi pemerintah pusat demi percepatan kesejahteraan. Sebagai pengambil kebijakan di tingkat pusat, langkah yang paling mencerminkan upaya menjaga keutuhan NKRI dalam jangka panjang adalah...", options: [{text: "Menyetujui usulan tersebut sebagai bentuk penghormatan terhadap hak otonomi daerah dan kesejahteraan rakyat.", val: 0}, {text: "Menolak usulan tersebut dan menggantinya dengan pembangunan infrastruktur konektivitas yang mengintegrasikan ekonomi lokal ke pasar nasional.", val: 5}, {text: "Memberikan bantuan sosial dan subsidi harga secara masif agar masyarakat tidak lagi bergantung pada barang dari negara tetangga.", val: 0}, {text: "Mengizinkan perjanjian dagang tersebut namun dengan pengawasan ketat dari aparat keamanan di wilayah perbatasan.", val: 0}, {text: "Melakukan normalisasi hubungan diplomatik yang lebih intens dengan negara tetangga agar mereka membantu pembangunan di wilayah tersebut.", val: 0}] },
{ text: "Dalam forum diskusi mengenai transisi energi, Indonesia mendapatkan tawaran investasi besar untuk pengembangan energi hijau. Namun, pihak investor mensyaratkan agar Indonesia menghapus kebijakan Tingkat Komponen Dalam Negeri (TKDN) khusus untuk teknologi ini dan membebaskan pajak impor alat berat sepenuhnya agar proyek bisa berjalan cepat. Sebagai seorang ASN yang memegang teguh prinsip kemandirian bangsa dalam bingkai NKRI, argumen yang paling tepat untuk mempertahankan kebijakan TKDN adalah...", options: [{text: "TKDN adalah aturan administratif yang wajib dipatuhi oleh seluruh investor asing tanpa terkecuali.", val: 0}, {text: "Kebijakan TKDN bertujuan untuk melindungi pengusaha lokal agar tidak kalah saing dengan perusahaan global.", val: 0}, {text: "Kemandirian teknologi melalui TKDN adalah instrumen kedaulatan ekonomi untuk mencegah ketergantungan permanen pada pihak asing.", val: 5}, {text: "Penghapusan TKDN akan menyebabkan berkurangnya pendapatan negara dari sektor pajak impor dan bea masuk.", val: 0}, {text: "Pemerintah harus mengutamakan produk dalam negeri meskipun secara kualitas masih di bawah produk luar negeri.", val: 0}] },
{ text: "Seorang atasan di sebuah lembaga riset pertahanan menemukan adanya upaya sistematis dari pihak luar untuk mensponsori beasiswa riset bagi peneliti-peneliti terbaik Indonesia di bidang teknologi satelit. Sponsor tersebut memberikan fasilitas luar biasa namun mensyaratkan agar seluruh hak atas kekayaan intelektual (HAKI) dari hasil riset tersebut didaftarkan di negara penyedia beasiswa. Menghadapi potensi Brain Drain dan penguasaan informasi strategis ini, tindakan pimpinan yang paling tepat sesuai semangat NKRI adalah...", options: [{text: "Melarang peneliti tersebut berangkat demi menjaga rahasia negara dan mencegah pelarian modal manusia.", val: 0}, {text: "Membiarkan peneliti tersebut berangkat dengan syarat mereka harus kembali dan mengabdi di instansi asal setelah lulus.", val: 0}, {text: "Mendorong pemerintah untuk menciptakan ekosistem riset serupa di dalam negeri dengan skema pembiayaan mandiri yang kompetitif.", val: 5}, {text: "Meminta peneliti tersebut untuk tetap berangkat namun secara rahasia memberikan laporan hasil risetnya ke instansi dalam negeri.", val: 0}, {text: "Menyarankan peneliti untuk mencari sponsor lain yang tidak meminta hak atas kekayaan intelektual secara eksklusif.", val: 0}] },
{ text: "Seorang manajer proyek infrastruktur di wilayah terluar mendapati bahwa penggunaan material impor akan mempercepat penyelesaian proyek dan menghemat anggaran secara signifikan. Namun, ia menyadari bahwa menggunakan material lokal, meski lebih mahal dan memakan waktu, akan menghidupkan industri kecil di wilayah tersebut dan memperkuat keterikatan ekonomi masyarakat lokal terhadap sistem suplai nasional. Sikap yang paling mencerminkan upaya menjaga keutuhan NKRI melalui kedaulatan ekonomi adalah...", options: [{text: "Memilih material impor demi efisiensi anggaran negara.", val: 0}, {text: "Menggunakan material lokal untuk memperkuat struktur ekonomi rakyat.", val: 5}, {text: "Mencampur kedua material agar kualitas tetap terjaga dengan harga miring.", val: 0}, {text: "Menunda proyek hingga tersedia anggaran tambahan untuk material lokal.", val: 0}, {text: "Mengajukan revisi desain agar tidak membutuhkan banyak material mahal.", val: 0}] },
{ text: "Dalam sebuah perundingan internasional, Indonesia ditawarkan bantuan teknologi pemantauan laut yang sangat canggih untuk mencegah pencurian ikan. Namun, perusahaan penyedia teknologi tersebut mensyaratkan akses penuh terhadap koordinat patroli kapal perang TNI AL secara real-time untuk alasan sinkronisasi sistem keamanan mereka. Sebagai pengambil keputusan, tindakan yang paling sesuai dengan prinsip kedaulatan wilayah NKRI adalah...", options: [{text: "Menerima tawaran tersebut guna meminimalkan kerugian akibat pencurian ikan.", val: 0}, {text: "Menolak akses data kapal perang karena merupakan rahasia pertahanan negara.", val: 5}, {text: "Memberikan akses terbatas hanya pada kapal pengawas perikanan sipil saja.", val: 0}, {text: "Membeli teknologi serupa dari negara lain yang tidak memberikan syarat akses data.", val: 0}, {text: "Menandatangani kerja sama dengan klausul pengawasan oleh otoritas keamanan nasional.", val: 0}] },
{ text: "Seorang gubernur di daerah yang memiliki sumber daya energi melimpah mengusulkan agar daerahnya memiliki kewenangan untuk mengatur kontrak ekspor energi secara mandiri tanpa campur tangan kementerian pusat, dengan dalih otonomi daerah dan percepatan pembangunan lokal. Tindakan pusat yang paling tepat untuk mempertahankan marwah negara kesatuan adalah...", options: [{text: "Memberikan izin penuh agar daerah tersebut cepat maju secara ekonomi.", val: 0}, {text: "Mencabut otonomi daerah tersebut karena dianggap menunjukkan gejala separatisme.", val: 0}, {text: "Menegaskan bahwa kebijakan energi strategis adalah urusan mutlak pemerintah pusat.", val: 5}, {text: "Memberikan porsi bagi hasil yang lebih besar tanpa memberikan kewenangan kontrak.", val: 0}, {text: "Mengizinkan keterlibatan daerah hanya pada tahap negosiasi teknis, bukan keputusan.", val: 0}] },
{ text: "Seorang kepala biro kerja sama internasional di sebuah kementerian strategis menerima tawaran pengembangan sistem kecerdasan buatan (AI) untuk optimasi birokrasi dari perusahaan global. Syaratnya, seluruh data alur kerja dan komunikasi internal harus diunggah ke cloud perusahaan tersebut agar mesin dapat belajar secara otomatis. Meski sangat membantu efisiensi, ia memilih menolak karena menyadari bahwa penguasaan atas logika birokrasi oleh pihak asing merupakan ancaman terselubung bagi kemandirian administrasi negara. Sikap ini merupakan wujud penjagaan NKRI dalam dimensi...", options: [{text: "Keamanan rahasia jabatan sesuai kode etik ASN.", val: 0}, {text: "Kedaulatan digital dan independensi tata kelola negara.", val: 5}, {text: "Efisiensi penggunaan anggaran riset dalam negeri.", val: 0}, {text: "Perlindungan hak kekayaan intelektual pegawai.", val: 0}, {text: "Formalitas prosedur keamanan informasi instansi.", val: 0}] },
{ text: "Dalam sebuah konflik lahan antara perusahaan pertambangan nasional dengan masyarakat adat di wilayah terpencil, muncul tawaran dari organisasi internasional untuk memediasi konflik dengan syarat wilayah tersebut dinyatakan sebagai kawasan konservasi internasional yang diawasi oleh badan dunia. Pemerintah pusat menolak mediasi tersebut dan memilih menyelesaikan konflik melalui jalur hukum nasional dan dialog kebudayaan. Penolakan terhadap keterlibatan badan dunia tersebut bertujuan untuk mempertahankan NKRI karena...", options: [{text: "Hukum internasional tidak berlaku dalam konflik agraria di Indonesia.", val: 0}, {text: "Intervensi asing dalam penyelesaian masalah domestik dapat mencederai kedaulatan wilayah.", val: 5}, {text: "Biaya mediasi internasional jauh lebih mahal dibanding penyelesaian internal.", val: 0}, {text: "Masyarakat adat tidak memiliki kedudukan hukum dalam forum internasional.", val: 0}, {text: "Kawasan konservasi akan menghambat target produksi pertambangan nasional.", val: 0}] },
{ text: "Seorang atasan di pelabuhan strategis menemukan bahwa banyak operator logistik lebih memilih menggunakan sistem navigasi dan perizinan pihak swasta asing yang lebih praktis daripada sistem resmi milik negara yang masih dalam tahap pengembangan. Meski praktis, sistem asing tersebut merekam seluruh pola pergerakan kapal logistik nasional secara detail. Atasan tersebut kemudian mewajibkan penggunaan sistem nasional sebagai instrumen utama. Tindakan ini mencerminkan penguatan NKRI melalui...", options: [{text: "Penertiban administrasi niaga dan kepabeanan.", val: 0}, {text: "Penguasaan atas data pergerakan logistik strategis bangsa.", val: 5}, {text: "Peningkatan pendapatan negara dari sektor retribusi jasa pelabuhan.", val: 0}, {text: "Perlindungan industri perangkat lunak dalam negeri agar berkembang.", val: 0}, {text: "Penegakan kedisiplinan operasional bagi para operator pelabuhan.", val: 0}] },
];

const twk_UUD1945 = [
{ text: "Sebuah perusahaan besar terbukti melakukan pencemaran lingkungan yang berdampak pada kesehatan warga di sekitarnya. Namun, perusahaan tersebut memiliki peran strategis dalam menyerap ribuan tenaga kerja lokal dan berkontribusi besar pada pendapatan daerah. Pemerintah daerah dihadapkan pada pilihan sulit antara mencabut izin operasional demi menegakkan aturan hukum lingkungan atau memberikan dispensasi demi menjaga stabilitas ekonomi warga. Dalam perspektif UUD 1945 sebagai dasar hukum tertinggi, tindakan paling tepat yang harus diambil oleh otoritas berwenang untuk mencerminkan esensi konstitusionalitas adalah...", options: [{text: "Mendahulukan negosiasi agar perusahaan tetap beroperasi sambil memperbaiki kerusakan.", val: 0}, {text: "Menegakkan sanksi hukum sesuai prosedur demi menjaga martabat dan kepastian aturan.", val: 5}, {text: "Memberikan kompensasi finansial langsung kepada warga tanpa menutup operasional.", val: 0}, {text: "Meminta pendapat masyarakat luas untuk menentukan keberlanjutan izin perusahaan.", val: 0}, {text: "Menunda sanksi administratif hingga perusahaan menemukan teknologi ramah lingkungan.", val: 0}] },
{ text: "Dalam sebuah rapat koordinasi antarlembaga, muncul usulan kebijakan nasional yang dianggap efektif untuk mempercepat pembangunan infrastruktur, namun kebijakan tersebut berpotensi membatasi ruang pengawasan lembaga legislatif terhadap penggunaan anggaran. Beberapa pihak mendukung karena alasan efisiensi birokrasi, sementara pihak lain khawatir akan potensi penyalahgunaan kekuasaan. Sebagai seorang aparatur yang memahami prinsip konstitusi pasca-amandemen, sikap yang harus dikedepankan dalam memandang efisiensi versus pengawasan tersebut adalah...", options: [{text: "Mendukung efisiensi karena percepatan pembangunan adalah mandat utama pemerintah.", val: 0}, {text: "Mengutamakan mekanisme saling kontrol agar kekuasaan tetap memiliki batasan yang jelas.", val: 5}, {text: "Menyerahkan keputusan sepenuhnya kepada pimpinan tertinggi demi kesatuan komando.", val: 0}, {text: "Menyarankan agar pengawasan dilakukan setelah seluruh proyek pembangunan selesai.", val: 0}, {text: "Mendorong penghapusan prosedur yang menghambat gerak cepat eksekutif di lapangan.", val: 0}] },
{ text: "Di sebuah instansi pelayanan publik, terdapat kebijakan baru yang mewajibkan seluruh pegawai untuk bersedia ditugaskan di daerah terpencil kapan saja guna menjamin pemerataan kualitas layanan bagi masyarakat luas. Seorang pegawai merasa keberatan karena memiliki tanggung jawab merawat anggota keluarga yang sakit kronis dan membutuhkan perawatan intensif di kota. Konflik antara kewajiban menjalankan tugas negara dengan hak pribadi pegawai tersebut seharusnya diselesaikan dengan cara pandang konstitusional yang menekankan bahwa...", options: [{text: "Hak pribadi harus selalu dikorbankan demi tercapainya tujuan pembangunan nasional.", val: 0}, {text: "Peraturan instansi harus ditaati tanpa pengecualian untuk menjaga integritas lembaga.", val: 0}, {text: "Kepentingan umum diprioritaskan tanpa mengabaikan perlindungan terhadap martabat individu.", val: 5}, {text: "Pegawai yang keberatan sebaiknya mengundurkan diri agar tidak menghambat kinerja.", val: 0}, {text: "Kebijakan negara bersifat mutlak sehingga keluhan personal tidak dapat dipertimbangkan.", val: 0}] },
{ text: "Pesatnya perkembangan teknologi kecerdasan buatan (AI) mulai menggeser beberapa fungsi pekerjaan administratif di instansi pemerintah, yang memicu kekhawatiran pegawai akan keberlangsungan karier mereka. Di sisi lain, negara dituntut untuk melakukan efisiensi birokrasi demi optimalisasi layanan publik sesuai mandat konstitusi. Menghadapi disrupsi ini, kebijakan negara yang paling mencerminkan kedudukan UUD 1945 sebagai pelindung segenap bangsa adalah...", options: [{text: "Menolak penggunaan teknologi AI demi menjaga ketersediaan lapangan kerja bagi warga negara.", val: 0}, {text: "Melakukan otomatisasi penuh sesegera mungkin guna memangkas beban anggaran belanja pegawai.", val: 0}, {text: "Mengintegrasikan teknologi sambil memfasilitasi peningkatan kompetensi baru bagi pegawai terdampak.", val: 5}, {text: "Memberikan tunjangan pengangguran sementara kepada pegawai yang posisinya tergantikan teknologi.", val: 0}, {text: "Menyerahkan sepenuhnya proses adaptasi teknologi kepada mekanisme pasar dan kebutuhan industri.", val: 0}] },
{ text: "Seorang pejabat publik mendapat tekanan dari kelompok kepentingan untuk memprioritaskan izin proyek tertentu yang diklaim akan meningkatkan pertumbuhan ekonomi nasional secara instan. Namun, kajian teknis menunjukkan adanya risiko pelanggaran prosedur tata ruang yang berpotensi merugikan masyarakat luas di masa depan. Meskipun ada celah aturan yang bisa dimanfaatkan untuk melegalkan proyek tersebut, tindakan yang paling sesuai dengan prinsip konstitusionalitas adalah...", options: [{text: "Mengizinkan proyek tersebut dengan catatan perusahaan memberikan bantuan sosial yang besar.", val: 0}, {text: "Menolak permohonan tersebut meskipun berisiko menghambat target pertumbuhan ekonomi.", val: 5}, {text: "Melakukan modifikasi aturan tata ruang agar proyek tersebut tidak lagi melanggar prosedur.", val: 0}, {text: "Meminta jaminan tertulis dari investor bahwa tidak akan ada masalah hukum di kemudian hari.", val: 0}, {text: "Menyerahkan keputusan kepada lembaga yang lebih tinggi untuk menghindari tanggung jawab pribadi.", val: 0}] },
{ text: "Dalam sebuah pembangunan fasilitas publik di suatu daerah, terdapat penolakan dari sebagian kelompok mayoritas setempat karena merasa keberadaan fasilitas tersebut tidak sesuai dengan nilai budaya dominan di sana. Namun, fasilitas tersebut sangat dibutuhkan oleh kelompok masyarakat lain yang juga merupakan warga negara sah. Dalam menghadapi konflik horizontal ini, peran negara berdasarkan mandat konstitusi sebagai hukum tertinggi adalah...", options: [{text: "Menunda pembangunan hingga tercapai kesepakatan bulat tanpa ada satu pihak pun yang keberatan.", val: 0}, {text: "Memindahkan lokasi pembangunan ke daerah lain yang lebih inklusif untuk menghindari konflik fisik.", val: 0}, {text: "Menjamin pembangunan tetap berjalan sesuai aturan hukum seraya memberikan edukasi keberagaman.", val: 5}, {text: "Memprioritaskan aspirasi kelompok mayoritas demi menjaga stabilitas keamanan di daerah tersebut.", val: 0}, {text: "Memberikan kebebasan kepada masyarakat setempat untuk menentukan sendiri jenis fasilitas publiknya.", val: 0}] },
{ text: "Pemerintah mulai mendigitalisasi seluruh skema bantuan sosial untuk meningkatkan akurasi data dan efisiensi penyaluran. Namun, di beberapa wilayah pelosok, masyarakat lanjut usia dan warga dengan keterbatasan akses internet kesulitan memenuhi persyaratan administratif digital tersebut. Dalam perspektif UUD 1945 sebagai payung hukum tertinggi yang menjamin kesejahteraan sosial, langkah yang harus diambil negara agar kebijakan ini tetap konstitusional adalah...", options: [{text: "Mewajibkan seluruh warga untuk segera beralih ke perangkat digital demi kemajuan bangsa.", val: 0}, {text: "Menunda digitalisasi secara nasional hingga infrastruktur internet merata di seluruh desa.", val: 0}, {text: "Menyediakan pendampingan fisik dan jalur alternatif bagi warga yang memiliki hambatan akses.", val: 5}, {text: "Memberikan bantuan hanya kepada warga yang sudah mampu mengoperasikan sistem digital.", val: 0}, {text: "Menyerahkan urusan administrasi warga pelosok kepada pihak swasta agar lebih profesional.", val: 0}] },
{ text: "Seorang warga menyampaikan kritik tajam melalui media sosial mengenai kebijakan pembangunan di daerahnya yang dianggap merusak ekosistem sungai. Pihak pengembang melaporkan warga tersebut dengan tuduhan pencemaran nama baik yang dapat mengganggu iklim investasi. Dalam koridor UUD 1945 yang menjamin kemerdekaan berserikat dan berkumpul serta mengeluarkan pikiran, cara penyelesaian yang paling sesuai dengan semangat negara demokrasi adalah...", options: [{text: "Memproses hukum warga tersebut agar tercipta ketertiban dalam menyampaikan pendapat.", val: 0}, {text: "Meminta warga tersebut menghapus kritiknya sebagai syarat agar laporan polisi dicabut.", val: 0}, {text: "Menjadikan kritik tersebut sebagai bahan evaluasi kebijakan dengan tetap menjamin perlindungan hukum bagi pemberi kritik.", val: 5}, {text: "Mengutamakan perlindungan bagi investor demi menjaga stabilitas ekonomi dan lapangan kerja.", val: 0}, {text: "Menyarankan warga agar menyampaikan kritik secara tertutup melalui surat resmi kepada dinas terkait saja.", val: 0}] },
{ text: "Sebuah komunitas adat telah menempati wilayah hutan secara turun-temurun, namun secara administratif lahan tersebut ditetapkan sebagai kawasan hutan produksi oleh pemerintah dan diberikan izin pengelolaannya kepada perusahaan besar. Konflik muncul ketika perusahaan mulai melakukan penebangan untuk industri. Berdasarkan kedudukan UUD 1945 sebagai hukum tertinggi yang mengakui keberadaan kesatuan masyarakat hukum adat, tindakan negara yang paling tepat adalah...", options: [{text: "Mendahulukan hak perusahaan karena memiliki izin resmi yang sah secara administratif.", val: 0}, {text: "Merelokasi masyarakat adat ke pemukiman baru yang difasilitasi penuh oleh negara.", val: 0}, {text: "Melakukan verifikasi dan pengakuan atas hak ulayat masyarakat adat sebelum memberikan izin pemanfaatan lahan.", val: 5}, {text: "Meminta masyarakat adat untuk membeli lahan tersebut dari pemerintah agar memiliki sertifikat sah.", val: 0}, {text: "Menghentikan seluruh aktivitas industri di daerah tersebut secara permanen tanpa kecuali.", val: 0}] },
{ text: "Pemerintah merilis kebijakan sistem pemantauan digital nasional yang mampu mendeteksi potensi penyebaran paham radikalisme dan ujaran kebencian secara real-time di ruang privat media sosial. Kebijakan ini diambil demi menjaga stabilitas keamanan nasional dan persatuan bangsa dari ancaman disintegrasi. Namun, kelompok masyarakat sipil menilai hal ini melanggar kedaulatan individu atas ruang privasi. Dalam esensi UUD 1945 sebagai hukum tertinggi, batasan yang paling tepat dalam penerapan kebijakan tersebut adalah...", options: [{text: "Menjalankan pemantauan secara menyeluruh karena keamanan negara adalah syarat mutlak pembangunan.", val: 0}, {text: "Membatasi pemantauan hanya pada individu yang sudah terbukti melakukan tindak pidana sebelumnya.", val: 0}, {text: "Menyelaraskan perlindungan keamanan negara dengan jaminan perlindungan atas privasi dan data pribadi.", val: 5}, {text: "Memberikan keleluasaan bagi lembaga keamanan untuk mengakses data selama tujuannya demi persatuan.", val: 0}, {text: "Menghentikan kebijakan pemantauan digital agar tidak terjadi penyalahgunaan kekuasaan oleh otoritas.", val: 0}] },
{ text: "Dalam menghadapi ancaman krisis pangan global, pemerintah mencanangkan program perluasan lahan pertanian skala besar (food estate) di atas lahan yang secara teknis merupakan kawasan hutan lindung. Program ini dipandang sebagai implementasi amanat konstitusi untuk kemakmuran rakyat melalui kedaulatan pangan. Di sisi lain, pembukaan lahan tersebut berisiko merusak ekosistem yang dilindungi. Jika merujuk pada prinsip pembangunan berkelanjutan dalam UUD 1945, sikap kebijakan yang paling tepat adalah...", options: [{text: "Mengutamakan perluasan lahan karena pemenuhan pangan adalah hak asasi manusia yang paling mendasar.", val: 0}, {text: "Menghentikan program tersebut demi menjaga kelestarian hutan bagi generasi mendatang secara mutlak.", val: 0}, {text: "Melakukan kajian dampak lingkungan yang ketat dan menerapkan teknologi pertanian tanpa merusak fungsi hutan.", val: 5}, {text: "Mengalihkan program ke wilayah luar negeri melalui investasi demi menjaga keutuhan ekologi domestik.", val: 0}, {text: "Menyerahkan keputusan kepada masyarakat sekitar hutan untuk menentukan peruntukan lahan tersebut.", val: 0}] },
{ text: "Seorang pimpinan di sebuah lembaga negara menemukan bahwa ada prosedur internal organisasi yang telah berjalan bertahun-tahun namun ternyata bertentangan dengan prinsip transparansi yang diatur dalam undang-undang turunan UUD 1945. Jika prosedur itu diubah secara mendadak, stabilitas internal organisasi akan terganggu dan kinerja layanan publik akan menurun sementara waktu. Sebagai pimpinan yang menjunjung tinggi UUD 1945 sebagai hukum tertinggi, tindakan yang harus diambil adalah...", options: [{text: "Mempertahankan prosedur lama demi menjamin stabilitas dan kelancaran layanan publik.", val: 0}, {text: "Melakukan perubahan prosedur secara bertahap sambil menyosialisasikan aturan yang lebih tinggi.", val: 5}, {text: "Melaporkan ketidaksesuaian tersebut kepada lembaga pengawas dan menunggu instruksi pusat.", val: 0}, {text: "Mengabaikan pertentangan norma tersebut selama tidak ada pihak luar yang melakukan gugatan.", val: 0}, {text: "Meminta pendapat seluruh staf untuk melakukan voting terkait perubahan prosedur organisasi.", val: 0}] },
{ text: "Menjelang kontestasi pemilihan kepala daerah, seorang aparatur sipil negara (ASN) melihat adanya ketimpangan informasi di media sosial terkait capaian kinerja instansinya yang dipelintir untuk menjatuhkan salah satu calon. Di satu sisi, ia ingin meluruskan informasi tersebut demi menjaga nama baik institusi dan kebenaran data publik, namun di sisi lain terdapat aturan ketat mengenai netralitas ASN dalam politik. Berdasarkan prinsip UUD 1945 mengenai kedaulatan hukum dan fungsi ASN sebagai pelayan publik, tindakan yang paling tepat adalah...", options: [{text: "Membiarkan informasi tersebut berkembang karena menjaga netralitas berarti tidak ikut campur sama sekali.", val: 0}, {text: "Meluruskan informasi secara objektif melalui kanal resmi institusi tanpa memihak atau menyerang calon manapun.", val: 5}, {text: "Menggunakan akun pribadi untuk memberikan pembelaan agar tidak membawa nama instansi secara langsung.", val: 0}, {text: "Mendukung salah satu calon yang dianggap memiliki visi paling sesuai dengan rencana pembangunan instansi.", val: 0}, {text: "Melaporkan pengunggah informasi tersebut kepada pihak kepolisian atas tuduhan penyebaran berita bohong.", val: 0}] },
{ text: "Sebuah tim kerja di instansi pemerintah berhasil melakukan penghematan anggaran yang cukup signifikan melalui inovasi sistem pengadaan mandiri. Pimpinan tim mengusulkan agar sisa anggaran tersebut dibagikan sebagai bonus performa bagi anggota tim sebagai bentuk apresiasi atas efisiensi yang dilakukan. Meskipun hal ini meningkatkan motivasi kerja, secara aturan penggunaan anggaran tersebut sudah ditetapkan untuk pos lain. Dalam kerangka UUD 1945 sebagai hukum tertinggi, sikap Anda sebagai anggota tim adalah...", options: [{text: "Menyetujui usulan tersebut karena kesejahteraan pegawai adalah bagian dari amanat konstitusi.", val: 0}, {text: "Menolak usulan tersebut dan menyarankan agar sisa anggaran dikembalikan ke kas negara sesuai aturan.", val: 5}, {text: "Menerima bonus tersebut asalkan seluruh anggota tim sepakat dan tidak ada keberatan internal.", val: 0}, {text: "Mengusulkan agar sisa anggaran digunakan untuk kegiatan sosial di luar instansi agar lebih bermanfaat.", val: 0}, {text: "Menyarankan agar bonus diberikan dalam bentuk barang agar tidak terdeteksi sebagai pelanggaran anggaran.", val: 0}] },
{ text: "Dalam proses promosi jabatan di sebuah perusahaan milik negara, terdapat seorang kandidat yang memiliki kompetensi teknis dan rekam jejak paling unggul. Namun, panel seleksi ragu untuk meloloskannya karena kandidat tersebut memiliki pandangan keagamaan atau latar belakang budaya yang berbeda dari mayoritas pimpinan di lembaga tersebut, sehingga dikhawatirkan akan sulit beradaptasi. Mengacu pada jaminan UUD 1945 tentang hak warga negara, keputusan yang harus diambil adalah...", options: [{text: "Memilih kandidat lain yang lebih setipe dengan pimpinan demi menjaga kekompakan organisasi.", val: 0}, {text: "Tetap mempromosikan kandidat tersebut berdasarkan prestasi dan kompetensi yang dimilikinya.", val: 5}, {text: "Meminta kandidat tersebut mengubah gaya hidupnya agar bisa menyesuaikan dengan budaya mayoritas.", val: 0}, {text: "Menunda promosi hingga kandidat tersebut mampu membuktikan bahwa ia bisa diterima oleh semua pihak.", val: 0}, {text: "Memberikan posisi yang setara namun di divisi yang tidak terlalu strategis untuk menghindari konflik.", val: 0}] },
{ text: "Sebuah pemerintah daerah mengeluarkan Peraturan Daerah (Perda) yang membatasi aktivitas ekonomi warga pada jam-jam tertentu dengan alasan untuk menjaga kekhusyukan ibadah dan kearifan lokal. Namun, kebijakan ini berdampak pada penurunan penghasilan drastis bagi kelompok pedagang kecil yang justru hanya bisa beroperasi pada jam tersebut. Sebagai warga negara yang memahami kedudukan UUD 1945 sebagai hukum tertinggi, argumen konstitusional yang paling tepat untuk meninjau ulang aturan tersebut adalah...", options: [{text: "Perda harus dibatalkan karena menghambat pertumbuhan ekonomi daerah dan nasional.", val: 0}, {text: "Kebijakan daerah tidak boleh bertentangan dengan jaminan hak warga negara untuk mencari penghidupan yang layak.", val: 5}, {text: "Aspirasi masyarakat lokal harus tetap dihormati sebagai bentuk otonomi daerah yang luas.", val: 0}, {text: "Pemerintah pusat harus memberikan subsidi sebagai ganti rugi atas hilangnya pendapatan pedagang.", val: 0}, {text: "Perda tersebut sah selama sudah melalui proses persetujuan oleh DPRD dan kepala daerah.", val: 0}] },
{ text: "Dalam sebuah persidangan kasus pencurian kecil yang dilakukan oleh seorang warga miskin demi memenuhi kebutuhan pangan mendesak, hakim dihadapkan pada tuntutan jaksa yang sesuai dengan UU yang berlaku. Di sisi lain, masyarakat menuntut adanya keadilan restoratif mengingat kondisi kemanusiaan terdakwa. Dalam perspektif negara hukum yang berlandaskan UUD 1945, sikap hakim yang paling mencerminkan esensi hukum tertinggi adalah...", options: [{text: "Menjalankan hukum secara kaku sesuai teks UU demi menjaga kepastian hukum dan wibawa pengadilan.", val: 0}, {text: "Memberikan vonis maksimal agar menjadi peringatan bagi masyarakat lain untuk tidak melanggar hukum.", val: 0}, {text: "Menggunakan diskresi hukum untuk memberikan putusan yang adil dengan mempertimbangkan nilai kemanusiaan.", val: 5}, {text: "Meminta pemerintah memberikan pekerjaan kepada terdakwa agar tidak mengulangi perbuatannya.", val: 0}, {text: "Menyerahkan keputusan sepenuhnya kepada kesepakatan antara pelapor dan terdakwa di luar pengadilan.", val: 0}] },
{ text: "Masyarakat sipil merasa sebuah Undang-Undang yang baru disahkan oleh DPR dan Presiden mengandung pasal-pasal yang berpotensi membungkam kebebasan pers dan hak mendapatkan informasi. Meskipun UU tersebut sudah sah secara prosedur pembentukan, kelompok masyarakat ingin membatalkan pasal tersebut. Berdasarkan mekanisme konstitusional di Indonesia, jalan yang paling tepat dan terhormat adalah...", options: [{text: "Melakukan aksi demonstrasi besar-besaran hingga pemerintah mengeluarkan Perpu pembatalan.", val: 0}, {text: "Mengabaikan UU tersebut karena dianggap tidak sesuai dengan aspirasi rakyat banyak.", val: 0}, {text: "Mengajukan permohonan keberatan langsung kepada Presiden agar UU tersebut tidak diberlakukan.", val: 0}, {text: "Melakukan judicial review ke Mahkamah Konstitusi sebagai pengawal konstitusi.", val: 5}, {text: "Meminta lembaga internasional untuk menekan pemerintah Indonesia agar mencabut UU tersebut.", val: 0}] },
{ text: "Sebuah kasus hukum yang melibatkan tokoh masyarakat populer sedang berjalan di pengadilan. Opini publik di media sosial sangat masif mendesak agar terdakwa dibebaskan karena rekam jejak sosialnya yang baik, meskipun bukti-bukti materil di persidangan menunjukkan adanya pelanggaran hukum yang nyata. Di sisi lain, hakim dituntut untuk tetap independen sesuai amanat UUD 1945. Dalam menjaga marwah sistem hukum Indonesia, sikap yang paling mencerminkan prinsip konstitusionalitas hakim adalah...", options: [{text: "Mempertimbangkan tuntutan massa demi menjaga stabilitas keamanan dan kepercayaan publik.", val: 0}, {text: "Memutus perkara hanya berdasarkan bukti dan keyakinan hakim tanpa terpengaruh tekanan luar.", val: 5}, {text: "Memberikan hukuman minimal sebagai jalan tengah antara fakta hukum dan keinginan masyarakat.", val: 0}, {text: "Menunda putusan hingga suasana kondusif agar pengadilan tidak menjadi sasaran kemarahan warga.", val: 0}, {text: "Menyerahkan keputusan akhir kepada hasil pemungutan suara pakar hukum untuk menjamin objektivitas.", val: 0}] },
{ text: "Pemerintah pusat meluncurkan undang-undang baru yang menyederhanakan berbagai izin investasi guna mempercepat pertumbuhan ekonomi nasional. Namun, terdapat peraturan daerah (Perda) lama yang masih berlaku dan mengatur prosedur yang lebih ketat demi perlindungan adat setempat. Akibatnya, pelaku usaha mengalami ketidakpastian hukum karena perbedaan aturan tersebut. Berdasarkan hierarki hukum yang berlandaskan UUD 1945, penyelesaian yang paling tepat secara sistemik adalah...", options: [{text: "Pelaku usaha bebas memilih aturan mana yang dianggap paling menguntungkan bagi bisnisnya.", val: 0}, {text: "Peraturan daerah tersebut otomatis batal tanpa perlu ada tindakan hukum karena derajatnya lebih rendah.", val: 0}, {text: "Mengutamakan undang-undang baru melalui mekanisme penyesuaian regulasi daerah agar selaras dengan norma yang lebih tinggi.", val: 5}, {text: "Membiarkan kedua aturan berlaku di wilayah masing-masing untuk menghargai otonomi daerah yang seluas-luasnya.", val: 0}, {text: "Menunggu gugatan dari pihak yang dirugikan ke pengadilan sebelum melakukan perubahan aturan apapun.", val: 0}] },
{ text: "Dalam sebuah kasus kejahatan luar biasa yang sangat melukai perasaan masyarakat, tersangka mendapatkan pendampingan hukum dari pengacara profesional. Masyarakat mengecam pengacara tersebut dan menganggapnya tidak nasionalis karena membela musuh negara. Dalam perspektif UUD 1945 sebagai dasar hukum tertinggi yang menjamin hak asasi manusia, kedudukan pembelaan hukum dalam sistem peradilan kita adalah...", options: [{text: "Hak yang boleh ditiadakan khusus untuk kasus-kasus berat yang mengancam stabilitas negara.", val: 0}, {text: "Prosedur formalitas saja untuk memenuhi syarat persidangan tanpa harus melakukan pembelaan nyata.", val: 0}, {text: "Jaminan konstitusional bagi setiap warga negara untuk mendapatkan peradilan yang jujur dan berimbang.", val: 5}, {text: "Upaya untuk membebaskan pelaku dari hukuman agar hukum terlihat lemah di mata internasional.", val: 0}, {text: "Beban negara yang seharusnya diminimalisir agar anggaran penegakan hukum lebih efisien.", val: 0}] },
{ text: "Dalam sebuah persidangan perkara perdata terkait sengketa lahan, ditemukan fakta bahwa salah satu pihak memenangkan gugatan di tingkat pertama karena memiliki dokumen administrasi yang lengkap secara formal namun diduga kuat diperoleh melalui proses yang tidak etis di masa lalu. Pihak lawan, yang merupakan warga lokal, hanya memiliki bukti penguasaan lahan secara fisik selama puluhan tahun tanpa surat resmi. Jika merujuk pada prinsip UUD 1945 sebagai dasar hukum tertinggi yang menjamin kepastian hukum yang adil, sikap hakim dalam memandang sistem pembuktian tersebut adalah...", options: [{text: "Memenangkan pemilik dokumen formal demi menjaga marwah administrasi negara dan kepastian investasi.", val: 0}, {text: "Mengabaikan dokumen formal jika masyarakat sekitar memberikan kesaksian yang mendukung warga lokal.", val: 0}, {text: "Menelaah keabsahan substansial dari dokumen formal tersebut guna memastikan hukum tidak melindungi kecurangan.", val: 5}, {text: "Menyarankan kedua belah pihak untuk berbagi lahan agar tidak terjadi konflik sosial di wilayah tersebut.", val: 0}, {text: "Menolak memeriksa perkara tersebut karena sengketa administrasi bukan merupakan ranah peradilan umum.", val: 0}] },
{ text: "Sebuah undang-undang yang baru disahkan mendapatkan penolakan luas dari masyarakat dan diajukan untuk uji materi di Mahkamah Konstitusi. Di saat yang sama, lembaga eksekutif dan legislatif secara terbuka memberikan pernyataan bahwa pembatalan undang-undang tersebut akan mengganggu stabilitas nasional dan ekonomi. Sebagai garda terdepan sistem hukum Indonesia, sikap Mahkamah Konstitusi yang paling sesuai dengan spirit UUD 1945 adalah...", options: [{text: "Menunda putusan hingga tensi politik menurun guna menghindari benturan antarlembaga negara.", val: 0}, {text: "Menyesuaikan putusan dengan keinginan eksekutif agar pembangunan nasional tidak terhambat.", val: 0}, {text: "Memutus perkara sepenuhnya berdasarkan kesesuaian norma undang-undang dengan konstitusi.", val: 5}, {text: "Melakukan lobi politik dengan pimpinan lembaga negara lain untuk mencari titik temu putusan.", val: 0}, {text: "Menolak permohonan uji materi tersebut karena undang-undang adalah produk kesepakatan politik rakyat.", val: 0}] },
{ text: "Dalam sistem hukum nasional, sering terjadi tumpang tindih antara izin pemanfaatan sumber daya alam yang dikeluarkan pemerintah pusat dengan hak ulayat masyarakat adat yang diakui secara tradisional. Ketika terjadi konflik, seringkali hukum formal mengabaikan hukum adat karena dianggap tidak tertulis atau tidak terdaftar. Menghadapi isu sistem hukum ini, langkah yang paling mencerminkan pengakuan negara terhadap keberagaman hukum dalam UUD 1945 adalah...", options: [{text: "Mewajibkan masyarakat adat untuk menghapus hukum adatnya demi penyatuan hukum nasional.", val: 0}, {text: "Memberikan prioritas mutlak kepada izin pemerintah pusat karena bersifat legal-formal.", val: 0}, {text: "Mengintegrasikan pengakuan hak masyarakat adat ke dalam sistem hukum formal secara setara.", val: 5}, {text: "Membiarkan konflik diselesaikan sendiri oleh masyarakat dan perusahaan tanpa campur tangan negara.", val: 0}, {text: "Menghapus status hukum adat agar tidak menghambat prosedur administrasi negara yang modern.", val: 0}] },
{ text: "Sebuah kementerian mengeluarkan Peraturan Menteri (Permen) untuk mempercepat prosedur ekspor komoditas tertentu demi meningkatkan devisa negara. Namun, Permen tersebut secara teknis mengabaikan beberapa syarat kelestarian lingkungan yang telah diatur secara rinci dalam sebuah Undang-Undang (UU). Sebagai seorang analis hukum di instansi terkait, sikap yang paling mencerminkan kepatuhan terhadap hierarki hukum berdasarkan UUD 1945 adalah...", options: [{text: "Mendukung penerapan Permen tersebut karena merupakan diskresi menteri untuk kepentingan ekonomi.", val: 0}, {text: "Menyarankan agar Permen tersebut direvisi karena secara hierarkis tidak boleh bertentangan dengan UU.", val: 5}, {text: "Mengabaikan UU tersebut sementara waktu hingga target devisa negara pada tahun berjalan tercapai.", val: 0}, {text: "Meminta lembaga yudisial untuk membatalkan UU agar Permen memiliki landasan hukum yang kuat.", val: 0}, {text: "Menyerahkan keputusan pelaksanaan kepada kebijakan pimpinan unit kerja masing-masing di lapangan.", val: 0}] },
{ text: "Dalam sebuah diskusi hukum, muncul perdebatan mengenai status Ketetapan Majelis Permusyawaratan Rakyat (TAP MPR) yang masih berlaku namun isinya dianggap sudah tidak relevan dengan kebutuhan transformasi digital saat ini. Beberapa pihak mengusulkan agar pemerintah mengabaikan TAP MPR tersebut melalui Peraturan Pemerintah (PP) agar kebijakan digitalisasi bisa bergerak lebih fleksibel. Secara konstitusional, cara memandang kedudukan TAP MPR dalam hierarki hukum adalah...", options: [{text: "TAP MPR dapat dikesampingkan oleh PP jika menyangkut teknis operasional teknologi informasi.", val: 0}, {text: "PP memiliki kedudukan yang lebih tinggi dari TAP MPR karena merupakan produk eksekutif modern.", val: 0}, {text: "TAP MPR berada di atas Undang-Undang dan PP, sehingga perubahannya tidak bisa dilakukan melalui PP.", val: 5}, {text: "TAP MPR sudah tidak berlaku lagi sejak amandemen UUD 1945 dilakukan secara menyeluruh.", val: 0}, {text: "Kedudukan TAP MPR adalah setara dengan Peraturan Daerah karena jangkauannya yang spesifik.", val: 0}] },
{ text: "Sebuah pasal dalam Undang-Undang telah dinyatakan bertentangan dengan UUD 1945 oleh Mahkamah Konstitusi (MK) dan dinyatakan tidak memiliki kekuatan hukum mengikat. Namun, karena belum ada perubahan formal pada naskah Undang-Undang tersebut oleh DPR, sebuah instansi masih menggunakan pasal lama tersebut sebagai dasar pengambilan keputusan administrasi. Tindakan instansi tersebut jika dikaitkan dengan kedudukan UUD 1945 sebagai hukum tertinggi adalah...", options: [{text: "Benar, karena naskah UU belum diubah secara resmi melalui proses legislasi di parlemen.", val: 0}, {text: "Salah, karena putusan MK bersifat final dan mengikat serta berkedudukan setara dengan konstitusi.", val: 0}, {text: "Salah, karena putusan MK otomatis menghapus kekuatan hukum pasal tersebut demi tegaknya konstitusi.", val: 5}, {text: "Benar, demi menjaga kepastian hukum bagi warga negara yang sudah terbiasa dengan aturan lama.", val: 0}, {text: "Menunggu instruksi menteri terkait untuk menentukan apakah putusan MK tersebut perlu diikuti atau tidak.", val: 0}] },
{ text: "Seorang petugas administrasi kependudukan dihadapkan pada situasi di mana seorang warga lanjut usia yang sakit keras membutuhkan pemutakhiran data instan untuk mendapatkan akses perawatan darurat. Namun, sistem secara otomatis menolak karena ada dokumen fisik asli yang hilang, dan secara aturan hukum, petugas dilarang memproses data tanpa dokumen tersebut. Di sisi lain, menunda proses tersebut berisiko fatal bagi keselamatan warga. Berdasarkan semangat UUD 1945 yang menempatkan perlindungan nyawa sebagai hak asasi tertinggi, tindakan yang paling mencerminkan keseimbangan hukum dan moral adalah...", options: [{text: "Tetap menolak proses tersebut demi menjaga kepatuhan total pada standar operasional prosedur yang berlaku.", val: 0}, {text: "Meminta warga tersebut kembali lain waktu setelah dokumen ditemukan agar tidak menyalahi aturan hukum.", val: 0}, {text: "Melakukan diskresi dengan verifikasi data pendukung lain yang tersedia demi menyelamatkan nyawa warga.", val: 5}, {text: "Memberikan bantuan pribadi berupa biaya perawatan agar tidak perlu melanggar aturan administrasi negara.", val: 0}, {text: "Menyerahkan keputusan sepenuhnya kepada atasan untuk menghindari tanggung jawab hukum di masa depan.", val: 0}] },
{ text: "Dalam sebuah kasus pencurian ringan di sebuah perusahaan, pelaku adalah seorang karyawan yang terdesak kebutuhan biaya pengobatan anaknya. Secara hukum (KUHP), tindakan tersebut tetap merupakan tindak pidana yang harus diproses ke pengadilan. Namun, pemilik perusahaan bersedia memaafkan dan ingin menyelesaikan secara kekeluargaan. Masyarakat sekitar pun mendukung perdamaian tersebut. Sebagai penegak hukum, cara pandang yang paling sesuai dengan esensi hukum tertinggi Indonesia dalam menghadapi dilema ini adalah...", options: [{text: "Menolak perdamaian dan tetap memproses ke pengadilan karena hukum harus ditegakkan tanpa pandang bulu.", val: 0}, {text: "Mengutamakan penyelesaian di luar pengadilan (restorative justice) guna mencapai keadilan yang lebih substantif.", val: 5}, {text: "Meminta pelaku tetap dihukum penjara namun dengan durasi yang lebih singkat sebagai bentuk empati.", val: 0}, {text: "Menyarankan perusahaan untuk memecat karyawan tersebut tanpa melaporkannya ke pihak berwajib.", val: 0}, {text: "Mengabaikan kasus tersebut sepenuhnya karena dianggap sebagai masalah internal perusahaan semata.", val: 0}] },
{ text: "Seorang staf ahli di sebuah kementerian menemukan adanya draf regulasi yang secara teknis hukum sangat rapi dan sah secara prosedur, namun ia menyadari bahwa implementasi regulasi tersebut secara moral akan merugikan kelompok masyarakat rentan dalam jangka panjang. Ia diperintahkan oleh pimpinannya untuk segera memfinalisasi draf tersebut. Dalam bingkai UUD 1945 sebagai moralitas hukum tertinggi, sikap profesional yang harus diambil adalah...", options: [{text: "Patuh sepenuhnya pada perintah pimpinan karena loyalitas adalah kode etik utama seorang staf.", val: 0}, {text: "Menyelesaikan draf tersebut dan menyerahkan dampak sosialnya kepada para politisi di parlemen.", val: 0}, {text: "Memberikan catatan kritis dan analisis dampak secara jujur kepada pimpinan sebagai bentuk tanggung jawab profesi.", val: 5}, {text: "Melakukan sabotase halus terhadap draf tersebut agar tidak pernah selesai tepat waktu.", val: 0}, {text: "Langsung membocorkan draf tersebut ke media massa agar mendapatkan penolakan luas dari masyarakat.", val: 0}] },
{ text: "Dalam sebuah kasus pelanggaran lalu lintas, terdapat dua orang pengendara yang melakukan kesalahan yang sama, yaitu menerobos lampu merah. Pengendara pertama adalah seorang warga biasa, sedangkan pengendara kedua adalah kerabat dari seorang pejabat daerah. Petugas di lapangan tetap memberikan surat tilang kepada keduanya tanpa membeda-bedakan status sosial mereka. Tindakan petugas tersebut merupakan penerapan nyata dari prinsip UUD 1945 yang menjamin bahwa...", options: [{text: "Setiap warga negara wajib menjunjung tinggi hukum dan pemerintahan dengan tidak ada kecualinya.", val: 5}, {text: "Pejabat daerah memiliki hak istimewa dalam prosedur hukum asalkan tidak merugikan orang lain.", val: 0}, {text: "Penegakan hukum harus dilakukan dengan mengedepankan sopan santun kepada tokoh masyarakat.", val: 0}, {text: "Surat tilang hanya diberikan kepada warga yang tidak memiliki akses komunikasi ke pimpinan.", val: 0}, {text: "Hukum di Indonesia dapat disesuaikan berdasarkan kondisi ekonomi dan jabatan seseorang.", val: 0}] },
{ text: "Pemerintah mengeluarkan peraturan baru yang mewajibkan seluruh pelaku usaha mikro untuk memiliki nomor induk berusaha secara gratis melalui sistem daring. Kebijakan ini bertujuan agar negara memiliki data yang akurat untuk penyaluran bantuan dan perlindungan hukum bagi usaha kecil. Dalam sistem hukum Indonesia, tujuan utama dibuatnya peraturan semacam ini adalah untuk mencapai...", options: [{text: "Kekuasaan pemerintah yang mutlak atas seluruh aktivitas ekonomi rakyat kecil.", val: 0}, {text: "Kepastian hukum dan kemanfaatan bagi warga negara dalam menjalankan usahanya.", val: 5}, {text: "Penambahan beban administrasi agar masyarakat lebih disiplin dalam bekerja.", val: 0}, {text: "Pembatasan jumlah pedagang agar tidak terjadi persaingan usaha yang terlalu ketat.", val: 0}, {text: "Formalitas belaka agar Indonesia terlihat memiliki sistem administrasi yang canggih.", val: 0}] },
{ text: "Seorang warga negara yang tidak mampu secara ekonomi terjerat masalah hukum dan harus menjalani proses persidangan. Karena tidak memahami hukum dan tidak memiliki biaya, ia merasa sangat tertekan. Berdasarkan sistem hukum Indonesia yang berlandaskan UUD 1945, negara wajib hadir untuk memberikan bantuan dalam bentuk...", options: [{text: "Pembebasan dari segala tuntutan hukum secara otomatis karena kondisi ekonominya.", val: 0}, {text: "Dana bantuan sosial yang besar agar warga tersebut bisa membayar ganti rugi.", val: 0}, {text: "Penyediaan pendampingan hukum atau advokat secara cuma-cuma bagi warga tersebut.", val: 5}, {text: "Surat keputusan dari pemerintah yang menyatakan warga tersebut tidak boleh diadili.", val: 0}, {text: "Saran agar warga tersebut segera mengakui kesalahan agar proses sidang lebih cepat.", val: 0}] },
{ text: "Pemerintah daerah berencana membangun proyek infrastruktur besar yang akan melewati pemukiman padat penduduk. Warga sekitar merasa khawatir akan dampak lingkungan dan sosialnya, namun kesulitan mendapatkan naskah peraturan terkait proyek tersebut. Dalam sistem hukum Indonesia yang berlandaskan kedaulatan rakyat dan UUD 1945, sikap otoritas yang paling tepat dalam memenuhi hak hukum warga adalah...", options: [{text: "Merahasiakan dokumen tersebut hingga proyek selesai agar tidak terjadi unjuk rasa.", val: 0}, {text: "Meminta warga untuk mempercayai sepenuhnya bahwa proyek tersebut pasti bermanfaat.", val: 0}, {text: "Menyediakan akses bagi warga untuk mempelajari aturan dan dampak proyek secara transparan.", val: 5}, {text: "Menyarankan warga agar pindah terlebih dahulu sebelum menanyakan dasar hukum proyek.", val: 0}, {text: "Hanya memberikan informasi kepada perwakilan tokoh masyarakat yang mendukung pemerintah.", val: 0}] },
{ text: "Seorang pegawai instansi pemerintah diberikan fasilitas kendaraan dinas untuk mendukung mobilitas pekerjaannya. Pada suatu hari, anggota keluarganya meminta izin menggunakan kendaraan tersebut untuk keperluan wisata pribadi dengan alasan kendaraan tersebut sedang tidak digunakan untuk dinas. Tindakan pegawai tersebut yang paling sesuai dengan prinsip kepatuhan hukum dan etika jabatan adalah...", options: [{text: "Mengizinkan penggunaan kendaraan tersebut selama bensin diisi dengan uang pribadi.", val: 0}, {text: "Menolak permohonan tersebut karena kendaraan dinas hanya untuk kepentingan pekerjaan.", val: 5}, {text: "Memberikan izin hanya jika perjalanan wisata tersebut dilakukan di hari libur kerja.", val: 0}, {text: "Menghapus plat nomor dinas saat digunakan wisata agar tidak terlihat oleh publik.", val: 0}, {text: "Mengizinkan asalkan keluarga tersebut berjanji untuk menjaga kebersihan kendaraan.", val: 0}] },
{ text: "Seorang warga merasa dipersulit saat mengurus perizinan usaha karena petugas terus meminta persyaratan tambahan yang tidak tercantum dalam peraturan resmi. Warga tersebut merasa haknya dirugikan oleh tindakan sepihak oknum petugas tersebut. Langkah hukum yang disediakan oleh sistem hukum Indonesia bagi warga untuk mendapatkan keadilan administrasi adalah...", options: [{text: "Memberikan uang tambahan kepada petugas agar urusan cepat selesai tanpa kendala.", val: 0}, {text: "Melakukan protes secara anarkis di kantor tersebut agar mendapatkan perhatian media.", val: 0}, {text: "Melaporkan tindakan tersebut melalui kanal pengaduan resmi atau lembaga Ombudsman.", val: 5}, {text: "Berhenti berusaha karena menganggap hukum di Indonesia memang sulit ditembus.", val: 0}, {text: "Mencari jalur belakang melalui kenalan pejabat agar izin dapat segera diterbitkan.", val: 0}] },
];

